insert into public.daily_terms (date, term, hints, definition) values
  ('2026-07-01', 'Stack', ARRAY['The thing you put in most recently is the only thing you can reach right now.', 'The mechanism that lets functions call other functions is built on one of these.', 'Undo features and backtracking rely naturally on its ordering.', 'Its two core moves, push and pop, both happen at the same end.', 'Its discipline is last in, first out.', 'It works like a pile of trays where you always add to and take from the top.']::text[], 'An abstract data type with last-in-first-out (LIFO) ordering, supporting push (add to the top) and pop (remove from the top). It underlies function-call management, expression evaluation, and backtracking.'),
  ('2026-07-02', 'Arithmetic Logic Unit', ARRAY['It is the part of the processor that actually does the math.', 'It also performs the comparisons and logical operations behind every decision.', 'It takes operands from fast internal stores and produces a result plus status flags.', 'Those flags record things like whether a result was zero or overflowed.', 'It is one of the two main subunits inside a central processor.', 'It is the circuit within the CPU that performs arithmetic and logical operations.']::text[], 'A digital circuit within the CPU that performs arithmetic (add, subtract) and logical (AND, OR, comparison) operations on operands from registers, setting status flags such as zero, carry, and overflow. It is a core component of the processor.'),
  ('2026-07-03', 'Version Control', ARRAY['It remembers every change ever made to a project, and who made it.', 'It lets you return to any earlier state at will.', 'It enables many people to work on the same code without overwriting each other.', 'Parallel lines of work can diverge and later be merged back together.', 'Git is by far its most popular incarnation.', 'It is a system that records and manages changes to files over time.']::text[], 'A system that records changes to files over time, letting developers review history, revert to earlier states, and collaborate without overwriting each other’s work via branching and merging. Distributed systems like Git are the modern standard for managing source code.'),
  ('2026-07-04', 'NoSQL', ARRAY['It is a broad family united mainly by what they are not.', 'They abandon rigid tables in favor of more flexible data models.', 'Many trade strict consistency for the ability to scale across many machines.', 'Document, key-value, column, and graph stores all fall under it.', 'It rose to prominence with the demands of massive web applications.', 'It is the umbrella term for databases that depart from the relational table model.']::text[], 'An umbrella term for databases that depart from the relational table model, using flexible schemas and models such as document, key-value, wide-column, or graph. Often built to scale horizontally and to favor availability over strict consistency, they suit large-scale and rapidly evolving data.'),
  ('2026-07-05', 'AVL Tree', ARRAY['It is willing to do extra shuffling after every edit to guarantee it never gets lopsided.', 'After each insert or delete it checks whether any part has grown too tall relative to its sibling.', 'When it detects imbalance it performs local rotations to restore even height.', 'Its strict balancing keeps every operation logarithmic even in the worst case.', 'It was the first self-balancing search tree ever invented, named after two mathematicians.', 'It is a height-balanced search tree that rotates to keep sibling subtrees within one level of each other.']::text[], 'A self-balancing binary search tree that keeps, for every node, a height difference of at most one between its subtrees, restoring this with rotations after insertions and deletions. It guarantees O(log n) operations, at the cost of more rotations than more loosely balanced trees.'),
  ('2026-07-06', 'Immutability', ARRAY['Once created, such a value can never be changed—only replaced.', 'Wanting a modified version means making a whole new copy.', 'It eliminates a class of bugs where shared data changes underfoot.', 'It makes sharing data across threads inherently safe.', 'Strings in many languages already have this property.', 'It is the property of data that cannot be altered after it is created.']::text[], 'The property of an object or value that cannot be changed after creation; any "modification" produces a new value instead. Immutability simplifies reasoning, prevents a class of aliasing bugs, and makes data safe to share across threads, at the cost of extra copying.'),
  ('2026-07-07', 'Huffman Coding', ARRAY['It assigns shorter codes to the things that appear most often.', 'Rare symbols get longer codes in exchange.', 'No code is ever a prefix of another, so decoding is unambiguous.', 'It builds its code by repeatedly merging the two least frequent items.', 'It provably produces the optimal such variable-length code.', 'It is the greedy algorithm for optimal prefix-free compression codes.']::text[], 'A greedy algorithm that produces an optimal prefix-free variable-length code, assigning shorter bit sequences to more frequent symbols by repeatedly merging the two least frequent nodes into a binary tree. It is a foundational lossless-compression technique used within formats like ZIP and JPEG.'),
  ('2026-07-08', 'Matrix', ARRAY['It arranges data in a rectangle, so two numbers rather than one are needed to locate any element.', 'Rows and columns give every element an address like a grid reference.', 'Graphics transformations and systems of equations are expressed and solved with it.', 'One common way to store a graph uses one of these, marking which nodes connect.', 'It is a two-dimensional arrangement of values laid out in rows and columns.', 'It is the rectangular grid of numbers that linear algebra multiplies and transforms.']::text[], 'A two-dimensional array of values arranged in rows and columns and addressed by a pair of indices. Matrices represent linear transformations, systems of equations, image data, and graph adjacency, and are central to linear algebra and computer graphics.'),
  ('2026-07-09', 'Class', ARRAY['It is a blueprint, not a thing you can use until you make one from it.', 'It specifies what data its products hold and what they can do.', 'From it you stamp out any number of individual instances.', 'It can build on another one, inheriting its features.', 'Its instances each carry their own copy of the data it describes.', 'It is the template from which objects are created.']::text[], 'A blueprint that defines the structure (fields) and behavior (methods) shared by a category of objects. Objects are instances of a class, each with its own data, and classes can inherit from others to form hierarchies.'),
  ('2026-07-10', 'Reference', ARRAY['It lets two names refer to the very same underlying object.', 'Change the object through one and the change is visible through the other.', 'It behaves like a pointer but usually cannot be left empty or aimed elsewhere.', 'Passing a large object by it avoids copying the whole thing.', 'Many high-level languages use it silently for all their objects.', 'It is an alias that lets you access an object without copying it.']::text[], 'A value that refers to an object without copying it, letting multiple names access the same data. Similar to a pointer but usually safer—often non-null and non-reassignable—references enable sharing and the pass-by-reference semantics common in high-level languages.'),
  ('2026-07-11', 'Exception', ARRAY['It is the language’s way of signaling that something went wrong.', 'When raised, it interrupts the normal flow of the program.', 'It travels up the call stack until something agrees to handle it.', 'Unhandled, it usually crashes the program with a diagnostic message.', 'It cleanly separates error handling from the main logic.', 'It is an object representing an error that disrupts normal control flow.']::text[], 'A mechanism for signaling and handling errors or unusual conditions: when raised (thrown), it interrupts normal control flow and propagates up the call stack until caught by a handler, or terminates the program if uncaught. Exceptions separate error handling from mainline logic.'),
  ('2026-07-12', 'Callback', ARRAY['It is a function you hand to other code to be run later.', 'It is invoked when some operation finishes or an event occurs.', 'It is a classic way to handle work that completes asynchronously.', 'Nesting many of them deeply leads to famously tangled code.', 'Newer abstractions were invented largely to tame it.', 'It is a function passed to other code to be called back at a later point.']::text[], 'A function passed as an argument to other code, to be invoked later—when an operation completes or an event fires. Callbacks are a fundamental way to handle asynchronous work and events, though deeply nested ones create hard-to-read "callback hell," which promises and async/await address.'),
  ('2026-07-13', 'Variable', ARRAY['It is a name you attach to a value so you can refer to it later.', 'Behind the name sits a location that can hold data.', 'In many languages the value it holds can change over time.', 'It usually has a type that constrains what kind of value it may store.', 'Where it can be used is governed by its scope.', 'It is a named storage location holding a value that a program can read and change.']::text[], 'A named storage location that holds a value a program can read and, in many languages, modify. Each variable has a name, a value, usually a type, and a scope governing where it is accessible; variables are the basic means of tracking state in code.'),
  ('2026-07-14', 'Sharding', ARRAY['It splits one giant database into pieces spread across many machines.', 'Each piece holds only a subset of the total rows.', 'A key decides which piece any given record lives in.', 'It lets a database scale beyond what a single server could handle.', 'Queries spanning multiple pieces become more complicated as a result.', 'It is horizontally partitioning data across multiple servers to scale.']::text[], 'A horizontal-partitioning technique that splits a large dataset across multiple servers (shards), each holding a subset of rows chosen by a shard key. Sharding lets a database scale beyond one machine’s capacity, at the cost of more complex cross-shard queries and rebalancing.'),
  ('2026-07-15', 'Unicode', ARRAY['It set out to give every character in every language a single number.', 'It also covers symbols and, famously, emoji.', 'It assigns each character an abstract number independent of how it is stored.', 'Several encodings exist to turn those numbers into actual bytes.', 'It superseded a patchwork of incompatible regional character sets.', 'It is the universal standard assigning a unique number to every character.']::text[], 'A universal character-encoding standard that assigns a unique number (code point) to virtually every character across the world’s writing systems, plus symbols and emoji. It defines the abstract character-to-number mapping, while encodings like UTF-8 and UTF-16 specify how those numbers become bytes.'),
  ('2026-07-16', 'Circular Buffer', ARRAY['It reuses the same fixed space forever, letting new data quietly overwrite the oldest.', 'When writing reaches the end, it simply wraps back around to the beginning.', 'Its capacity never changes, which makes it a favorite in memory-tight systems.', 'Streaming audio, logs, and producer-consumer pipelines lean on it.', 'Two markers chase each other around the loop to track where reading and writing happen.', 'It is a fixed-size buffer treated as a ring, so the newest data overwrites the oldest.']::text[], 'A fixed-size buffer treated as a loop, using head and tail pointers so that once full, new writes overwrite the oldest data. Also called a ring buffer, it suits streaming, buffering, and producer-consumer scenarios with bounded memory.'),
  ('2026-07-17', 'Bit Shifting', ARRAY['It slides all the ones and zeros of a value sideways by a set number of places.', 'Nudging them one way is a lightning-fast stand-in for multiplying by two.', 'Nudging them the other way divides by two instead.', 'Digits that fall off the end are simply discarded.', 'It is a favorite tool for squeezing performance out of tight numeric code.', 'It is the operation that moves a number’s bits left or right by a given amount.']::text[], 'An operation that moves all bits of a value left or right by a specified number of positions. A left shift by k multiplies an unsigned integer by 2^k and a right shift divides by 2^k, making shifts fast substitutes for multiplication and division by powers of two.'),
  ('2026-07-18', 'Quadtree', ARRAY['It saves effort by refusing to subdivide regions that are empty or uniform.', 'Whenever a region holds too much detail, it splits that region into four smaller ones.', 'Two-dimensional space is what it is built to organize.', 'Image compression, collision detection, and maps use it to skip over empty areas quickly.', 'Each of its internal nodes has exactly four children, one per quadrant.', 'It is the tree that recursively divides a two-dimensional area into four quadrants.']::text[], 'A tree in which each internal node has four children, recursively subdividing a two-dimensional space into quadrants only where detail requires it. Quadtrees accelerate spatial queries, collision detection, image compression, and geographic indexing by pruning empty or uniform regions.'),
  ('2026-07-19', 'Deque', ARRAY['It refuses to pick a side: both ends are equally open for business.', 'You can add or remove at the front or the back with equal speed.', 'It generalizes two simpler structures, behaving like either one depending on how you use it.', 'Sliding-window algorithms often lean on it to add and drop items at both ends.', 'Its name is a contraction of the phrase "double-ended".', 'It is a queue that lets you insert and remove at both the front and the back.']::text[], 'A double-ended queue supporting insertion and removal at both ends in O(1). It generalizes stacks and queues and is commonly used for sliding-window problems and work-stealing schedulers.'),
  ('2026-07-20', 'Big-O Notation', ARRAY['It deliberately ignores the constant factors that decide real-world speed.', 'By its measure, a sluggish algorithm and a fast one can look identical.', 'It cares only about behavior as the input grows toward infinity.', 'Coefficients and lower-order terms drop away; only the dominant growth remains.', 'It sorts algorithms into families like constant, logarithmic, linear, and quadratic.', 'It is the notation, written with a capital O and parentheses, describing growth rate.']::text[], 'A notation describing the limiting growth of an algorithm’s time or space as input size increases, expressed as an asymptotic upper bound with constant factors and lower-order terms dropped (e.g., O(n), O(log n), O(n²)). It lets algorithms be compared independently of hardware.'),
  ('2026-07-21', 'Side Effect', ARRAY['It is anything a function does beyond simply computing and returning a value.', 'Printing to the screen or writing a file is a classic example.', 'Modifying a global variable or its own arguments counts too.', 'Functions that avoid it are far easier to reason about and test.', 'Managing it carefully is a central theme of functional programming.', 'It is an observable change to state outside a function’s local computation.']::text[], 'Any observable effect a function has beyond returning a value—such as modifying global state, mutating arguments, performing I/O, or throwing. Side effects make code harder to test and reason about, so functional programming seeks to minimize and isolate them.'),
  ('2026-07-22', 'Abstraction', ARRAY['It lets you use something without knowing how it works inside.', 'It exposes the essential controls while hiding messy detail.', 'Driving a car without understanding its engine is the classic analogy.', 'Layers of it are how large systems stay comprehensible.', 'It focuses on what an object does rather than how it does it.', 'It is the practice of exposing only essential features while hiding complexity.']::text[], 'The practice of exposing only the essential features of something while hiding its underlying complexity, letting users work at a higher conceptual level. In software it appears as interfaces, functions, and layers separating what a component does from how it does it.'),
  ('2026-07-23', 'Virtual Memory', ARRAY['It lets programs behave as if they have far more memory than physically exists.', 'It also gives each program the illusion of a private, contiguous address space.', 'Rarely used portions can be quietly parked on disk until needed.', 'Hardware translates the addresses a program sees into real physical ones.', 'Overusing it triggers thrashing, where the system spends all its time swapping.', 'It is the abstraction that maps each program’s address space onto physical memory and disk.']::text[], 'A memory-management technique that gives each process the illusion of a large, private, contiguous address space by mapping virtual addresses to physical memory and disk. It enables isolation, more apparent memory than exists, and demand paging, at the risk of thrashing under load.'),
  ('2026-07-24', 'Referential Transparency', ARRAY['It means an expression can be swapped for its value without changing anything.', 'It holds only when evaluating the expression has no hidden effects.', 'Pure functions are exactly what make it possible.', 'It lets a compiler safely cache or reorder computations.', 'It is a property that fails the moment code depends on mutable state.', 'It is the property that an expression can be replaced by its result with no change in behavior.']::text[], 'A property of an expression whereby it can be replaced by its resulting value without altering the program’s behavior. It requires freedom from side effects, holds for pure functions, and enables optimizations like caching and reordering as well as equational reasoning.'),
  ('2026-07-25', 'Type Inference', ARRAY['It lets you skip writing out types the compiler can figure out on its own.', 'The language deduces each type from how a value is used.', 'It gives you the safety of declared types without all the typing.', 'Writing "auto" or "var" often hands the job to it.', 'Functional languages pioneered its most powerful forms.', 'It is a compiler’s ability to deduce the types of expressions automatically.']::text[], 'A feature by which the compiler automatically deduces the types of variables and expressions from context, so explicit annotations are often unnecessary. It combines static typing’s safety with concise code, and its advanced forms (like Hindley-Milner) come from functional languages.'),
  ('2026-07-26', 'Two Pointers', ARRAY['It replaces a slow nested loop with a single sweep using two moving markers.', 'Those markers often begin at opposite ends and move toward each other.', 'Sorted input is what usually makes it work.', 'Finding a pair that sums to a target value is its textbook example.', 'It cuts many quadratic scans down to a single linear pass.', 'It is the technique of scanning a sequence with two coordinated indices at once.']::text[], 'A technique that solves array or string problems by advancing two indices in a coordinated way—often from opposite ends or at differing speeds—usually over sorted data. It commonly reduces O(n²) brute force to O(n), as in pair-sum and partitioning problems.'),
  ('2026-07-27', 'A* Search', ARRAY['It improves on a plain shortest-path search by using a hint about how far the goal still is.', 'It balances the distance already traveled against an estimate of the distance remaining.', 'That estimate must never overshoot, or the path it returns may not be optimal.', 'Game pathfinding and route planners rely on it constantly.', 'With a perfect estimate it heads straight for the goal, exploring almost nothing extra.', 'It is the best-first search that guides itself toward a goal using an admissible heuristic.']::text[], 'A best-first search that finds a lowest-cost path to a goal by ranking nodes by the cost so far plus a heuristic estimate of the cost remaining. With an admissible heuristic it is guaranteed optimal, generalizing Dijkstra’s algorithm with goal-directed guidance.'),
  ('2026-07-28', 'B-Tree', ARRAY['It was designed for a world where reaching storage is slow, so it minimizes how often it must do so.', 'Unlike most trees, a single one of its nodes can hold many keys and have many children.', 'Keeping nodes wide and the whole structure shallow means fewer storage reads per lookup.', 'Database indexes and filesystems are its natural home.', 'It stays balanced by splitting and merging its fat nodes as data changes.', 'It is the shallow, wide, self-balancing tree used to index data kept on disk.']::text[], 'A self-balancing tree that keeps data sorted while allowing each node to hold many keys and children, minimizing height and therefore disk accesses. Widely used in databases and filesystems, B-trees and variants like B+ trees give O(log n) operations tuned for block storage.'),
  ('2026-07-29', 'Declarative Programming', ARRAY['It focuses on what you want, leaving the how to the system.', 'You describe the desired result rather than the steps to reach it.', 'A database query language is a familiar example.', 'It often reads more clearly but hides the underlying execution.', 'Functional and logic programming both fall under it.', 'It is the paradigm of specifying the desired outcome rather than the control flow.']::text[], 'A paradigm that expresses the logic of a computation—what result is desired—without describing the explicit control flow to achieve it, leaving execution details to the system. SQL, HTML, and functional and logic languages exemplify it, often improving clarity at the cost of low-level control.'),
  ('2026-07-30', 'Port', ARRAY['It lets a single machine run many network services without confusion.', 'It is a number that identifies which program should get an arriving message.', 'Combined with an address, it pinpoints an exact endpoint.', 'Certain low numbers are reserved for well-known services.', 'Web traffic conventionally uses 80 and its secure form 443.', 'It is a numbered endpoint distinguishing services on the same network host.']::text[], 'A numbered communication endpoint that, combined with an IP address, identifies a specific service or process on a host, letting one machine handle many connections at once. Well-known ports (like 80 for HTTP and 443 for HTTPS) are reserved for standard services.'),
  ('2026-07-31', 'GPU', ARRAY['It was built for one job—drawing pixels—but now powers something entirely different.', 'Its strength is doing thousands of similar calculations at the same time.', 'It struggles with branchy, sequential work that its general-purpose cousin handles easily.', 'Training modern neural networks would be impractical without it.', 'Cryptocurrency mining once created a notorious shortage of them.', 'It is the massively parallel processor originally designed to render graphics.']::text[], 'A graphics processing unit, a processor with many simple cores optimized for performing the same operation on large amounts of data in parallel. Originally for rendering images, its throughput makes it central to machine learning, scientific computing, and other data-parallel workloads.'),
  ('2026-08-01', 'Concurrency', ARRAY['It is about a program structured to juggle many tasks, not necessarily at the same instant.', 'A single processor can achieve it by rapidly switching among tasks.', 'It is often confused with truly simultaneous execution, but the two are distinct.', 'Its central challenge is coordinating access to shared state safely.', 'It deals with tasks that overlap in time even if only one runs at any moment.', 'It is the composition of independently executing tasks that make progress together.']::text[], 'The ability of a system to make progress on multiple tasks whose lifetimes overlap, whether or not they run at the same instant—for example by interleaving them on one CPU. It concerns program structure and coordination, and is distinct from parallelism, which is literal simultaneous execution.'),
  ('2026-08-02', 'Design Pattern', ARRAY['It is a reusable solution shape, not a piece of code you copy directly.', 'It captures a proven answer to a problem that keeps recurring.', 'A famous "Gang of Four" book catalogued many of them.', 'They fall into creational, structural, and behavioral families.', 'Naming them gives developers a shared vocabulary for designs.', 'It is a general, reusable template for solving a common design problem.']::text[], 'A general, reusable solution to a commonly occurring software-design problem—a template for structuring classes and objects, not concrete code. Popularized by the "Gang of Four," patterns are grouped as creational, structural, and behavioral and give teams a shared design vocabulary.'),
  ('2026-08-03', 'Bubble Sort', ARRAY['It is the sort almost everyone learns first and almost no one uses in earnest.', 'It works by comparing neighbors and swapping them whenever they are out of order.', 'After each full pass, the largest remaining value has drifted to its final place at the end.', 'Larger values appear to rise toward the top one position at a time, which inspired its name.', 'On already-sorted data it can finish in a single pass, but otherwise it is quadratic.', 'It repeatedly steps through the list swapping adjacent out-of-order pairs until none remain.']::text[], 'A simple comparison sort that repeatedly steps through the list, comparing adjacent elements and swapping them if out of order, so larger values gradually move to the end. It runs in O(n²) on average and is mainly of educational value.'),
  ('2026-08-04', 'Garbage Collection', ARRAY['It frees programmers from a tedious and error-prone chore.', 'It automatically reclaims memory that a program can no longer reach.', 'It periodically hunts down objects nothing points to anymore.', 'Its work can briefly pause a program at unpredictable moments.', 'Java, Python, and Go all rely on some form of it.', 'It is the automatic reclamation of memory no longer in use by a program.']::text[], 'Automatic memory management that reclaims memory occupied by objects a program can no longer reach, sparing developers manual freeing. Using strategies like tracing (mark-and-sweep) or reference counting, it prevents many leaks and dangling pointers but can introduce pauses and overhead.'),
  ('2026-08-05', 'Assembly Language', ARRAY['It is the most human-friendly way to write code that still maps almost directly onto the hardware.', 'Each of its statements corresponds to a single processor instruction.', 'It uses short mnemonic names in place of raw numeric codes.', 'A dedicated tool converts it into the binary the CPU runs.', 'It is tied to one specific processor architecture.', 'It is the low-level language of mnemonics that stands one step above machine code.']::text[], 'A low-level language using human-readable mnemonics that correspond almost one-to-one with a processor’s machine instructions. Tied to a specific architecture and translated by an assembler, it offers direct hardware control for performance-critical or systems code.'),
  ('2026-08-06', 'Instruction Set', ARRAY['It is the vocabulary of commands a particular processor natively understands.', 'Code compiled for one is generally gibberish to a different one.', 'Designs split broadly into lean, reduced styles and richer, complex ones.', 'It defines the registers, operations, and encodings the hardware exposes.', 'Families like x86 and ARM are prominent examples.', 'It is the set of low-level commands a processor architecture can execute.']::text[], 'The set of instructions a processor architecture can execute, defining its operations, registers, data types, and encodings—the contract between hardware and software. Designs range from reduced (RISC, like ARM) to complex (CISC, like x86), and binaries are specific to one instruction set.'),
  ('2026-08-07', 'Reservoir Sampling', ARRAY['It can pick a fair random sample even when it never learns how much data is coming.', 'It reads a stream once and keeps only a fixed number of items at any moment.', 'Each new item may randomly bump out one already chosen, with carefully set odds.', 'When the stream ends, every item that ever passed had an equal chance of being kept.', 'It is ideal when the data is too large to store or its size is unknown in advance.', 'It selects a fixed-size sample uniformly at random from a stream of unknown length in one pass.']::text[], 'A family of randomized algorithms that choose a uniform random sample of k items from a stream of unknown or very large size in a single pass using O(k) space. Each new element replaces a held one with a carefully tuned probability so all elements are equally likely to be selected.'),
  ('2026-08-08', 'Register', ARRAY['It is the fastest storage a processor has, and also the scarcest.', 'It sits right inside the processor, not out in main memory.', 'The processor works almost exclusively on data held here.', 'There are only a few dozen of them, each holding a single word.', 'Values are constantly shuttled between it and slower memory.', 'It is a small, extremely fast storage location built directly into the CPU.']::text[], 'A small, very fast storage location built into the CPU that holds the data and addresses the processor is actively working on. Registers are the top of the memory hierarchy—fastest and least numerous—and instructions typically operate directly on their contents.'),
  ('2026-08-09', 'Cryptographic Hash', ARRAY['It is a fingerprinting function built to resist deliberate tampering.', 'Changing a single bit of input scrambles the entire output unpredictably.', 'Finding two inputs with the same output must be computationally infeasible.', 'It must also be practically impossible to reverse.', 'Passwords are stored as these rather than in the clear.', 'It is a hash function designed to be one-way and collision-resistant for security.']::text[], 'A hash function designed for security, with properties including preimage resistance (hard to invert), collision resistance (hard to find two inputs with the same digest), and the avalanche effect (tiny input changes drastically alter the output). Examples like SHA-256 secure passwords, signatures, and integrity checks.'),
  ('2026-08-10', 'Cache Miss', ARRAY['It is the disappointing moment a fast lookup fails to find what it hoped for.', 'It forces the system to fetch the data from a slower level instead.', 'Poor data layout that ignores locality makes it happen far more often.', 'It comes in flavors named compulsory, capacity, and conflict.', 'Minimizing it is a central goal of performance-sensitive code.', 'It occurs when requested data is absent from the cache and must come from slower storage.']::text[], 'An event where data requested from a cache is not present, requiring it to be fetched from a slower level of the memory hierarchy and incurring a latency penalty. Misses are classified as compulsory, capacity, or conflict, and reducing them via locality-friendly code is key to performance.'),
  ('2026-08-11', 'Tabulation', ARRAY['Unlike its top-down sibling, it never uses recursion at all.', 'It fills a table starting from the smallest cases and working upward.', 'Every entry it needs has already been computed before it is read.', 'It is the bottom-up way to carry out a well-known optimization technique.', 'It trades the elegance of recursion for tight iterative loops and no call-stack risk.', 'It solves a problem bottom-up by filling a table of subproblem answers in order.']::text[], 'The bottom-up form of dynamic programming that iteratively fills a table of subproblem solutions from the base cases up, so every entry is available before it is needed. It avoids recursion and its stack overhead, sometimes at the cost of computing entries a top-down method would skip.'),
  ('2026-08-12', 'Mutex', ARRAY['Whoever locks it is the only one who should unlock it.', 'Forget to release it and the whole program can seize up.', 'It forces a shared section of code to run one thread at a time.', 'A thread that cannot acquire it simply waits until it is free.', 'Its name is a contraction of the two words describing what it enforces.', 'It is a lock granting one thread at a time exclusive access to a shared resource.']::text[], 'A synchronization primitive (short for "mutual exclusion") ensuring only one thread accesses a shared resource or critical section at a time. Threads acquire the lock, do their work, and release it while others block; misuse causes deadlocks or data corruption.'),
  ('2026-08-13', 'Stack Overflow', ARRAY['It is what an infinite recursion almost always ends in.', 'It happens when a program’s automatic call-tracking region runs out of room.', 'Each unreturned function call eats a little more of a fixed space until none is left.', 'A missing base case in a recursive function is the usual culprit.', 'It typically crashes the program immediately when it strikes.', 'It is the error that occurs when the call stack exceeds its size limit.']::text[], 'A runtime error that occurs when a program uses more space on the call stack than is available, typically from unbounded or excessively deep recursion. It usually terminates the program abruptly, and is distinct from the programming question-and-answer website of the same name.'),
  ('2026-08-14', 'Semaphore', ARRAY['Unlike a simple lock, it can let a limited number of users in at once.', 'At its heart is just a counter guarded against simultaneous changes.', 'Taking one decrements the counter; releasing one increments it.', 'When the counter hits zero, further takers must wait.', 'A version limited to values of zero and one behaves like a plain lock.', 'It is a counter-based primitive that controls access to a limited pool of resources.']::text[], 'A synchronization primitive built around a counter that controls access to a limited number of identical resources: threads decrement it to acquire and increment it to release, blocking when it reaches zero. A binary semaphore acts like a lock, and semaphores also coordinate signaling between threads.'),
  ('2026-08-15', 'Generics', ARRAY['They let you write one piece of code that works for many different types.', 'A single list or sorting routine can serve integers, strings, and more.', 'They preserve type safety without forcing you to duplicate code per type.', 'The specific type is supplied as a parameter when the code is used.', 'C++ templates and Java’s angle-bracket syntax are examples.', 'They are the feature allowing code to be written against a type supplied later.']::text[], 'A language feature that lets code be written in terms of type parameters supplied later, so one implementation works across many types while preserving type safety. Also called parametric polymorphism, it avoids duplication, as with C++ templates or Java’s List<T>.'),
  ('2026-08-16', 'Lambda Calculus', ARRAY['It shows that functions alone are enough to express any computation.', 'It has no loops, no numbers, and no data types built in—only rule-based substitution.', 'It is exactly as powerful as the tape-based model of computation.', 'Functional programming languages trace their core ideas directly back to it.', 'In it, everything is a function that takes a function and returns a function.', 'It is the formal system of computation built entirely from anonymous functions and application.']::text[], 'A formal system introduced by Alonzo Church that expresses computation using only anonymous functions, variable binding, and function application with substitution. Equivalent in power to Turing machines, it is the theoretical foundation of functional programming.'),
  ('2026-08-17', 'Deadlock', ARRAY['Four specific conditions must all hold at once; break any one and it cannot occur.', 'Everyone involved is waiting, and no one can ever move forward.', 'Each party holds exactly what another party is waiting for.', 'A circular chain of waiting sits at its heart.', 'Two threads each grabbing a lock the other already holds triggers it.', 'It is a standstill in which processes block forever, each waiting on the others.']::text[], 'A situation where two or more processes or threads are each blocked forever, waiting on resources the others hold. It requires four simultaneous conditions—mutual exclusion, hold-and-wait, no preemption, and circular wait—and is broken by negating one of them.'),
  ('2026-08-18', 'Method Overriding', ARRAY['A subclass uses it to replace behavior it would otherwise inherit.', 'The replacement keeps the same name and signature as the original.', 'Which version runs is decided by the object’s actual type at runtime.', 'It is the everyday mechanism behind runtime polymorphism.', 'A subclass’s toString replacing its parent’s is a common case.', 'It is redefining an inherited method in a subclass to change its behavior.']::text[], 'The redefinition of an inherited method in a subclass, keeping the same name and signature but supplying new behavior. The version invoked is chosen at runtime by the object’s actual type (dynamic dispatch), making overriding the basis of subtype polymorphism.'),
  ('2026-08-19', 'NP-Hard', ARRAY['Membership means "at least as hard as the hardest problems whose answers are easy to check".', 'A problem can belong even if verifying a proposed answer is not itself easy.', 'Every problem in a certain famous class reduces to any problem here.', 'Some members are not even decision problems and may lie outside that famous class.', 'Finding an efficient exact solution to one would be a historic breakthrough.', 'It labels problems at least as hard as every problem whose solutions are quickly verifiable.']::text[], 'A classification for problems at least as hard as every problem in NP, meaning any NP problem reduces to them in polynomial time. Such problems need not be in NP themselves or even be decision problems, and no polynomial-time algorithm is known for any of them.'),
  ('2026-08-20', 'Floating Point', ARRAY['It trades exactness for the ability to represent an enormous range of magnitudes.', 'Adding two innocent-looking decimals in it can yield a tiny, surprising error.', 'It stores numbers in parts, much like scientific notation does.', 'A sign, an exponent, and a fraction together encode each value.', 'An international standard governs exactly how it behaves across machines.', 'It is the format that represents real numbers using a movable radix point.']::text[], 'A method of representing real numbers using a sign, a fractional significand, and an exponent, analogous to scientific notation and standardized by IEEE 754. It spans a vast range of magnitudes at the cost of limited precision, which causes rounding errors in many decimal fractions.'),
  ('2026-08-21', 'Kernel', ARRAY['It is the innermost, most privileged part of the software that runs a computer.', 'It is the one component allowed to touch the hardware directly.', 'Ordinary programs must politely ask it to do anything sensitive.', 'It handles scheduling, memory, and device access at the lowest level.', 'It runs in a protected mode separate from regular applications.', 'It is the core of the operating system, with full control over the hardware.']::text[], 'The central, most privileged component of an operating system, running in a protected mode with direct control over hardware. It manages CPU scheduling, memory, device drivers, and system calls, mediating all access between applications and the machine.'),
  ('2026-08-22', 'Selection Sort', ARRAY['No matter what the input looks like, it always does the same amount of comparing.', 'It divides the list into a sorted part and an unsorted part, growing the first one element at a time.', 'On each pass it scans the unsorted part to find the smallest remaining value.', 'It then places that value at the end of the sorted part, making very few swaps overall.', 'Its comparisons are always quadratic, but it never moves an element more than once.', 'It repeatedly selects the minimum of the unsorted portion and appends it to the sorted portion.']::text[], 'A comparison sort that repeatedly finds the minimum of the unsorted portion and moves it to the end of the sorted portion. It always performs O(n²) comparisons regardless of input but at most n swaps, which matters when writes are costly.'),
  ('2026-08-23', 'Write-Ahead Log', ARRAY['It is the safety journal a database writes before touching the real data.', 'Every change is recorded here first, then applied.', 'After a crash, replaying it restores the database to a consistent state.', 'It is the mechanism behind durability in many storage engines.', 'Its append-only nature makes writing to it fast and sequential.', 'It is a log of changes written before they are applied, enabling crash recovery.']::text[], 'A durability technique in which every change is first appended to a sequential log on stable storage before being applied to the main data. After a crash, replaying the log restores a consistent state, underpinning the atomicity and durability of many databases and filesystems.'),
  ('2026-08-24', 'Dynamic Programming', ARRAY['It only pays off when the same small subproblem keeps showing up again and again.', 'Its confusing name has nothing to do with code that changes at runtime.', 'The trick is to solve each piece once and remember the answer.', 'It comes in a top-down memoized flavor and a bottom-up tabulated one.', 'Knapsack and longest-common-subsequence are among its classic problems.', 'It solves a problem by combining stored answers to overlapping subproblems.']::text[], 'An optimization method that solves problems by breaking them into overlapping subproblems, solving each once, and storing results (via memoization or tabulation) to avoid redundant work. It applies when a problem has optimal substructure and overlapping subproblems.'),
  ('2026-08-25', 'Firewall', ARRAY['It is the guard that decides which network traffic is allowed through.', 'It filters connections based on a set of configured rules.', 'It can block traffic by address, port, or protocol.', 'It forms a barrier between a trusted network and an untrusted one.', 'It exists in both hardware and software forms.', 'It is a security system that monitors and controls network traffic by rules.']::text[], 'A network security system that monitors and controls incoming and outgoing traffic based on configured rules, forming a barrier between trusted and untrusted networks. Firewalls filter by address, port, and protocol—and, in advanced forms, by application—and exist as hardware or software.'),
  ('2026-08-26', 'Red-Black Tree', ARRAY['It tolerates a bit more lopsidedness than the strictest balanced trees, trading perfect shape for fewer fix-ups.', 'Every node wears one of two colors, and rules about those colors keep it roughly balanced.', 'No path from top to bottom can be more than twice as long as any other.', 'It backs many standard-library ordered maps and sets.', 'After edits it repairs itself through recoloring and a few rotations.', 'It is a self-balancing search tree that uses two node colors and coloring rules to bound its height.']::text[], 'A self-balancing binary search tree in which each node is colored red or black and a set of color invariants ensures the longest root-to-leaf path is at most twice the shortest. It offers O(log n) operations with fewer rotations than an AVL tree and backs many library ordered maps and sets.'),
  ('2026-08-27', 'Binary Search', ARRAY['Its correctness rests on a precondition people frequently forget to check.', 'A slightly wrong midpoint calculation can overflow or loop forever on huge inputs.', 'Each comparison lets it throw away half of what remains.', 'It narrows a range by tracking a low and a high bound and probing the middle.', 'It runs in logarithmic time, but only on data that is already ordered.', 'It finds a value in a sorted list by repeatedly splitting the search range in half.']::text[], 'A search algorithm that finds a target in a sorted array by repeatedly comparing it to the middle element and discarding the half that cannot contain it. It runs in O(log n) but requires the data to be sorted.'),
  ('2026-08-28', 'TCP', ARRAY['It is the workhorse that makes an unreliable network feel dependable.', 'It guarantees your data arrives complete and in the right order.', 'It sets up a connection with a handshake before any data flows.', 'Lost pieces are detected and quietly resent.', 'It trades a little speed for reliability, unlike its lightweight sibling.', 'It is the connection-oriented protocol providing reliable, ordered delivery.']::text[], 'The Transmission Control Protocol, a core internet protocol providing reliable, ordered, error-checked delivery of a byte stream between applications. It opens a connection via a three-way handshake, retransmits lost data, and manages flow and congestion, trading some speed for reliability.'),
  ('2026-08-29', 'SQL Join', ARRAY['It is how a query pulls related rows from more than one table together.', 'It matches rows based on a condition, usually shared key values.', 'One variety keeps only rows that match on both sides.', 'Others deliberately keep unmatched rows, filling the gaps with nulls.', 'Done carelessly on large tables, it can be very expensive.', 'It is the SQL operation that combines rows from two tables on a related column.']::text[], 'A SQL operation that combines rows from two or more tables based on a related column, usually matching keys. Inner joins keep only matching rows, while outer joins also retain unmatched rows padded with nulls; joins recombine normalized data for queries.'),
  ('2026-08-30', 'Currying', ARRAY['It rewrites a function of several arguments as a chain of one-argument functions.', 'Each call in the chain takes one argument and hands back another function.', 'Supplying only some arguments produces a specialized function awaiting the rest.', 'It is named after the same logician as a well-known programming language.', 'It makes partial application natural and function composition cleaner.', 'It is the transformation of a multi-argument function into nested single-argument functions.']::text[], 'The technique of transforming a function of multiple arguments into a sequence of functions each taking one argument, so applying some arguments yields a specialized function awaiting the rest. Named after Haskell Curry, it enables partial application and cleaner composition.'),
  ('2026-08-31', 'Null Pointer', ARRAY['It points to nothing, which is exactly what makes it dangerous.', 'Trying to follow it typically crashes the program on the spot.', 'Its inventor famously called introducing it his billion-dollar mistake.', 'Forgetting to check for it before use is one of the most common bugs there is.', 'It is the special address value meaning "this refers to no object".', 'It is a pointer that deliberately references no valid memory location.']::text[], 'A pointer that references no valid object, represented by a special value such as null, nil, or nullptr. Dereferencing it causes a crash or exception; its inventor Tony Hoare called it his "billion-dollar mistake," and guarding against it is routine defensive practice.'),
  ('2026-09-01', 'Bloom Filter', ARRAY['It may claim to have seen something it never did, but it will never deny something it truly saw.', 'You can add items to it, but you can never remove one.', 'It answers "have I seen this?" using nothing but a row of bits.', 'Several hash functions each flip a few of those bits per item.', 'It trades exactness for a tiny, fixed amount of memory.', 'It is a probabilistic set that reports an item as possibly present or definitely absent.']::text[], 'A space-efficient probabilistic data structure that tests set membership using a bit array and several hash functions. It can produce false positives but never false negatives, trading exactness for very low memory, and is used to skip expensive lookups for items that are definitely absent.'),
  ('2026-09-02', 'Pointer', ARRAY['Its value is not the data you care about, but where to find that data.', 'Leave one dangling or empty and you get a classic crash.', 'Following it reaches through to the value it refers to.', 'Doing arithmetic on it moves in units of the type it targets.', 'C exposes it directly, while Java hides it behind safer references.', 'It is a variable that stores a memory address.']::text[], 'A variable whose value is the memory address of another value; dereferencing it accesses the data it points to. Pointers enable dynamic structures and efficient sharing, but null or dangling ones are a common source of crashes and security bugs.'),
  ('2026-09-03', 'Turing Machine', ARRAY['It is a deliberately primitive imaginary device, yet nothing real computes anything it cannot.', 'It consists of an endless tape, a head that reads and writes cells, and a table of rules.', 'Despite its simplicity it defines the very limits of what is computable.', 'What a modern computer can compute is exactly what it can compute.', 'It was introduced in the 1930s to make the idea of an algorithm precise.', 'It is the abstract machine, with an infinite tape and state rules, that formalizes computation.']::text[], 'An abstract device with an infinite tape, a read-write head, and a finite set of state-transition rules, introduced by Alan Turing to formalize computation. It captures exactly what any physical computer can compute and defines computability and decidability.'),
  ('2026-09-04', 'Randomized Algorithm', ARRAY['Run it twice on the same input and it may take different paths or even give different answers.', 'It deliberately uses random choices as part of its logic.', 'Some variants are always correct but random in how long they take.', 'Others run in a fixed time but are only probably correct.', 'Randomly choosing a pivot to dodge a sorting algorithm’s worst case is a classic use.', 'It is an algorithm that makes random choices to guide its behavior.']::text[], 'An algorithm that incorporates randomness into its logic. Las Vegas variants are always correct with random running time; Monte Carlo variants run in bounded time but are only probably correct. Randomization can simplify algorithms and avoid worst-case inputs, as in randomized quicksort.'),
  ('2026-09-05', 'Serialization', ARRAY['It flattens a living in-memory object into a form that can be stored or sent.', 'The reverse process rebuilds the object from that flat form later.', 'Formats for it include JSON, XML, and compact binary schemes.', 'It is how program state crosses between machines or survives to disk.', 'Deserializing untrusted input is a well-known security risk.', 'It is converting an in-memory object into a storable or transmittable format.']::text[], 'The process of converting an in-memory data structure or object into a format (such as JSON, XML, or a binary encoding) that can be stored or transmitted, with deserialization reconstructing it later. It enables persistence and communication across systems, though deserializing untrusted data is hazardous.'),
  ('2026-09-06', 'Clock Speed', ARRAY['It loosely indicates how many basic steps a processor can take each second.', 'It is measured in cycles per second, nowadays in the billions.', 'Raising it too far makes a chip run dangerously hot.', 'It is only a rough guide to real performance, which also depends on architecture.', 'Chipmakers hit a wall on it and turned to adding more cores instead.', 'It is the rate, measured in hertz, at which a CPU executes its basic cycle.']::text[], 'The frequency, measured in hertz (typically gigahertz), at which a CPU’s clock drives its fetch-decode-execute cycle. Higher speeds mean more cycles per second but more heat and power; because scaling it hit physical limits, designers shifted toward multiple cores.'),
  ('2026-09-07', 'Backtracking', ARRAY['It explores possibilities but abandons any path the moment it proves hopeless.', 'It builds up a candidate solution one choice at a time.', 'When a partial choice cannot possibly work, it undoes it and tries another.', 'Solving a maze, placing queens on a chessboard, or filling a Sudoku all use it.', 'It is essentially a depth-first exploration of the space of solutions, with pruning.', 'It is the strategy of trying choices, retreating on dead ends, and trying the next option.']::text[], 'A problem-solving strategy that incrementally builds candidate solutions and abandons a candidate as soon as it cannot be completed. Effectively a pruned depth-first search of the solution space, it solves constraint problems like N-queens, Sudoku, and maze-solving.'),
  ('2026-09-08', 'Kadane’s Algorithm', ARRAY['It solves a classic array problem in a single pass with no nested loops.', 'At each element it makes one simple decision: extend, or start fresh here.', 'It keeps a running best-ending-here total alongside the best seen anywhere.', 'A running total that goes negative is discarded, because it can only hurt what follows.', 'It finds the contiguous stretch of numbers with the largest possible sum.', 'It is the linear-time dynamic-programming method for the maximum-subarray problem.']::text[], 'A dynamic-programming algorithm that finds the maximum-sum contiguous subarray in one O(n) pass by tracking the best sum ending at the current position and the best overall, resetting the running sum whenever it turns negative.'),
  ('2026-09-09', 'Loop Invariant', ARRAY['It is a fact you pin down to convince yourself a loop is actually correct.', 'It must hold before the loop starts and remain true after every iteration.', 'Combined with the loop’s exit condition, it proves the final result is right.', 'It is the loop equivalent of the base-and-inductive reasoning used in proofs.', 'For a sorting loop, it might state that a prefix of the array is already sorted.', 'It is a condition that stays true throughout a loop and helps prove its correctness.']::text[], 'A condition that holds before a loop begins and after every iteration, used to reason formally about a loop’s correctness. Showing it is established initially, maintained each iteration, and combined with the exit condition proves the loop computes the intended result.'),
  ('2026-09-10', 'Factory Pattern', ARRAY['It hands responsibility for creating objects to a dedicated helper.', 'Calling code asks for an object without naming the concrete type it gets.', 'This lets the exact type produced be decided or swapped in one place.', 'It decouples what a program uses from how those things are constructed.', 'It is one of the creational patterns from the classic catalogue.', 'It is a pattern that delegates object creation instead of calling a constructor directly.']::text[], 'A creational design pattern that delegates object creation to a dedicated method or class, so client code requests an object by interface without naming its concrete class. This decouples usage from construction and centralizes decisions about which implementation to instantiate.'),
  ('2026-09-11', 'Hash Table', ARRAY['Its worst case is genuinely awful, yet in everyday use you almost never meet it.', 'A function turns each key into a position in an underlying array.', 'Two different keys can demand the same slot, so it needs a plan for those clashes.', 'Growing it means rebuilding the whole thing so the keys spread out again.', 'It gives average constant-time lookup, insertion, and deletion by key.', 'It is the key-value store that Python calls a dict and Java a HashMap.']::text[], 'A structure that maps keys to values by applying a hash function to compute an index into an array of buckets. It offers average O(1) insert, lookup, and delete using collision-resolution strategies such as chaining or open addressing, and degrades to O(n) in the rare worst case.'),
  ('2026-09-12', 'Event Loop', ARRAY['It is how a single-threaded program juggles many tasks without blocking.', 'It continuously pulls the next pending task from a queue and runs it.', 'Slow operations are handed off, and their results are queued for later.', 'It is the beating heart of JavaScript’s runtime.', 'A long-running task on it freezes everything else.', 'It is the loop that processes queued events and callbacks one at a time.']::text[], 'A construct that repeatedly takes events or tasks from a queue and dispatches their handlers one at a time, letting a single thread handle many concurrent operations without blocking. Long-running I/O is offloaded and its callbacks queued; it is central to Node.js and browser JavaScript.'),
  ('2026-09-13', 'Socket', ARRAY['It is the software endpoint a program uses to speak over a network.', 'It bundles an address and a port into one handle a program can read and write.', 'Opening one is how an application joins a network conversation.', 'Its interface makes network I/O look much like file I/O.', 'Both ends of a connection have one.', 'It is the programming endpoint through which a process sends and receives network data.']::text[], 'An endpoint for network communication, identified by an IP address and port, that a program uses to send and receive data. The socket API abstracts network I/O to resemble file operations, and a connection is defined by the pair of sockets at its two ends.'),
  ('2026-09-14', 'Denormalization', ARRAY['It deliberately breaks a tidy design in the name of speed.', 'It stores redundant copies of data to avoid expensive joins.', 'Reads get faster, but keeping the copies in sync becomes a burden.', 'It is common in read-heavy and analytics workloads.', 'It is essentially the reverse of the redundancy-removing process.', 'It is intentionally adding redundant data to a schema to improve read performance.']::text[], 'The deliberate introduction of redundancy into a schema—duplicating data or precomputing joins—to speed reads by avoiding expensive joins. The reverse of normalization, it improves read-heavy performance at the cost of extra storage and harder update consistency.'),
  ('2026-09-15', 'Message Queue', ARRAY['It lets two systems communicate without both being available at the same time.', 'A sender drops a message into it and moves on immediately.', 'A receiver picks the message up whenever it is ready.', 'It smooths out bursts by buffering work until it can be processed.', 'It decouples producers from consumers, improving resilience.', 'It is a buffer that holds messages between sender and receiver for asynchronous communication.']::text[], 'A component that enables asynchronous communication by holding messages sent by producers until consumers retrieve and process them. By decoupling senders from receivers in time, message queues buffer bursts, improve resilience, and enable scalable, loosely coupled architectures.'),
  ('2026-09-16', 'Quickselect', ARRAY['It answers a question a full sort could answer, but does far less work to do it.', 'It borrows the partitioning idea from a well-known sorting algorithm.', 'After partitioning, it recurses into only the side that must contain its target.', 'It finds the k-th smallest element without fully ordering the data.', 'On average it runs in linear time, though a bad pivot can ruin that.', 'It is the selection algorithm that partitions like quicksort but recurses on one side only.']::text[], 'A selection algorithm that finds the k-th smallest element of an unordered list by partitioning around a pivot (as in quicksort) and recursing only into the partition containing the target. It runs in O(n) on average and O(n²) in the worst case, avoiding a full sort.'),
  ('2026-09-17', 'Primary Key', ARRAY['It is the column whose value uniquely fingerprints each row.', 'No two rows may share the same one, and it can never be empty.', 'It is how other tables refer to a specific record.', 'A database automatically indexes it for fast lookup.', 'Sometimes it is a natural attribute, sometimes an auto-generated number.', 'It is the column (or columns) uniquely identifying each row in a table.']::text[], 'A column or set of columns whose value uniquely identifies each row in a table and which cannot be null or duplicated. It is the anchor other tables reference via foreign keys, and databases index it automatically for fast lookups.'),
  ('2026-09-18', 'Strong Typing', ARRAY['It refuses to quietly reinvent one kind of value as another behind your back.', 'Adding a number to a string, for instance, is rejected rather than guessed at.', 'It contrasts with looser systems that perform surprising automatic conversions.', 'It reduces a class of subtle bugs caused by unintended coercions.', 'It is about how strictly types are enforced, not about when they are checked.', 'It is a discipline that forbids operating on incompatible types without explicit conversion.']::text[], 'A typing discipline that strictly enforces type rules and disallows implicit, error-prone conversions between incompatible types, requiring explicit casts instead. Orthogonal to static versus dynamic typing, it reduces bugs from unintended coercions.'),
  ('2026-09-19', 'Atomic Operation', ARRAY['To the rest of the system it appears to happen all at once, with no in-between state.', 'It cannot be interrupted partway through by another thread.', 'This indivisibility is what makes it safe to use on shared data without a lock.', 'Compare-and-swap is a famous example used to build lock-free structures.', 'Hardware often provides a few of these as primitives.', 'It is an operation that completes indivisibly, appearing instantaneous to other threads.']::text[], 'An operation that appears to occur instantaneously and indivisibly to other threads—none can observe it half-completed. Provided by hardware (for example, compare-and-swap), atomics are the foundation of lock-free programming and safe access to shared data.'),
  ('2026-09-20', 'Singleton', ARRAY['It guarantees that only one instance of something can ever exist.', 'It provides a single, global point of access to that lone instance.', 'Configuration objects and connection pools sometimes use it.', 'Critics warn it acts like a global variable in disguise.', 'It often hurts testability by hiding a hard dependency.', 'It is the design pattern ensuring a class has just one instance, globally accessible.']::text[], 'A creational design pattern that restricts a class to a single instance and provides a global access point to it. Useful for shared resources like configuration or connection pools, it is often criticized for introducing global state that complicates testing and hides dependencies.'),
  ('2026-09-21', 'JSON', ARRAY['It is a lightweight text format that both humans and machines can read.', 'Its structure grew out of a scripting language’s object syntax.', 'It represents data as nested key-value pairs and ordered lists.', 'It has become the default way web APIs exchange data.', 'It supports only a handful of basic value types.', 'It is the text-based format for representing structured data as objects and arrays.']::text[], 'JavaScript Object Notation, a lightweight, human-readable text format representing structured data as key-value objects and ordered arrays with a few basic value types. Language-independent despite its origins, it is the de facto standard for data interchange in web APIs.'),
  ('2026-09-22', 'ASCII', ARRAY['It is an early scheme for turning characters into numbers.', 'It uses only seven bits, covering 128 possible characters.', 'It handles the English letters, digits, and basic punctuation, and little else.', 'Its inability to represent other languages spurred a much larger successor.', 'The letter A is 65 in it.', 'It is the standard mapping of basic English characters to 7-bit numbers.']::text[], 'The American Standard Code for Information Interchange, a 7-bit character encoding mapping 128 values to English letters, digits, punctuation, and control codes (for example, "A" is 65). Its limited range led to Unicode, and it remains a compatible subset of UTF-8.'),
  ('2026-09-23', 'Byte', ARRAY['It is the chunk a computer typically hands out as its smallest addressable piece of memory.', 'It is built from eight of the tiniest units of information.', 'It can represent 256 distinct values, enough for one character in older text encodings.', 'Storage is measured in multiples of it, like kilo, mega, and giga.', 'A single one usually holds one ASCII character.', 'It is a group of eight bits treated as a single unit.']::text[], 'A unit of digital information consisting of eight bits, able to represent 256 distinct values. It is typically the smallest individually addressable unit of memory and the standard measure of storage, historically encoding a single ASCII character.'),
  ('2026-09-24', 'Digital Signature', ARRAY['It proves both who created a message and that it was not altered.', 'It is produced using the sender’s private key.', 'Anyone can verify it using the matching public key.', 'It provides authenticity and makes denial of authorship impossible.', 'Software updates and certificates rely on it for trust.', 'It is a cryptographic stamp verifying a message’s origin and integrity.']::text[], 'A cryptographic mechanism in which a sender signs data with their private key, producing a value anyone can verify with the corresponding public key. It proves authenticity and integrity and provides non-repudiation, underpinning secure software distribution, certificates, and signed documents.'),
  ('2026-09-25', 'Eventual Consistency', ARRAY['It accepts brief disagreement in exchange for staying always available.', 'Different copies of the data may momentarily hold different values.', 'Given no new updates, all copies eventually converge to the same state.', 'It is a common choice in large distributed systems that favor availability.', 'It contrasts with the immediate agreement of strict consistency.', 'It is a model where replicas converge to the same value over time, not instantly.']::text[], 'A consistency model for distributed systems in which replicas may temporarily hold different values but, absent new updates, all converge to the same state over time. It favors availability and partition tolerance, accepting temporary staleness for responsiveness and scale.'),
  ('2026-09-26', 'Greedy Algorithm', ARRAY['It never looks back or reconsiders once it makes a choice.', 'At each step it simply grabs whatever looks best right now.', 'For some problems this shortsighted strategy still yields the true optimum.', 'Making change with coins and building certain minimum-cost trees rely on it.', 'Proving it actually works often requires showing a special structural property.', 'It builds a solution step by step, always taking the locally best option available.']::text[], 'A strategy that builds a solution incrementally, always choosing the option that looks best at the moment without reconsidering. It is simple and fast and gives optimal results for problems with the right structure, but can be suboptimal otherwise.'),
  ('2026-09-27', 'Rate Limiting', ARRAY['It caps how often a client may hit a service in a given window.', 'It protects a system from being overwhelmed, whether by abuse or bugs.', 'Exceeding the cap typically returns a "too many requests" response.', 'Common schemes include token buckets and fixed windows.', 'Public APIs use it to enforce fair usage across many callers.', 'It is the practice of restricting how many requests a client can make over time.']::text[], 'A technique that restricts how many requests a client may make to a service within a time window, protecting it from overload, abuse, and runaway cost. Implemented with schemes like token buckets or sliding windows, it typically returns a 429 "Too Many Requests" response when exceeded.'),
  ('2026-09-28', 'Coroutine', ARRAY['It is a function that can pause itself partway and resume later where it left off.', 'Unlike an ordinary function, it does not have to run to completion in one go.', 'It cooperatively hands control back rather than being forcibly interrupted.', 'It is a lightweight way to express concurrency without full threads.', 'Generators are a common, restricted form of it.', 'It is a routine that can suspend and resume, preserving its state between pauses.']::text[], 'A generalization of a subroutine that can suspend its execution and later resume from the same point, preserving local state across pauses. Coroutines yield control cooperatively, giving lightweight concurrency without OS threads, and underlie generators, async runtimes, and cooperative multitasking.'),
  ('2026-09-29', 'Model-View-Controller', ARRAY['It splits an application into three cooperating responsibilities.', 'One part holds the data and rules, cleanly separate from how things look.', 'Another renders what the user sees, and a third handles their input.', 'This separation lets the interface change without touching core logic.', 'It has shaped countless web and desktop application frameworks.', 'It is the architectural pattern dividing an app into model, view, and controller.']::text[], 'An architectural pattern that separates an application into the model (data and business rules), the view (presentation), and the controller (input handling that mediates between them). This separation of concerns improves modularity and has shaped many UI and web frameworks.'),
  ('2026-09-30', 'Encapsulation', ARRAY['It hides an object’s inner workings behind a controlled surface.', 'Outside code interacts only through an approved set of operations.', 'This lets the internals change without breaking anyone relying on the object.', 'It typically marks internal data as private and off-limits.', 'It bundles data together with the methods that are allowed to touch it.', 'It is the bundling of data with its methods while hiding internal details.']::text[], 'The bundling of data with the methods that operate on it, while restricting direct outside access to internal state behind a public interface. Encapsulation enforces invariants, reduces coupling, and lets implementations change without affecting client code.'),
  ('2026-10-01', 'Idempotence', ARRAY['It describes an operation you can repeat without changing the result further.', 'Doing it once or doing it five times leaves the same final state.', 'It makes safely retrying a failed request possible.', 'Setting a value to five has it; adding five to a value does not.', 'Certain web request methods are expected to have this property.', 'It is the property that repeating an operation yields the same result as doing it once.']::text[], 'A property of an operation whereby applying it multiple times yields the same result as applying it once, leaving state unchanged after the first application. Idempotence makes retries safe—crucial for unreliable networks and APIs—and characterizes HTTP methods like GET, PUT, and DELETE.'),
  ('2026-10-02', 'Compiler', ARRAY['It does all of its work before a program ever runs.', 'It reads a whole program in one language and produces an equivalent one in another.', 'It catches many mistakes up front that would otherwise surface only later.', 'Its output is usually a form the machine can run directly and fast.', 'It contrasts with a tool that instead executes source line by line.', 'It is the program that translates source code into machine code ahead of time.']::text[], 'A program that translates source code from one language (typically high-level) into another, usually machine code or bytecode, before execution. Compilation catches many errors ahead of time and produces fast-running output, in contrast with interpretation.'),
  ('2026-10-03', 'Firmware', ARRAY['It is software, yet it lives so close to the hardware that people forget it is software.', 'It is stored on a chip inside a device rather than loaded from a disk.', 'It is the first code that runs when many devices power on.', 'Updating it is riskier than updating an ordinary app; a failure can brick the device.', 'A router, a keyboard, and a hard drive each contain some.', 'It is low-level software embedded in a device to control its hardware.']::text[], 'Low-level software stored in non-volatile memory on a hardware device that controls the device’s basic functions and often runs first at power-on. Ranging from a PC’s BIOS/UEFI to the code inside peripherals, it sits between pure hardware and higher-level software and is updated cautiously.'),
  ('2026-10-04', 'Continuous Integration', ARRAY['It has developers merge their work into a shared codebase frequently.', 'Each merge automatically triggers a build and a test run.', 'This catches integration problems within minutes rather than weeks.', 'A broken build is meant to be fixed immediately, before other work continues.', 'It is often paired with automated deployment as a pipeline.', 'It is the practice of frequently merging code and automatically building and testing it.']::text[], 'A practice in which developers frequently merge changes into a shared repository, each merge automatically triggering a build and automated tests. By surfacing integration problems quickly, it keeps the codebase working and is often extended into continuous delivery pipelines.'),
  ('2026-10-05', 'Recursion', ARRAY['Done wrong, it is indistinguishable from a loop that eventually crashes.', 'Every step quietly consumes a little more of a resource you do not manage directly.', 'It leans on a terminating condition to know when to stop.', 'A function reduces a problem by invoking itself on something smaller.', 'Traversing a tree or computing a factorial are its textbook examples.', 'It is what happens when a function calls itself to solve smaller versions of a problem.']::text[], 'A technique where a function solves a problem by calling itself on smaller subproblems, converging toward a base case that stops the process. Each call adds a frame to the call stack, and tree traversals, divide-and-conquer, and backtracking are naturally expressed with it.'),
  ('2026-10-06', 'Assembler', ARRAY['It handles the last, smallest gap between human-written code and raw numbers.', 'Its input is already very close to what the processor executes.', 'It mostly swaps mnemonic names for the numeric codes they stand for.', 'There is nearly a one-to-one correspondence between its input and its output.', 'It sits one level below a compiler in the translation chain.', 'It is the tool that translates assembly language into machine code.']::text[], 'A program that translates assembly language—human-readable mnemonics for a processor’s instructions—into the corresponding machine code. The mapping is nearly one-to-one, making it the lowest-level translator in a typical toolchain.'),
  ('2026-10-07', 'CPU', ARRAY['It is the component that actually carries out a program’s instructions.', 'It endlessly repeats a cycle of fetching, decoding, and executing.', 'Its speed is loosely described by how many cycles it runs per second.', 'It contains arithmetic circuitry, control logic, and a handful of tiny fast stores.', 'It is often called the brain of the computer.', 'It is the central processor that executes the instructions of a program.']::text[], 'The central processing unit, the primary component that executes program instructions by repeatedly fetching, decoding, and executing them. It contains an arithmetic logic unit, control unit, and registers, and its clock speed and core count largely determine performance.'),
  ('2026-10-08', 'Object-Oriented Programming', ARRAY['It organizes a program around bundles of data and the behavior that acts on that data.', 'Those bundles are created from blueprints and interact by calling each other’s methods.', 'Four ideas anchor it: inheritance, polymorphism, encapsulation, and abstraction.', 'It aims to model real-world entities as self-contained units.', 'Java, C++, and C# are built squarely around it.', 'It is the paradigm that structures software as interacting objects with state and behavior.']::text[], 'A paradigm that structures software as objects—bundles of data (state) and the methods that operate on them—created from classes and interacting by invoking one another’s methods. Its pillars are encapsulation, inheritance, polymorphism, and abstraction, underlying languages like Java, C++, and C#.'),
  ('2026-10-09', 'Merge Conflict', ARRAY['It arises when two changes to the same code cannot be reconciled automatically.', 'The version-control tool throws up its hands and asks a human to decide.', 'It typically happens when two people edit the same lines differently.', 'Markers are inserted showing both competing versions.', 'Resolving it means choosing or combining the changes and marking it done.', 'It is a clash the version-control system cannot auto-resolve when merging changes.']::text[], 'A situation during a merge where a version-control system cannot automatically reconcile competing changes—typically because two branches edited the same lines differently—and needs a human to choose or combine the versions. The tool marks the conflicting regions for manual resolution.'),
  ('2026-10-10', 'Latency', ARRAY['It is about delay, not about how much data you can move.', 'It measures the time before a response even begins to arrive.', 'Distance and the number of hops both add to it.', 'It matters more than raw capacity for things like gaming and video calls.', 'It is often quoted as a round-trip time in milliseconds.', 'It is the time delay between sending a request and receiving a response.']::text[], 'The time delay between initiating an action and its effect—commonly the round-trip time for a network request, in milliseconds. Driven by distance, hops, and processing and distinct from bandwidth, latency dominates the feel of interactive applications like gaming and video calls.'),
  ('2026-10-11', 'Pigeonhole Principle', ARRAY['It is an almost absurdly obvious idea that nonetheless proves surprising results.', 'It reasons about what must happen when there are more items than containers.', 'It guarantees that at least one container ends up holding more than one item.', 'It proves, for instance, that two people in a large enough group share a birthday.', 'Hash collisions are ultimately unavoidable because of it.', 'It states that placing more items than boxes forces some box to hold at least two.']::text[], 'A basic combinatorial principle stating that if more than n items are placed into n containers, at least one container holds more than one item. Despite its simplicity, it proves powerful existence results, such as the inevitability of hash collisions and duplicate values.'),
  ('2026-10-12', 'Container', ARRAY['It packages an application with everything it needs so it runs the same everywhere.', 'Unlike a full virtual machine, it shares the host’s operating-system core.', 'That sharing makes it far lighter and faster to start.', 'It isolates processes and their dependencies without simulating hardware.', 'Docker popularized it, and Kubernetes orchestrates fleets of them.', 'It is a lightweight, isolated package of an application and its dependencies sharing the host kernel.']::text[], 'A lightweight, isolated unit that bundles an application with its dependencies and runs as isolated processes sharing the host operating system’s kernel, rather than emulating hardware like a virtual machine. Popularized by Docker and orchestrated by Kubernetes, containers start fast and give consistent environments across machines.'),
  ('2026-10-13', 'Interface', ARRAY['It is a promise about what an object can do, saying nothing about how.', 'It lists a set of operations a type agrees to provide.', 'Any type can fulfill it, and otherwise-unrelated types can share it.', 'Code written against it works with every type that satisfies it.', 'It enables polymorphism without requiring shared ancestry.', 'It is a contract of methods a type must implement, carrying no implementation itself.']::text[], 'A contract specifying a set of methods a type must provide, without dictating their implementation. Types that satisfy an interface can be used interchangeably by code written against it, enabling polymorphism and loose coupling independent of class hierarchy.'),
  ('2026-10-14', 'Stack Trace', ARRAY['It is the breadcrumb trail showing how a program reached the point of failure.', 'It lists the chain of function calls that were active at that moment.', 'Reading it traces the path back toward where things started.', 'It is a developer’s first clue when something crashes.', 'It is captured at the instant an error is raised.', 'It is a report of the active function call chain at a specific moment, usually an error.']::text[], 'A report of the active stack frames—the chain of function calls—at a particular point in execution, typically captured when an exception is thrown. It shows the sequence of calls leading to an error and is a primary tool for diagnosing and debugging failures.'),
  ('2026-10-15', 'Bellman-Ford Algorithm', ARRAY['Unlike the popular greedy alternative, it copes fine with edges of negative weight.', 'It can even detect when a graph contains a cycle that makes paths infinitely short.', 'It works by relaxing every edge repeatedly rather than settling nodes one at a time.', 'After enough rounds, all the tentative distances stop improving.', 'It runs slower than the greedy method but handles cases that method cannot.', 'It finds single-source shortest paths by relaxing all edges V minus one times.']::text[], 'A single-source shortest-path algorithm that relaxes all edges V−1 times, handling negative edge weights and detecting negative-weight cycles. It runs in O(V·E), slower than Dijkstra’s algorithm but more general.'),
  ('2026-10-16', 'Adjacency Matrix', ARRAY['It answers "are these two connected?" instantly, but pays for that speed in memory.', 'It uses a square grid whose rows and columns are both the network’s nodes.', 'A mark at row i, column j means node i links to node j.', 'For dense networks it is efficient, but for sparse ones it wastes enormous space.', 'Checking any single connection is a constant-time lookup.', 'It represents a graph as a two-dimensional grid marking which pairs of vertices are connected.']::text[], 'A graph representation using a square matrix where entry (i, j) records whether, or how heavily, vertex i connects to vertex j. It gives O(1) edge lookups and suits dense graphs but uses O(n²) space regardless of how few edges exist.'),
  ('2026-10-17', 'Master Theorem', ARRAY['It is a plug-in formula that spares you from solving certain recurrences by hand.', 'It applies specifically to divide-and-conquer algorithms.', 'It compares the cost of the recursive splitting against the cost of the combining work.', 'Whichever of those costs dominates decides the final growth rate.', 'It instantly gives the running time of merge sort and binary search.', 'It is the cookbook theorem for solving common divide-and-conquer recurrences.']::text[], 'A formula giving the asymptotic running time of divide-and-conquer recurrences of the form T(n) = a·T(n/b) + f(n) by comparing f(n) with n^(log_b a). It classifies the solution into three cases and quickly bounds algorithms like merge sort and binary search.'),
  ('2026-10-18', 'Kruskal’s Algorithm', ARRAY['It builds its answer by always grabbing the cheapest option that does not cause trouble.', 'It considers edges in increasing order of weight.', 'It adds an edge only if doing so would not form a loop.', 'A union-find structure is what lets it check for loops quickly.', 'It stops once every node is joined into a single connected tree.', 'It is the greedy method that builds a minimum spanning tree by adding the cheapest safe edges.']::text[], 'A greedy algorithm that builds a minimum spanning tree by sorting edges by weight and adding each edge that does not create a cycle, using a disjoint-set structure for cycle checks. It runs in O(E log E) and suits sparse graphs.'),
  ('2026-10-19', 'Packet', ARRAY['Data does not travel the network in one piece; it is chopped into these.', 'Each carries a payload wrapped in headers with addressing information.', 'Different ones from the same message may take different routes.', 'They can arrive out of order, or not at all, and higher layers cope.', 'Routers forward them one hop at a time toward their destination.', 'It is a small formatted unit of data carried across a packet-switched network.']::text[], 'A formatted unit of data transmitted over a packet-switched network, consisting of a payload plus headers carrying addressing and control information. Messages are split into packets routed independently, possibly out of order, and reassembled at the destination.'),
  ('2026-10-20', 'Binary Search Tree', ARRAY['Feed it already-sorted input and it quietly collapses into something no better than a list.', 'Reading it in one particular order magically produces sorted output.', 'At every node, smaller keys go one way and larger keys go the other.', 'That ordering rule lets a search throw away half of the remaining nodes at each step.', 'When kept balanced, it searches, inserts, and deletes in logarithmic time.', 'It is a binary tree that keeps its keys ordered so left is always less and right is always greater.']::text[], 'A binary tree maintaining the invariant that every node’s left subtree holds only smaller keys and its right subtree only larger keys. This enables O(log n) search, insertion, and deletion when balanced, degrading to O(n) when skewed; an in-order traversal yields the keys in sorted order.'),
  ('2026-10-21', 'Thread', ARRAY['It is a single stream of execution living inside a larger running program.', 'Several of them can run within one program, sharing its memory.', 'That shared memory makes them cheap to create but dangerous to coordinate.', 'Unsynchronized access among them leads to elusive, timing-dependent bugs.', 'It is a lighter-weight unit of execution than the process that contains it.', 'It is an independent path of execution that shares its process’s memory with others.']::text[], 'The smallest unit of execution scheduled by the operating system, running within a process and sharing that process’s memory with sibling threads. Threads enable cheap concurrency within a program, but shared state requires synchronization to avoid race conditions.'),
  ('2026-10-22', 'Compression', ARRAY['It shrinks data so it takes up less space or transfers faster.', 'It works by finding and eliminating redundancy in the data.', 'One family perfectly restores the original; another sacrifices detail for smaller size.', 'Photos and music often use the detail-sacrificing kind.', 'Repeated patterns are its favorite thing to exploit.', 'It is the process of encoding data to use fewer bits than the original.']::text[], 'The process of encoding data to use fewer bits than its original representation by exploiting redundancy. Lossless compression (e.g., ZIP) restores the exact original, while lossy compression (e.g., JPEG, MP3) discards less-noticeable detail for smaller size; both save storage and speed transfer.'),
  ('2026-10-23', 'Context-Free Grammar', ARRAY['It is powerful enough to describe nesting that a simpler pattern model cannot.', 'It is written as a set of rules that expand symbols into other symbols.', 'Programming-language syntax is standardly defined with one.', 'Its rules let one symbol become a sequence regardless of what surrounds it.', 'A parser uses it to turn flat source text into a tree structure.', 'It is the rule system, more powerful than regular expressions, that defines nested syntax.']::text[], 'A formal grammar of production rules that rewrite a single nonterminal into a sequence of symbols regardless of context. More expressive than regular expressions, it defines the syntax of most programming languages and underlies parsing and abstract syntax trees.'),
  ('2026-10-24', 'Scope', ARRAY['It answers the question of where a given name is even meaningful.', 'A name declared inside a block is often invisible outside it.', 'It prevents distant parts of a program from clashing over the same names.', 'It can nest, with inner regions able to see names from enclosing ones.', 'It comes in lexical and dynamic varieties, differing in how it is resolved.', 'It is the region of a program where a particular name is valid and accessible.']::text[], 'The region of a program in which a particular name (variable, function, and so on) is visible and usable. Scoping rules—commonly lexical, sometimes dynamic—prevent naming conflicts, control visibility and lifetime, and let inner scopes access names from enclosing ones.'),
  ('2026-10-25', 'Process', ARRAY['It is a running program considered together with everything it currently owns.', 'It gets its own private slice of memory, walled off from every other one.', 'Creating it is relatively heavy compared with the lighter units of work inside it.', 'Two of them must go through the operating system to share data.', 'It can contain one or more independent streams of execution.', 'It is an instance of a program in execution, with its own isolated memory space.']::text[], 'An instance of a running program, comprising its code, its own isolated memory space, and the resources the OS has allocated to it. Processes are isolated for protection, communicate through OS-mediated mechanisms, and each contains one or more threads.'),
  ('2026-10-26', 'Euclidean Algorithm', ARRAY['It is one of the oldest algorithms still in everyday use, dating back to antiquity.', 'It repeatedly replaces a pair of numbers with a smaller, equivalent pair.', 'At each step it swaps in the remainder of dividing one number by the other.', 'It stops when one number reaches zero, and the other is the answer.', 'It efficiently finds the largest number that divides two integers evenly.', 'It computes the greatest common divisor through repeated division with remainder.']::text[], 'An ancient, efficient method for computing the greatest common divisor of two integers by repeatedly replacing the larger with the remainder of dividing it by the smaller until one becomes zero. It runs in logarithmic time and extends to modular inverses.'),
  ('2026-10-27', 'Disjoint Set', ARRAY['Its whole job is to keep track of which items currently belong to the same cluster.', 'It supports just two moves: merge two clusters, and ask whether two items share one.', 'Two optimizations together make those moves run in nearly constant time.', 'Kruskal’s algorithm uses it to tell whether adding an edge would create a cycle.', 'Each cluster is identified by a representative element the others ultimately point to.', 'It is the union-find structure that tracks a partition of elements into merging groups.']::text[], 'A structure, also called union-find, that tracks a partition of elements into disjoint groups and supports union (merge two groups) and find (identify an element’s group). With path compression and union by rank it runs in near-constant amortized time, and is key to Kruskal’s algorithm and connectivity queries.'),
  ('2026-10-28', 'Scheduler', ARRAY['It is the referee that decides which waiting task gets to run next.', 'It divides limited processor time among many competing programs.', 'Its policy shapes whether the system feels responsive or sluggish.', 'Strategies range from simple round-robin to elaborate priority schemes.', 'It aims to balance fairness, throughput, and responsiveness.', 'It is the operating-system component that chooses which process or thread runs next.']::text[], 'The operating-system component that decides which ready process or thread runs on the CPU and for how long, using policies such as round-robin, priority, or fair-share scheduling. Its choices balance responsiveness, throughput, and fairness among competing tasks.'),
  ('2026-10-29', 'Halting Problem', ARRAY['It is the classic proof that some tasks are forever beyond any computer.', 'It concerns predicting a program’s behavior by analyzing it, not by running it.', 'The specific behavior in question is whether a program will ever stop.', 'A clever self-referential contradiction shows no general solver can exist.', 'Alan Turing proved it unsolvable in the 1930s.', 'It is the undecidable task of deciding whether an arbitrary program eventually stops or runs forever.']::text[], 'The problem of determining, for an arbitrary program and input, whether the program will eventually halt or run forever. Alan Turing proved in 1936 that no general algorithm can decide this, making it the canonical example of an undecidable problem.'),
  ('2026-10-30', 'Bit', ARRAY['It is the smallest possible unit of information there is.', 'It has exactly two possible states and nothing in between.', 'Eight of them grouped together form a more familiar unit.', 'Physically it might be a charged capacitor, a magnetized spot, or a voltage level.', 'It is usually written as either 0 or 1.', 'It is a single binary digit, the atom of all digital data.']::text[], 'The smallest unit of digital information, representing one of two states, conventionally written 0 or 1. All data and instructions in a computer are ultimately encoded as sequences of these, and eight of them make a byte.'),
  ('2026-10-31', 'Boolean Logic', ARRAY['Everything in it reduces to just two values: true and false.', 'Its handful of operations combine those values in fixed, predictable ways.', 'The physical gates inside every processor implement it directly.', 'A table can exhaustively list every possible outcome of its operations.', 'It is named after the 19th-century mathematician who formalized it.', 'It is the algebra of true and false values combined with and, or, and not.']::text[], 'A branch of algebra dealing with values that are either true or false, combined using operations such as AND, OR, and NOT. Formalized by George Boole, it is the theoretical basis of digital logic circuits and of conditional expressions in programming.'),
  ('2026-11-01', 'Object', ARRAY['It is a concrete, individual thing built from a general blueprint.', 'It bundles some data together with the operations allowed on that data.', 'Many of them can share a blueprint yet each hold different values.', 'It typically interacts with others by having its methods called.', 'It is what you actually work with at runtime, unlike the template it came from.', 'It is a specific instance of a class, holding state and exposing behavior.']::text[], 'A runtime instance of a class that bundles state (its field values) with behavior (its methods). Multiple objects can share a class yet hold independent data, collaborating by invoking one another’s methods—the basic unit of object-oriented programs.'),
  ('2026-11-02', 'Queue', ARRAY['Fairness is its defining virtue: nothing is served ahead of what arrived before it.', 'You add at one end and remove from the other.', 'Print spoolers and task schedulers are naturally built around it.', 'Its two core moves are usually called enqueue and dequeue.', 'Its discipline is first in, first out.', 'It works like a line of people waiting their turn, served in the order they arrived.']::text[], 'An abstract data type with first-in-first-out (FIFO) ordering, supporting enqueue (add to the back) and dequeue (remove from the front). Queues are central to scheduling, buffering, and breadth-first traversal.'),
  ('2026-11-03', 'Cache', ARRAY['Knowing what to throw out of it is famously one of the hard problems in computing.', 'It bets that whatever was just used will be wanted again very soon.', 'A hit is fast; a miss falls through to something slower behind it.', 'When full, a policy such as least-recently-used decides what to evict.', 'Processors stack several levels of it close to their cores.', 'It is a small, fast store holding copies of frequently or recently used data.']::text[], 'A small, fast storage layer that keeps copies of frequently or recently used data so future requests are served quickly. Governed by eviction policies like LRU when full, caches appear throughout computing—CPU caches, disk caches, web caches—exploiting locality of reference.'),
  ('2026-11-04', 'Method Overloading', ARRAY['It lets several functions share one name as long as they differ in their parameters.', 'The compiler picks which to call based on the arguments you pass.', 'It is resolved before the program runs, unlike its runtime-decided cousin.', 'A print that accepts an int, a string, or a list illustrates it.', 'It offers convenience, letting related operations share a familiar name.', 'It is defining multiple methods with the same name but different parameter lists.']::text[], 'Defining multiple methods or functions with the same name but different parameter lists in the same scope; the compiler selects which to call from the argument types and count. Resolved at compile time, it is a form of ad-hoc polymorphism that improves API convenience.'),
  ('2026-11-05', 'Linear Search', ARRAY['It makes no assumptions at all about how the data is arranged.', 'It simply looks at each element in turn until it finds what it wants.', 'On unsorted data it is often the only option available.', 'Its cost grows in direct proportion to the number of elements.', 'In the worst case it inspects every single element before answering.', 'It finds a value by checking elements one by one from start to finish.']::text[], 'The simplest search: it examines each element of a collection in sequence until the target is found or the collection is exhausted. It runs in O(n), requires no ordering, and is the fallback when data is unsorted or lacks indexed access.'),
  ('2026-11-06', 'Dangling Pointer', ARRAY['It still points somewhere, but what it points to is no longer valid.', 'It arises when the memory it referenced has already been freed.', 'Following it yields unpredictable behavior—sometimes garbage, sometimes a crash.', 'Reusing freed memory through one is a serious security vulnerability.', 'Setting a pointer to empty right after freeing helps avoid it.', 'It is a pointer that refers to memory that has been released or is otherwise invalid.']::text[], 'A pointer that still references memory which has been freed, moved, or gone out of scope, so the data there is no longer valid. Dereferencing it causes undefined behavior and use-after-free vulnerabilities; nulling pointers after freeing and clear ownership rules prevent it.'),
  ('2026-11-07', 'Stored Procedure', ARRAY['It is program logic that lives and runs inside the database itself.', 'It bundles a sequence of queries into one callable routine.', 'Running it avoids repeated round trips between application and database.', 'It can accept parameters and return results like a function.', 'Critics note it scatters business logic outside the application.', 'It is a named, reusable block of SQL stored and executed in the database.']::text[], 'A named, precompiled block of SQL and procedural logic stored in the database and invoked by name, optionally with parameters. Stored procedures encapsulate reusable operations, cut round trips between application and database, and can improve performance, though they move logic into the database.'),
  ('2026-11-08', 'Regular Expression', ARRAY['It is no more powerful than a finite automaton, and provably cannot describe everything.', 'Trying to use it to fully parse nested markup is a running programmer joke.', 'An engine compiles it into a state machine that scans text.', 'Quantifiers, character classes, and anchors are its building blocks.', 'It matches, extracts, and replaces text according to a pattern.', 'It is the compact pattern notation usually shortened to "regex".']::text[], 'A compact notation for describing text patterns, used to match, search, extract, and replace strings. Equivalent in power to finite automata, it combines literals, character classes, quantifiers, and anchors, and cannot describe arbitrarily nested structures.'),
  ('2026-11-09', 'Bandwidth', ARRAY['It describes capacity, not speed of response.', 'It is the maximum amount of data a link can carry in a given time.', 'A wide one lets large files transfer quickly once they start.', 'It is often confused with the delay before data begins arriving.', 'It is usually measured in bits per second.', 'It is the maximum rate at which data can be transferred over a connection.']::text[], 'The maximum rate at which data can be transferred over a network connection, typically in bits per second. Distinct from latency (delay), higher bandwidth moves more data per unit time, which matters most for large transfers and many simultaneous users.'),
  ('2026-11-10', 'Type System', ARRAY['It is the set of rules classifying the values a program manipulates.', 'Its job is to catch certain mistakes by ensuring operations get sensible operands.', 'It can enforce its rules before the program runs or while it runs.', 'A stricter one catches more errors early but constrains the programmer more.', 'It underlies the distinction between an integer, a string, and a boolean.', 'It is the rules a language uses to assign and check the types of values.']::text[], 'The set of rules a language uses to assign types to values and expressions and constrain how they combine, catching many errors before or during execution. Type systems vary along axes like static versus dynamic and strong versus weak, trading safety against flexibility.'),
  ('2026-11-11', 'Fenwick Tree', ARRAY['It performs a clever trick with the binary form of indices to accumulate partial totals.', 'It maintains running totals over ranges of an array while still allowing quick updates.', 'It does the same range-sum job as a heavier structure but with less memory and shorter code.', 'Flipping the lowest set bit of an index is how it walks up and down its implicit tree.', 'It answers prefix-sum queries and point updates both in logarithmic time.', 'It is the compact array-based structure, also called a binary indexed tree, for fast prefix sums.']::text[], 'A compact array-based structure, also known as a binary indexed tree, that maintains prefix sums of a sequence while supporting point updates, both in O(log n). It exploits the binary representation of indices to navigate an implicit tree, using less space and code than a segment tree for cumulative-frequency problems.'),
  ('2026-11-12', 'Amortized Analysis', ARRAY['It looks past a single pricey operation to the average cost across a long run.', 'It explains why a structure with occasional slow steps can still be efficient overall.', 'A resizable array that doubles its capacity is its classic example.', 'Techniques like the accounting or potential method make it rigorous.', 'It differs from average-case analysis, which instead averages over random inputs.', 'It is the analysis that spreads the cost of rare expensive operations over many cheap ones.']::text[], 'A method of analysis that averages the cost of operations over a sequence, showing that occasional expensive operations are affordable when spread across many cheap ones. Using the aggregate, accounting, or potential method, it explains why appending to a doubling array is amortized O(1).'),
  ('2026-11-13', 'CAP Theorem', ARRAY['It says a distributed system cannot promise everything at once.', 'It names three desirable properties and forces a compromise among them.', 'When the network splits, you must sacrifice one of the two remaining guarantees.', 'It explains why some databases choose availability over strict consistency.', 'Its three letters stand for consistency, availability, and partition tolerance.', 'It states a distributed store can guarantee only two of those three properties at once.']::text[], 'A principle stating that a distributed data store can simultaneously guarantee at most two of consistency, availability, and partition tolerance. Since network partitions are unavoidable, real systems must trade consistency against availability during a partition, shaping database design.'),
  ('2026-11-14', 'Inheritance', ARRAY['It lets one type acquire the features of another without rewriting them.', 'The new type extends an existing one, adding or changing behavior.', 'It expresses an "is a kind of" relationship between types.', 'Overused, it produces brittle, deeply nested hierarchies.', 'Many now favor combining simpler parts over relying on it.', 'It is the mechanism by which a class derives fields and methods from a parent class.']::text[], 'A mechanism by which a subclass derives the fields and methods of a superclass, extending or overriding them to model an "is-a" relationship. It promotes reuse but, overused, creates rigid, deep hierarchies, prompting the guideline to favor composition.'),
  ('2026-11-15', 'SQL', ARRAY['It is the standard language for talking to a table-based database.', 'You describe what data you want, not how to fetch it.', 'Its core verbs select, insert, update, and delete.', 'Joins let it combine rows from several tables at once.', 'Improperly building its queries from user input invites a classic attack.', 'It is the declarative language for querying and managing relational databases.']::text[], 'Structured Query Language, the standard declarative language for defining, querying, and manipulating relational databases. With statements like SELECT, INSERT, UPDATE, and DELETE plus joins and aggregation, it specifies what data is wanted rather than how to retrieve it.'),
  ('2026-11-16', 'Topological Sort', ARRAY['It only makes sense on a network that has a direction and no loops.', 'It produces an order in which every prerequisite comes before whatever depends on it.', 'Build systems and course-scheduling problems ask for exactly this ordering.', 'If the network contains a cycle, no valid ordering exists and it must fail.', 'One way to compute it repeatedly removes nodes that currently have nothing pointing at them.', 'It arranges the vertices of a directed acyclic graph so every edge points forward.']::text[], 'An ordering of the vertices of a directed acyclic graph such that for every edge u→v, u precedes v. Computable via DFS or repeated removal of zero-in-degree nodes (Kahn’s algorithm) in O(V+E), it schedules tasks with dependencies and fails if the graph has a cycle.'),
  ('2026-11-17', 'Logic Gate', ARRAY['It is the tiny physical building block from which all computation is assembled.', 'It takes one or more on/off inputs and produces a single on/off output.', 'Its behavior mirrors a basic operation of true-false algebra.', 'Wiring many of them together yields adders, memory, and entire processors.', 'A couple of specific types are enough to build every other type.', 'It is a hardware element that computes a basic boolean function of its inputs.']::text[], 'A physical device that implements a basic boolean function (such as AND, OR, NOT, NAND, or XOR), producing an output signal from its input signals. Logic gates are the fundamental building blocks of digital circuits, combining to form adders, memory, and processors.'),
  ('2026-11-18', 'Dijkstra’s Algorithm', ARRAY['Introduce a single negative weight and its guarantees quietly fall apart.', 'It always expands whichever unfinished node is currently closest to the start.', 'It keeps improving tentative distances as shorter routes are discovered.', 'A priority queue is what makes it efficient on large graphs.', 'It computes shortest paths from one source to every other node in a weighted graph.', 'It is the classic greedy shortest-path method, named after a Dutch computer scientist.']::text[], 'A greedy algorithm that computes shortest paths from a single source to all vertices in a graph with non-negative edge weights, repeatedly settling the nearest unvisited node with a priority queue. It runs in about O((V+E) log V) and fails with negative weights.'),
  ('2026-11-19', 'Heap Memory', ARRAY['Unlike its orderly counterpart, it hands out memory in no particular order.', 'It is where data whose lifetime you control yourself lives.', 'You explicitly ask for a block and, in some languages, must give it back.', 'Forgetting to release it is a classic cause of slow memory leaks.', 'It is slower to allocate from than the automatic region but far more flexible.', 'It is the pool of memory used for dynamic, manually managed allocation.']::text[], 'A region of memory used for dynamic allocation, where blocks are requested and freed explicitly (or reclaimed by a garbage collector) and can outlive the function that created them. Flexible but slower than stack allocation, it is prone to leaks and fragmentation, and is unrelated to the heap data structure.'),
  ('2026-11-20', 'Buffer Overflow', ARRAY['It happens when a program writes past the edge of the space set aside for data.', 'The spilled data corrupts whatever memory sits just beyond it.', 'In unsafe languages it is a notorious gateway for attackers.', 'Carefully crafted overspill can hijack a program’s control flow.', 'Bounds checking and safe string handling are the standard defenses.', 'It occurs when data written to a buffer exceeds its capacity and overruns adjacent memory.']::text[], 'A condition where a program writes more data to a fixed-size buffer than it can hold, overwriting adjacent memory. Beyond crashes, buffer overflows are a classic security vulnerability, since crafted input can overwrite return addresses and hijack execution.'),
  ('2026-11-21', 'Hexadecimal', ARRAY['It is a compact shorthand humans use for long strings of ones and zeros.', 'It works in base sixteen, so it needs six extra symbols beyond the usual digits.', 'Each of its digits stands in for exactly four binary digits.', 'Colors in web pages and memory addresses are commonly written in it.', 'The letters A through F extend its counting past nine.', 'It is the base-sixteen number system used as a concise stand-in for binary.']::text[], 'A base-16 number system using digits 0–9 and letters A–F, where each digit represents exactly four bits. Its compactness makes it a convenient human-readable shorthand for binary data such as memory addresses, color codes, and byte values.'),
  ('2026-11-22', 'Database Schema', ARRAY['It is the blueprint describing how a database is organized.', 'It defines the tables, their columns, and the types those columns hold.', 'It also captures the keys and relationships tying tables together.', 'Changing it on a live system must be done carefully to avoid breakage.', 'Some databases enforce it strictly; others are flexible about it.', 'It is the formal definition of a database’s structure and constraints.']::text[], 'The formal definition of a database’s structure: its tables, columns and their types, keys, relationships, and constraints. The schema is a blueprint the database enforces; altering it on a live system (a migration) must be handled carefully to avoid breaking applications.'),
  ('2026-11-23', 'Dynamic Array', ARRAY['It hides an occasional expensive moment behind many cheap ones, so on average each addition still feels instant.', 'Underneath it wraps a fixed block that it silently swaps for a larger one when space runs out.', 'When it fills up it typically doubles its capacity and copies everything into the new space.', 'That doubling trick is why appending is constant time when averaged over many operations.', 'It gives you index access like a plain array but without a size you must decide in advance.', 'It is the resizable list behind names like vector, ArrayList, and the Python list.']::text[], 'An array-backed list that grows automatically by allocating a larger block (usually doubling capacity) and copying elements when full. It provides O(1) indexed access and amortized O(1) append, and underlies structures such as C++ vector, Java ArrayList, and Python list.'),
  ('2026-11-24', 'REST', ARRAY['It is a style for designing web services, not a strict protocol.', 'It treats everything as a resource identified by a URL.', 'It leans on the standard web verbs to act on those resources.', 'Each request carries everything needed, with the server keeping no session.', 'It commonly exchanges data in a lightweight text format.', 'It is an architectural style for web APIs based on stateless resource operations.']::text[], 'Representational State Transfer, an architectural style for networked APIs that models everything as resources identified by URLs and manipulated with standard HTTP methods. REST is stateless, cacheable, and typically exchanges JSON, making it the dominant style for web services.'),
  ('2026-11-25', 'Lambda', ARRAY['It is a function without a name.', 'It is typically written inline, right where it is needed.', 'It is handy for short throwaway operations passed to another function.', 'It often captures variables from the surrounding scope, forming a closure.', 'Its name comes from a formal system of computation built on functions.', 'It is an anonymous function defined inline rather than declared with a name.']::text[], 'An anonymous function defined inline, without a bound name, typically used as a short throwaway passed to a higher-order function. Named after the lambda calculus, lambdas often capture surrounding variables to form closures and are common in functional-style code.'),
  ('2026-11-26', 'Transaction', ARRAY['It groups several operations so they succeed or fail as one unit.', 'If any step fails, everything it did is rolled back as if nothing happened.', 'Transferring money between accounts is the textbook example.', 'It protects data integrity when many operations must stay consistent.', 'Its guarantees are summarized by a four-letter acronym.', 'It is a unit of work executed as an all-or-nothing whole.']::text[], 'A sequence of database operations executed as a single all-or-nothing unit: either all commit or, on failure, all roll back, leaving the database unchanged. Transactions preserve integrity for multi-step operations like fund transfers and are characterized by the ACID properties.'),
  ('2026-11-27', 'Test-Driven Development', ARRAY['It insists you write the test before the code it checks.', 'The first run of that test is expected to fail.', 'You then write just enough code to make it pass.', 'A cleanup step follows, made safe because the test now guards behavior.', 'Its cycle is often summarized as red, green, refactor.', 'It is the practice of writing failing tests first, then code to satisfy them.']::text[], 'A development practice in which you write a failing test for desired behavior first, then write the minimum code to make it pass, then refactor—repeating the red-green-refactor cycle. It drives design, ensures coverage, and builds confidence to change code safely.'),
  ('2026-11-28', 'Bitmask', ARRAY['It is a specially chosen pattern of ones and zeros used to isolate parts of a value.', 'Combined with a bitwise AND, it clears every position except the ones you care about.', 'It lets many yes/no flags be packed into a single number.', 'Setting, clearing, or testing an individual flag all rely on one.', 'Permissions like read, write, and execute are commonly stored using it.', 'It is a pattern of bits used to select or modify specific bits within another value.']::text[], 'A pattern of bits used with bitwise operations to select, set, clear, or toggle specific bits within a value. Masks let multiple boolean flags be packed into one integer and are widely used for permissions, feature flags, and low-level configuration.'),
  ('2026-11-29', 'Executable', ARRAY['It is a file you can run directly, with nothing left to translate.', 'It bundles machine instructions together with the data a program needs to start.', 'A loader reads it into memory and hands control to its starting point.', 'Its internal format follows conventions specific to the operating system.', 'On Windows it usually ends in a familiar three-letter extension.', 'It is a file containing a program in ready-to-run machine-code form.']::text[], 'A file containing a program in ready-to-run form—machine instructions plus metadata and data—that the operating system can load into memory and run. Its structure follows a platform-specific format (such as ELF or PE), and a loader maps it in and jumps to its entry point.'),
  ('2026-11-30', 'RAM', ARRAY['Cut the power and everything it was holding vanishes instantly.', 'Any location in it can be reached just as quickly as any other.', 'Running programs and their data live here while in use.', 'It is far faster than a disk but far smaller and more expensive per byte.', 'Its name emphasizes that access time does not depend on location.', 'It is the fast, volatile main memory a computer uses for active data.']::text[], 'Random-access memory, the fast, volatile main memory that holds the code and data of running programs. Any location can be read or written in roughly constant time regardless of address, but its contents are lost when power is removed.'),
  ('2026-12-01', 'Floyd-Warshall Algorithm', ARRAY['Instead of solving from one starting point, it solves for every starting point at once.', 'It gradually allows more and more nodes to serve as intermediate stops.', 'Its whole logic fits into three tidy nested loops.', 'It handles negative edges, though not negative cycles.', 'Its cubic running time is acceptable only for reasonably small graphs.', 'It computes shortest paths between every pair of vertices using dynamic programming.']::text[], 'A dynamic-programming algorithm that finds shortest paths between all pairs of vertices by progressively allowing each vertex as an intermediate point, via three nested loops. It runs in O(V³), handles negative edges (but not negative cycles), and suits small or dense graphs.'),
  ('2026-12-02', 'Three-Way Handshake', ARRAY['It is the brief negotiation that opens a reliable connection.', 'It involves three messages exchanged before any data is sent.', 'One side proposes, the other acknowledges and proposes back, and the first confirms.', 'Its purpose is to synchronize sequence numbers and confirm both sides are ready.', 'The reliable transport protocol uses it to begin every connection.', 'It is the three-step exchange that establishes a TCP connection.']::text[], 'The three-step process by which TCP establishes a connection: the client sends SYN, the server replies SYN-ACK, and the client responds ACK. This exchange synchronizes sequence numbers and confirms both sides are ready before data transfer begins.'),
  ('2026-12-03', 'Observer Pattern', ARRAY['It lets objects react automatically when something they care about changes.', 'One subject keeps a list of dependents to notify.', 'When the subject’s state changes, it broadcasts an update to all of them.', 'The subject need not know anything about who is listening.', 'Event systems and UI data-binding are built on it.', 'It is the pattern where a subject notifies registered observers of its state changes.']::text[], 'A behavioral design pattern in which a subject maintains a list of dependents (observers) and notifies them automatically when its state changes. It enables loose, one-to-many, event-driven communication and underlies UI data binding, event listeners, and publish-subscribe systems.'),
  ('2026-12-04', 'Closure', ARRAY['It is a function that carries a piece of its birthplace around with it.', 'Even after the surrounding function returns, it still remembers those variables.', 'This lets it keep private state between calls without any global data.', 'Callbacks and function factories rely on it constantly.', 'It captures the variables of the scope in which it was defined.', 'It is a function bundled together with the environment it was created in.']::text[], 'A function bundled with references to variables from the scope in which it was defined, so it can access and remember them even after that scope has exited. Closures enable private state, callbacks, and function factories, and are central to functional programming.'),
  ('2026-12-05', 'Foreign Key', ARRAY['It is how one table points at a specific row in another.', 'Its value must match an existing key in the referenced table.', 'It is the mechanism that links related data across tables.', 'The database can enforce that it never points at something nonexistent.', 'It expresses relationships like an order belonging to a customer.', 'It is a column referencing the primary key of another table to link them.']::text[], 'A column or columns in one table whose values must match a primary key in another, establishing a link between the two. Foreign keys enforce referential integrity—preventing references to nonexistent rows—and model relationships such as orders belonging to customers.'),
  ('2026-12-06', 'TLS', ARRAY['It is the invisible layer that makes secure browsing possible.', 'It scrambles data so anyone intercepting it sees only noise.', 'It begins with a handshake that agrees on keys and verifies identity.', 'It replaced an older, now-insecure protocol of a similar name.', 'Certificates from trusted authorities anchor the trust it provides.', 'It is the protocol that encrypts and authenticates data sent over a network.']::text[], 'Transport Layer Security, a cryptographic protocol that encrypts and authenticates data sent over a network, protecting confidentiality and integrity. Through a handshake it negotiates keys and verifies identity with certificates; it secures HTTPS and succeeds the deprecated SSL.'),
  ('2026-12-07', 'IP Address', ARRAY['It is the number that tells the network where to deliver data.', 'Every device on a network needs one to be reachable.', 'An older format is running out, forcing a much larger replacement.', 'A separate naming system exists so humans need not memorize them.', 'It is often split into a network part and a host part.', 'It is the numerical label identifying a device on an IP network.']::text[], 'A numerical label assigned to each device on a network using the Internet Protocol, used to route data to the right destination. IPv4 addresses are 32 bits and nearly exhausted; IPv6 uses 128 bits to expand the space, and DNS maps names to these numbers.'),
  ('2026-12-08', 'Merge Sort', ARRAY['Its running time is the same whether the input is random, already sorted, or reversed.', 'It typically needs extra memory proportional to the size of the input.', 'It preserves the relative order of equal elements.', 'It splits the input in half over and over, then stitches the pieces back together.', 'The combining step interleaves two already-sorted runs into one.', 'It is the divide-and-conquer sort that recursively splits, then merges sorted halves.']::text[], 'A divide-and-conquer sort that recursively splits the array in half, sorts each half, and merges the sorted halves. It runs in O(n log n) in all cases and is stable, usually at the cost of O(n) extra space.'),
  ('2026-12-09', 'Set', ARRAY['It cares about membership, not counting or ordering: something is either in or out.', 'Ask it to hold the same value twice and it still keeps only one.', 'It is built for one fast question: have I seen this before?', 'Union, intersection, and difference are its natural operations.', 'Adding a value that is already present simply does nothing.', 'It is a collection of distinct elements with no duplicates allowed.']::text[], 'A collection that stores unique elements with no duplicates and typically no inherent order, optimized for fast membership tests. Sets support union, intersection, and difference and are usually backed by a hash table or balanced tree.'),
  ('2026-12-10', 'Parallelism', ARRAY['It requires genuinely running more than one thing at the exact same moment.', 'It fundamentally needs more than one processing unit to occur.', 'It splits a large task into pieces that run side by side to finish sooner.', 'A law named after Amdahl caps the speedup its inherently sequential parts allow.', 'It is often contrasted with merely interleaving tasks over time.', 'It is the simultaneous execution of multiple computations on multiple processors.']::text[], 'The simultaneous execution of multiple computations across multiple processing units to solve a problem faster. Distinct from concurrency (overlapping tasks that may share one core), its speedup is bounded by the sequential fraction of the work, as described by Amdahl’s law.'),
  ('2026-12-11', 'Heap', ARRAY['Finding its single most extreme element is instant, but finding any other is not.', 'It is almost always stored as a flat array with no pointers at all.', 'Every parent stands in a fixed order relationship with each of its children.', 'Inserting a value and removing the top element each cost logarithmic time.', 'It is the structure that makes a priority queue efficient.', 'It is a complete binary tree kept in either min- or max-order at every level.']::text[], 'A complete binary tree satisfying the heap property, where each parent is ordered relative to its children (min-heap or max-heap). Usually stored compactly in an array, it supports O(log n) insertion and extraction of the extreme element and underpins priority queues and heapsort.'),
  ('2026-12-12', 'Normalization', ARRAY['Its goal is to store each fact in exactly one place.', 'It splits data across tables to eliminate redundancy.', 'This prevents contradictions where copies of the same fact disagree.', 'It proceeds through a series of increasingly strict normal forms.', 'Its downside is that answering a query may require joining many tables.', 'It is the process of organizing tables to reduce redundancy and dependency.']::text[], 'The process of structuring relational tables to reduce redundancy and dependency by decomposing them according to a series of normal forms, so each fact is stored once. It prevents update anomalies and inconsistencies, at the cost of requiring joins to reassemble related data.'),
  ('2026-12-13', 'Database Index', ARRAY['It speeds up lookups the way a book’s index beats reading every page.', 'It is a separate structure the database maintains alongside the data.', 'It makes reads faster but slows writes and consumes extra space.', 'It is often built on a balanced tree kept sorted by key.', 'Querying an unindexed column forces a slow full scan.', 'It is an auxiliary structure that speeds up row lookups on chosen columns.']::text[], 'An auxiliary structure, typically a B-tree or hash, that a database maintains to speed lookups, filtering, and sorting on chosen columns—much like a book’s index. Indexes accelerate reads at the cost of extra storage and slower writes, and querying unindexed columns forces full scans.'),
  ('2026-12-14', 'Proxy', ARRAY['It is a stand-in that relays requests on your behalf.', 'Traffic passes through it rather than going straight to the destination.', 'It can hide your identity, filter content, or cache responses.', 'It sits in front of clients, unlike its reverse cousin that fronts servers.', 'Companies use it to control and monitor outbound web access.', 'It is an intermediary server that forwards requests between a client and a destination.']::text[], 'An intermediary server that forwards requests from clients to other servers and returns the responses, acting on the client’s behalf. Proxies provide anonymity, caching, filtering, and access control; a forward proxy fronts clients, while a reverse proxy fronts servers.'),
  ('2026-12-15', 'Skip List', ARRAY['It brings binary-search speed to a linked structure by stacking express lanes above the slow one.', 'Higher levels let a search leap over many elements before dropping down a level.', 'It decides each node’s height by coin flips rather than by careful balancing.', 'On average it matches a balanced tree’s logarithmic performance with far simpler code.', 'Its layered shortcuts are what let a search jump ahead instead of crawling.', 'It is a layered, sorted linked list whose upper levels act as express lanes for fast search.']::text[], 'A probabilistic structure built from a sorted linked list augmented with multiple levels of forward "express" pointers, each node’s height chosen randomly. It supports search, insertion, and deletion in O(log n) expected time and is a simpler alternative to balanced trees.'),
  ('2026-12-16', 'Operating System', ARRAY['It is the software layer standing between your programs and the bare hardware.', 'It decides which program gets the processor and when.', 'It manages memory, files, and devices on every program’s behalf.', 'It keeps programs isolated so one crashing does not take down the rest.', 'Windows, macOS, and Linux are the household examples.', 'It is the software that manages a computer’s hardware and runs its programs.']::text[], 'The software layer that manages a computer’s hardware and resources—CPU scheduling, memory, files, and devices—and provides services and isolation to applications. Examples include Windows, macOS, and Linux, and its privileged core is the kernel.'),
  ('2026-12-17', 'Radix Sort', ARRAY['It sorts numbers without ever directly comparing two of them.', 'It processes the input one digit position at a time.', 'It relies on a stable sub-sort at each digit so earlier passes are not undone.', 'It can go from least significant digit to most, or the reverse.', 'For fixed-width keys it achieves linear time overall.', 'It sorts by repeatedly bucketing elements digit by digit, using a stable pass each round.']::text[], 'A non-comparison sort that orders numbers or fixed-length keys by processing one digit (or group of bits) at a time, using a stable sub-sort such as counting sort per pass. For d digits it runs in O(d·(n + k)), giving linear time when key width is bounded.'),
  ('2026-12-18', 'Higher-Order Function', ARRAY['It works with other functions the way ordinary functions work with numbers.', 'It either accepts a function as an argument, returns one, or both.', 'Mapping, filtering, and reducing a collection are its everyday uses.', 'It relies on functions being treated as first-class values.', 'It lets you abstract over actions, not just over data.', 'It is a function that takes or returns another function.']::text[], 'A function that takes one or more functions as arguments, returns a function, or both. Enabled by first-class functions, higher-order functions such as map, filter, and reduce abstract over behavior and are a cornerstone of functional programming.'),
  ('2026-12-19', 'Adjacency List', ARRAY['It is the space-thrifty way to write down a network when most possible connections do not exist.', 'For each node it simply keeps a list of that node’s neighbors.', 'Sparse networks store far more compactly this way than in a full grid.', 'Walking over one node’s connections is quick, but checking one specific pair is slower.', 'Most graph algorithms assume the network is stored in this form.', 'It represents a graph by giving, for every vertex, the collection of vertices it links to.']::text[], 'A graph representation that stores, for each vertex, a list of its adjacent vertices. It uses space proportional to the number of edges, making it efficient for sparse graphs, and is the representation assumed by most traversal and shortest-path algorithms.'),
  ('2026-12-20', 'UTF-8', ARRAY['It is the dominant way of turning universal character numbers into bytes on the web.', 'It uses a variable number of bytes, from one to four, per character.', 'Plain English text in it is byte-for-byte identical to the old 7-bit standard.', 'This backward compatibility drove its near-universal adoption.', 'Common characters stay small while rarer ones take more bytes.', 'It is the variable-width byte encoding of Unicode that is compatible with ASCII.']::text[], 'A variable-width encoding of Unicode that represents each code point in one to four bytes, with ASCII characters encoded identically to 7-bit ASCII in a single byte. Its backward compatibility and efficiency made it the dominant text encoding on the web and in modern systems.'),
  ('2026-12-21', 'Binary Exponentiation', ARRAY['It computes a huge power without multiplying the base that many times.', 'It leans on the binary representation of the exponent.', 'Squaring repeatedly lets it cover the whole exponent in far fewer steps.', 'It turns a linear number of multiplications into a logarithmic one.', 'Cryptography uses it constantly to raise numbers to enormous powers under a modulus.', 'It raises a number to a power in logarithmic time by squaring and combining results.']::text[], 'A technique that computes b^n in O(log n) multiplications by squaring the base repeatedly and multiplying the powers matching the set bits of the exponent. Also called exponentiation by squaring, it is fundamental to modular arithmetic and cryptography.'),
  ('2026-12-22', 'Key-Value Store', ARRAY['It is about the simplest database model imaginable.', 'Every item is just a value retrieved by a unique lookup key.', 'It knows nothing about the structure of the values it holds.', 'This simplicity makes it extremely fast and easy to scale.', 'Caches and session stores are often built on one.', 'It is a database that stores data as a collection of key-to-value pairs.']::text[], 'A NoSQL database that stores data as unique keys each mapped to an opaque value, offering fast, simple get/put access without interpreting the value’s structure. Its simplicity enables high performance and easy scaling, making it popular for caches, sessions, and configuration.'),
  ('2026-12-23', 'Throughput', ARRAY['It measures what you actually get, not what the link promises.', 'It is the real rate of successful data delivery over time.', 'Overhead, congestion, and errors all keep it below the theoretical maximum.', 'It differs from raw capacity, which is only an upper bound.', 'It is what benchmarks report when they time a real transfer.', 'It is the actual rate at which useful data is successfully delivered.']::text[], 'The actual rate at which useful data is successfully delivered over a network or system, usually in bits or operations per second. Unlike bandwidth (theoretical capacity), throughput reflects real conditions such as overhead, congestion, and retransmissions.'),
  ('2026-12-24', 'Public-Key Cryptography', ARRAY['It cleverly uses two different but mathematically linked keys.', 'One key can be shared with the whole world; the other is kept secret.', 'Anything locked with the public key can only be opened with the private one.', 'It solves the age-old problem of exchanging a secret over an open channel.', 'It also underpins digital signatures that prove authorship.', 'It is encryption using a matched pair of public and private keys.']::text[], 'A cryptographic system using a mathematically linked pair of keys—a public key shared freely and a private key kept secret—where data encrypted with one is decrypted with the other. Also called asymmetric cryptography, it enables secure communication without prior secret exchange and supports digital signatures.'),
  ('2026-12-25', 'Paging', ARRAY['It chops memory into equal-sized blocks so any block can go anywhere.', 'This eliminates the wasteful gaps that variable-sized allocation leaves behind.', 'A lookup table records where each virtual block currently sits physically.', 'A small fast hardware cache remembers recent translations to keep it quick.', 'When a needed block is not resident, a fault fetches it from disk.', 'It is the scheme that divides memory into fixed-size pages mapped independently.']::text[], 'A memory-management scheme that divides virtual and physical memory into fixed-size pages and frames, mapped through a page table so a process’s pages can reside anywhere in physical memory. It avoids external fragmentation and underlies virtual memory and demand paging.'),
  ('2026-12-26', 'Graph', ARRAY['Direction, weight, and cycles are all optional flavors it can take or leave.', 'It is nothing more than a set of things and the connections among them.', 'You can store it as lists of neighbors or as a grid marking connections.', 'Social networks, road maps, and dependency charts are all naturally modeled by it.', 'A route through it that returns to where it started is called a cycle.', 'It is a collection of vertices joined by edges.']::text[], 'A structure of vertices (nodes) connected by edges, which may be directed or undirected and weighted or unweighted. Represented via adjacency lists or matrices, graphs model networks, maps, dependencies, and relationships, and are explored with traversals like BFS and DFS.'),
  ('2026-12-27', 'Database', ARRAY['It is the organized home where an application keeps its long-lived information.', 'Unlike working memory, what it holds survives restarts and crashes.', 'Dedicated software manages storing, querying, and updating its contents.', 'It comes in relational, document, key-value, and other flavors.', 'Many programs can safely read and write it at once.', 'It is an organized, persistent collection of data managed by dedicated software.']::text[], 'An organized, persistent collection of structured data managed by a database management system that supports efficient storage, retrieval, updating, and concurrent access. Databases come in many models—relational, document, key-value, graph—and underpin nearly all applications that remember data.'),
  ('2026-12-28', 'Encryption', ARRAY['It scrambles information so only the intended party can make sense of it.', 'Without the right secret, the result looks like meaningless noise.', 'Reversing it to recover the original requires a key.', 'It protects data both while stored and while in transit.', 'It comes in symmetric and public-key varieties.', 'It is the process of encoding data so only authorized parties can read it.']::text[], 'The process of transforming readable plaintext into unreadable ciphertext using an algorithm and a key, so only parties with the correct key can reverse it. Encryption protects the confidentiality of data at rest and in transit and comes in symmetric and asymmetric forms.'),
  ('2026-12-29', 'Breadth-First Search', ARRAY['On the right kind of graph it hands you shortest paths as a free side effect.', 'It fans outward in rings of equal distance from where it started.', 'It fully finishes one layer before touching the next.', 'A queue decides which node it visits next.', 'It is the natural counterpart to going as deep as possible first.', 'It is the graph traversal that explores level by level outward from the source.']::text[], 'A graph traversal that visits all nodes at the current distance from the source before moving outward, using a queue. Running in O(V+E), it finds shortest paths in unweighted graphs and explores the graph level by level.'),
  ('2026-12-30', 'HTTP', ARRAY['It is the language browsers and servers use to talk to each other.', 'Every web page you load is fetched using it.', 'It works as a series of requests met by responses.', 'It is stateless: each request stands alone, remembering nothing by itself.', 'Its methods include get, post, put, and delete.', 'It is the protocol for transferring web pages and data between client and server.']::text[], 'The Hypertext Transfer Protocol, the request-response protocol underlying the web, by which clients request resources and servers respond. It is stateless, uses methods like GET and POST plus status codes, and typically runs over TCP; its secure form is HTTPS.'),
  ('2026-12-31', 'Brute Force', ARRAY['It makes no attempt to be clever; it just tries everything.', 'It is often the easiest solution to write and the slowest to run.', 'It systematically enumerates every candidate and checks each one.', 'Its cost usually explodes as the problem grows, quickly becoming impractical.', 'It serves as a correctness baseline against which smarter methods are compared.', 'It solves a problem by exhaustively trying all possibilities until one works.']::text[], 'A straightforward approach that systematically enumerates all possible candidates and tests each against the problem’s conditions. Simple and always correct, it is typically inefficient—often exponential or factorial—and serves as a baseline for comparing smarter algorithms.'),
  ('2027-01-01', 'Imperative Programming', ARRAY['It describes a computation as a sequence of commands that change state.', 'It focuses on how to accomplish a task, step by explicit step.', 'Loops, assignments, and conditionals are its bread and butter.', 'It mirrors closely how the underlying hardware actually operates.', 'It contrasts with styles that describe what result is wanted, not how.', 'It is the paradigm of giving the computer an explicit ordered list of state-changing steps.']::text[], 'A paradigm that expresses computation as an explicit sequence of statements that change program state, focusing on how to achieve a result via assignments, loops, and conditionals. Close to the machine model, it contrasts with declarative styles that specify what is wanted rather than how.'),
  ('2027-01-02', 'DNS', ARRAY['It is essentially the phone book of the internet.', 'It spares you from having to remember strings of numbers.', 'It translates the names you type into the addresses machines use.', 'Its answers are cached at many levels to speed things up.', 'An outage in it can make working sites appear completely unreachable.', 'It is the system that resolves human-readable domain names into IP addresses.']::text[], 'The Domain Name System, a hierarchical, distributed directory that translates human-readable domain names into the IP addresses machines use to locate each other. Results are cached at many levels for speed, and it is essential infrastructure for the web.'),
  ('2027-01-03', 'Abstract Class', ARRAY['It is a blueprint that is deliberately left incomplete.', 'You cannot create an instance of it directly.', 'It exists to be extended by more specific subclasses.', 'It can mix finished methods with ones that subclasses must fill in.', 'It sits between a plain class and a pure interface.', 'It is a class that cannot be instantiated and is meant to be subclassed.']::text[], 'A class that cannot be instantiated on its own and is designed to be extended. It may provide implemented methods alongside abstract ones that subclasses must define, letting it share common code while requiring descendants to supply certain behavior.'),
  ('2027-01-04', 'Integer Overflow', ARRAY['It happens when a value grows past the largest amount its container can hold.', 'The excess often does not raise an error; it silently wraps around.', 'A large positive number can suddenly become negative because of it.', 'It has caused famous failures, from arcade games to a rocket launch.', 'Fixed-width storage is the root cause: only so many bits are available.', 'It is what occurs when an arithmetic result exceeds the range a fixed-size integer can store.']::text[], 'A condition where an arithmetic operation produces a result outside the range representable by a fixed-width integer type, causing the value to wrap around (or, in some languages, raise an error). It is a common source of subtle bugs and security vulnerabilities.'),
  ('2027-01-05', 'Context Switch', ARRAY['It is the overhead price a system pays to create the illusion of doing many things at once.', 'It happens whenever the processor sets one task aside to work on another.', 'The state of the outgoing task must be saved so it can resume later untouched.', 'Doing too many of them wastes time that could have gone to real work.', 'A timer interrupt often triggers one to enforce fair sharing.', 'It is the act of saving one task’s state and loading another’s so the CPU can switch tasks.']::text[], 'The act of saving the state (registers, program counter, and so on) of one running task and restoring another’s so the CPU can switch between processes or threads. It enables multitasking but incurs overhead, so excessive switching hurts performance.'),
  ('2027-01-06', 'Bytecode', ARRAY['It is a middle ground between human source and raw hardware instructions.', 'It targets an imaginary machine rather than any real processor.', 'A runtime either interprets it or compiles it further just before execution.', 'It lets the same compiled program run on many different platforms.', 'Java and the .NET languages both compile to a form of it.', 'It is the portable, intermediate instruction set run by a virtual machine.']::text[], 'A compact, portable, intermediate instruction set produced by a compiler and executed by a virtual machine, which either interprets it or compiles it to native code at runtime. Bytecode enables "write once, run anywhere" portability, as with Java and the .NET runtime.'),
  ('2027-01-07', 'Endianness', ARRAY['It concerns the order in which the pieces of a multi-byte value are laid down.', 'Two machines can store the same number with its bytes in opposite sequence.', 'One convention puts the most significant byte first, the other puts it last.', 'It becomes a real headache when different systems exchange raw binary data.', 'Network protocols pick one order and declare it the standard.', 'It is the convention for the byte order of a multi-byte value in memory.']::text[], 'The convention determining the order in which the bytes of a multi-byte value are stored or transmitted. Big-endian stores the most significant byte first; little-endian stores the least significant first. Mismatches must be handled when systems exchange binary data, and networks define a standard order.'),
  ('2027-01-08', 'Divide and Conquer', ARRAY['Its power comes from turning one big problem into several much smaller copies of itself.', 'It solves those smaller copies independently, often recursively.', 'A final step combines their answers into the answer for the whole.', 'Merge sort and fast multiplication algorithms follow this pattern.', 'Its running time is usually captured by a recurrence relation.', 'It is the strategy of splitting a problem, solving the parts, and merging their results.']::text[], 'A paradigm that breaks a problem into smaller independent subproblems of the same type, solves them (usually recursively), and combines their solutions. It underlies merge sort, quicksort, binary search, and fast multiplication, and its cost is analyzed with recurrences.'),
  ('2027-01-09', 'UDP', ARRAY['It fires data off and never looks back to see whether it arrived.', 'It skips handshakes, ordering, and retransmission entirely.', 'This makes it fast and lightweight but unreliable.', 'Live video, voice calls, and games favor it, tolerating an occasional lost packet.', 'It is the no-frills counterpart to the reliable stream protocol.', 'It is the connectionless protocol that sends datagrams without guarantees.']::text[], 'The User Datagram Protocol, a lightweight, connectionless internet protocol that sends independent packets without establishing a connection, ordering, or guaranteeing delivery. Its low overhead suits latency-sensitive uses like streaming, gaming, and DNS, where occasional loss is acceptable.'),
  ('2027-01-10', 'Heuristic', ARRAY['It aims for a good-enough answer quickly rather than a perfect one slowly.', 'It offers no guarantee of finding the true optimum.', 'It is invaluable when an exact solution would take impractically long.', 'Pathfinding searches use one to estimate the remaining distance to a goal.', 'A rule of thumb like "always take the nearest option" is a simple example.', 'It is a practical shortcut that trades guaranteed optimality for speed.']::text[], 'A problem-solving shortcut or rule of thumb that produces good-enough solutions quickly without guaranteeing optimality or even correctness. Heuristics are essential for intractable or real-time problems, guiding searches (as in A*) and optimization where exact methods are too slow.'),
  ('2027-01-11', 'P vs NP', ARRAY['It is a single unanswered question that carries a million-dollar prize.', 'It asks whether being able to check an answer quickly implies being able to find one quickly.', 'Most researchers believe the two abilities are not the same, but no one has proven it.', 'A surprising "yes" would upend modern cryptography overnight.', 'It concerns two famous complexity classes, one nested inside the other.', 'It is the open question of whether every quickly verifiable problem is also quickly solvable.']::text[], 'The central open problem in computer science asking whether P (problems solvable in polynomial time) equals NP (problems whose solutions are verifiable in polynomial time). Widely believed false, a resolution carries a Millennium Prize and would deeply affect cryptography and optimization.'),
  ('2027-01-12', 'Depth-First Search', ARRAY['Skip one small bookkeeping set and it can wander a loop forever.', 'It commits completely to one path before considering any alternative.', 'It backs up only once it hits a dead end.', 'A stack, or the call stack via recursion, drives the order it explores.', 'Cycle detection and topological sorting are built on it.', 'It is the graph traversal that goes as deep as possible before backtracking.']::text[], 'A graph and tree traversal that explores as far as possible along each branch before backtracking, implemented with recursion or an explicit stack. It runs in O(V+E) and underlies topological sorting, cycle detection, and connectivity analysis.'),
  ('2027-01-13', 'Cookie', ARRAY['It is how a stateless web remembers who you are between requests.', 'The server asks the browser to store a small piece of data.', 'The browser sends it back on every later request to that site.', 'It powers login sessions, shopping carts, and tracking.', 'Privacy rules increasingly demand consent before setting some kinds.', 'It is a small piece of data a site stores in the browser to persist state.']::text[], 'A small piece of data a website stores in the user’s browser and that the browser returns on subsequent requests, letting the stateless web remember state such as login sessions, preferences, and carts. Cookies also enable tracking, prompting privacy regulation and consent requirements.'),
  ('2027-01-14', 'ACID', ARRAY['It is a four-letter promise about how reliable a database transaction is.', 'Its first letter demands all-or-nothing execution.', 'Another letter guarantees a transaction never leaves data in an invalid state.', 'It also promises concurrent transactions do not corrupt each other.', 'Its final letter ensures committed changes survive a crash.', 'It is the acronym for the reliability guarantees of database transactions.']::text[], 'An acronym for the four guarantees of reliable database transactions: Atomicity (all-or-nothing), Consistency (valid states only), Isolation (concurrent transactions do not interfere), and Durability (committed changes survive failures). ACID compliance is a hallmark of traditional relational databases.'),
  ('2027-01-15', 'Two’s Complement', ARRAY['It is the clever trick that lets the same hardware add and subtract without caring about signs.', 'It is the standard way computers store numbers that can be negative.', 'Flipping every bit and adding one negates a value in it.', 'Its leftmost bit alone reveals whether a number is negative.', 'It has one more negative value than positive, and only a single representation of zero.', 'It is the binary scheme for signed integers where the top bit carries negative weight.']::text[], 'The standard binary encoding of signed integers, in which the most significant bit carries negative weight, so a value is negated by inverting all bits and adding one. It lets addition and subtraction share the same circuitry and has a single representation of zero.'),
  ('2027-01-16', 'Heapsort', ARRAY['It borrows a specialized tree structure to sort without needing extra memory.', 'First it rearranges the array so it obeys a parent-child ordering rule.', 'Then it repeatedly pulls off the largest element and shrinks the ordered region.', 'Its worst case stays well-behaved, unlike some sorts that are faster on average.', 'It runs in guaranteed n-log-n time, in place, but it is not stable.', 'It sorts by building a max-heap and repeatedly extracting the maximum to the array’s end.']::text[], 'A comparison sort that builds a max-heap from the array, then repeatedly swaps the root (maximum) to the end and re-heapifies the remainder. It runs in O(n log n) worst-case time in place, but is not stable.'),
  ('2027-01-17', 'Virtual Machine', ARRAY['It is an entire computer that exists only as software running on another computer.', 'It lets one physical machine pretend to be several independent ones.', 'Each instance believes it has its own hardware, all of it simulated.', 'A layer called a hypervisor creates and manages them.', 'Cloud providers rent out computing power in the form of these.', 'It is a software emulation of a complete computer that runs its own operating system.']::text[], 'A software emulation of a complete computer that runs its own operating system and applications on a host, managed by a hypervisor that allocates the real hardware. VMs provide strong isolation and let one machine host many systems, underpinning cloud computing. (Distinct from a language virtual machine that runs bytecode.)'),
  ('2027-01-18', 'Quicksort', ARRAY['One unlucky choice on already-sorted data can drag it down to its worst case.', 'Despite that quadratic worst case, it is often the fastest sort in practice.', 'It rearranges elements around one chosen value on each step.', 'It usually sorts in place, needing almost no extra memory.', 'Everything smaller than the chosen value goes before it and everything larger after.', 'It is the divide-and-conquer sort built around partitioning by a pivot.']::text[], 'A divide-and-conquer sort that selects a pivot, partitions elements into those less than and greater than it, and recursively sorts the partitions. It averages O(n log n) and sorts in place, but degrades to O(n²) with consistently poor pivots.'),
  ('2027-01-19', 'HTTPS', ARRAY['It is the everyday web protocol wrapped in a protective layer.', 'It keeps data exchanged with a website private from eavesdroppers.', 'It also verifies you are really talking to the site you think you are.', 'A padlock icon in the address bar signals its presence.', 'It relies on certificates and encryption to do its job.', 'It is the secure, encrypted version of the web’s core transfer protocol.']::text[], 'HTTP secured with TLS encryption, providing confidentiality, integrity, and authentication for web traffic so data cannot be read or tampered with in transit and the server’s identity is verified by certificates. It is now the default for virtually all websites.'),
  ('2027-01-20', 'Call Stack', ARRAY['It grows and shrinks automatically as a program dives into and returns from functions.', 'Each function call pushes a fresh frame holding its locals and where to return.', 'When a function finishes, its frame is popped and its local variables vanish.', 'Its strict last-in-first-out order mirrors how nested calls unwind.', 'Runaway recursion exhausts it and triggers a well-known error.', 'It is the region of memory that tracks active function calls in last-in-first-out order.']::text[], 'A region of memory organized as a stack that manages active function calls: each call pushes a frame with its parameters, local variables, and return address, popped when the call returns. Its LIFO discipline matches nested call-and-return, and exhausting it causes a stack overflow.'),
  ('2027-01-21', 'Async/Await', ARRAY['It lets asynchronous code be written as if it were ordinary sequential code.', 'One keyword marks a function as capable of pausing.', 'Another keyword pauses until a pending operation settles, without blocking the thread.', 'Under the hood it is built on top of promises.', 'It largely eliminates visible callback nesting.', 'It is the syntax that makes asynchronous code read like synchronous code.']::text[], 'Language syntax, built on promises, that lets asynchronous code be written in a sequential, readable style: an async function can pause at an await expression until the awaited operation settles, without blocking the thread. It flattens callback and promise chains into straightforward-looking code.'),
  ('2027-01-22', 'Finite State Machine', ARRAY['It remembers only which of a fixed set of situations it is currently in, nothing more.', 'An input nudges it from its current situation into another according to fixed rules.', 'It has no unbounded memory, so it cannot count arbitrarily high.', 'Traffic lights, vending machines, and lexical scanners are modeled with it.', 'It is exactly as powerful as the patterns a certain text-matching notation can describe.', 'It is a model of computation that is always in exactly one of a finite number of states.']::text[], 'A computational model always in exactly one of a finite set of states, moving between them in response to inputs via a transition function. Lacking unbounded memory, it recognizes precisely the regular languages and models protocols, parsers, and controllers.'),
  ('2027-01-23', 'Suffix Tree', ARRAY['It preprocesses one piece of text so that later questions about it can be answered blazingly fast.', 'It compactly stores every possible ending of a single string.', 'Once built, checking whether any pattern occurs takes time proportional only to the pattern’s length.', 'Bioinformatics uses it heavily to search long DNA sequences.', 'It is essentially a trie of all of a string’s suffixes, with single chains compressed.', 'It is the compressed tree of all suffixes of a string, built for fast substring search.']::text[], 'A compressed trie containing all suffixes of a given string, enabling substring search, repeated-pattern detection, and many string problems in time proportional to the query length after linear-time construction. It is powerful but memory-intensive, and heavily used in text processing and bioinformatics.'),
  ('2027-01-24', 'Pure Function', ARRAY['Give it the same inputs and it always returns the same output, forever.', 'It quietly changes nothing in the outside world.', 'It never reads or writes global state, files, or the screen.', 'This predictability makes it trivial to test and safe to run in parallel.', 'It has no observable effect beyond the value it returns.', 'It is a function whose result depends only on its inputs and which causes no side effects.']::text[], 'A function whose return value depends solely on its arguments and which produces no side effects—no mutation of external state, I/O, or hidden dependencies. Pure functions are deterministic, easy to test, cacheable, and safe to parallelize, and are a foundation of functional programming.'),
  ('2027-01-25', 'Instruction Pipeline', ARRAY['It keeps a processor busy by starting new work before the old work finishes.', 'It splits instruction handling into stages, like an assembly line.', 'While one instruction is being decoded, the next is already being fetched.', 'A mispredicted branch can force it to throw away partly-done work.', 'It boosts throughput without making any single instruction faster.', 'It is the technique of overlapping the stages of consecutive instructions in a CPU.']::text[], 'A CPU technique that overlaps execution of multiple instructions by dividing processing into stages (fetch, decode, execute, and so on), so different instructions occupy different stages at once, like an assembly line. It raises throughput but must handle hazards such as branch mispredictions.'),
  ('2027-01-26', 'Linker', ARRAY['It performs the final assembly step that turns separate pieces into one whole.', 'It stitches together the many object files a build produces.', 'It resolves references where one file calls something defined in another.', 'It also pulls in the library code a program depends on.', 'An unresolved reference at this stage is a classic build failure.', 'It is the tool that combines object files and libraries into a single executable.']::text[], 'A program that combines compiled object files and libraries into a single executable or library, resolving cross-references between them and assigning final addresses. Missing definitions surface here as linker errors, and linking may be static (baked in) or dynamic (resolved at load time).'),
  ('2027-01-27', 'Replication', ARRAY['It keeps copies of the same data on more than one machine.', 'If one copy fails, another can take over with little disruption.', 'It also spreads read traffic across the copies to boost performance.', 'Keeping the copies in sync introduces lag and consistency questions.', 'It commonly follows a leader-and-followers arrangement.', 'It is maintaining duplicate copies of data across servers for reliability and scale.']::text[], 'The practice of maintaining copies of the same data on multiple servers to improve availability, fault tolerance, and read scalability. Often arranged as a leader that accepts writes and followers that copy them, replication introduces synchronization lag and consistency trade-offs.'),
  ('2027-01-28', 'Race Condition', ARRAY['Its defining trait is that the outcome depends on unpredictable timing.', 'It appears only sometimes, which makes it maddening to reproduce.', 'It arises when multiple threads touch shared data without coordination.', 'The final result depends on which thread happens to win the moment.', 'Proper locking or atomic operations are the cure.', 'It is a bug where the result depends on the unsynchronized timing of concurrent operations.']::text[], 'A flaw in concurrent systems where correctness depends on the relative timing or interleaving of operations on shared state. Because the offending schedule occurs only intermittently, such bugs are hard to reproduce; they are prevented with synchronization like locks or atomic operations.'),
  ('2027-01-29', 'Binary Tree', ARRAY['Branching is strictly limited here: no part of it ever splits more than two ways.', 'It starts from a single topmost point and fans downward.', 'Each element may have a left child, a right child, both, or neither.', 'Visiting its elements in different orders yields several different useful sequences.', 'Its height determines how many steps it takes to reach the deepest element.', 'It is a tree in which every node has at most two children.']::text[], 'A hierarchical structure in which each node has at most two children, called left and right. Binary trees underpin many specialized forms (search trees, heaps, expression trees) and are traversed in pre-order, in-order, post-order, or level-order.'),
  ('2027-01-30', 'Relational Database', ARRAY['It organizes all its data into tidy tables of rows and columns.', 'Relationships between tables are drawn using shared key values.', 'A specialized declarative language queries and updates it.', 'It enforces structure through a predefined schema.', 'It typically guarantees reliable, all-or-nothing transactions.', 'It is a database that stores data in tables linked by keys.']::text[], 'A database that stores data in tables (relations) of rows and columns, with relationships expressed through shared key values and structure enforced by a schema. Queried with SQL and typically offering ACID transactions, it is the traditional and most widely used database model.'),
  ('2027-01-31', 'Debugging', ARRAY['It is the detective work of finding out why software misbehaves.', 'It often consumes more time than writing the code did.', 'Tools let you pause execution and inspect a program’s state mid-run.', 'Reproducing the problem reliably is often the hardest part.', 'Its name traces to a moth found in an early computer.', 'It is the process of locating and fixing defects in software.']::text[], 'The process of finding, diagnosing, and fixing defects in software, using techniques like breakpoints, stepping, logging, and inspecting program state. Often the most time-consuming part of development, its name famously derives from a moth found jamming an early computer.'),
  ('2027-02-01', 'Prim’s Algorithm', ARRAY['Rather than picking edges from anywhere, it grows a single connected blob outward.', 'It starts from one node and keeps attaching the nearest node not yet included.', 'A priority queue tracks the cheapest edge leaving the current blob.', 'Like its cousin, it produces a minimum-cost tree connecting every node.', 'It tends to outperform the edge-sorting approach on dense graphs.', 'It is the greedy method that builds a minimum spanning tree by expanding one growing set.']::text[], 'A greedy algorithm that builds a minimum spanning tree by starting from one vertex and repeatedly adding the cheapest edge that connects the growing tree to a new vertex, usually with a priority queue. It runs in about O(E log V) and is efficient on dense graphs.'),
  ('2027-02-02', 'Reference Counting', ARRAY['It is one simple way to know when a shared object is safe to destroy.', 'Each object keeps a tally of how many things currently point to it.', 'When that tally drops to zero, the object is freed at once.', 'Its Achilles heel is a cycle of objects pointing at each other.', 'Such cycles keep counts above zero forever, causing leaks.', 'It is the memory technique of freeing an object when its pointer count reaches zero.']::text[], 'A memory-management technique in which each object tracks how many references point to it and is freed the instant that count reaches zero. Simple and prompt, it cannot reclaim reference cycles on its own, so it is often paired with a cycle detector.'),
  ('2027-02-03', 'Cardinality', ARRAY['In one sense it simply counts how many elements a set contains.', 'In databases it also describes how one table’s rows relate to another’s.', 'Relationships get labeled one-to-one, one-to-many, or many-to-many by it.', 'Query optimizers use counts of distinct values of it to plan execution.', 'A column where nearly every value is unique is called high in it.', 'It is a measure of the number of elements in a set or the uniqueness of column values.']::text[], 'A measure of the number of elements in a set; in databases it describes both the uniqueness of values in a column and the nature of relationships between tables (one-to-one, one-to-many, many-to-many). Query optimizers rely on cardinality estimates to choose efficient execution plans.'),
  ('2027-02-04', 'Segment Tree', ARRAY['It is built to answer questions about stretches of a list far faster than scanning each element.', 'Each of its nodes summarizes a contiguous run of the underlying array.', 'It can report a sum, minimum, or maximum over any range in logarithmic time.', 'Crucially it also lets you change a value and keep every range answer correct, both quickly.', 'It splits each range in half again and again until single elements sit at the leaves.', 'It is the tree that stores range summaries so range queries and updates both run in logarithmic time.']::text[], 'A binary tree in which each node stores an aggregate (such as sum, min, or max) over a contiguous segment of an array. It answers range queries and applies point or range updates in O(log n), making it valuable for repeated range computations on changing data.'),
  ('2027-02-05', 'Duck Typing', ARRAY['It judges an object by what it can do, not by what it claims to be.', 'If something behaves as expected, it is accepted, whatever its declared type.', 'Its name comes from a saying about a bird that walks and quacks.', 'It is common in dynamically typed languages that skip formal interfaces.', 'Having the right method matters; the type’s name does not.', 'It is the style where an object’s suitability is judged by its methods, not its type.']::text[], 'A style, common in dynamic languages, where an object’s suitability for an operation is determined by whether it has the required methods and properties rather than its declared type—"if it walks and quacks like a duck, treat it as a duck." It favors flexibility over explicit interface conformance.'),
  ('2027-02-06', 'Composition', ARRAY['It builds complex behavior by assembling simpler parts rather than extending a base type.', 'An object gains capabilities by holding other objects and delegating to them.', 'It expresses a "has a" relationship instead of an "is a" one.', 'A famous design principle urges preferring it over inheritance.', 'It avoids the rigidity of deep class hierarchies.', 'It is building objects out of other objects to reuse behavior through delegation.']::text[], 'A design technique in which an object is built from other objects and reuses their behavior by delegating to them, modeling a "has-a" relationship. Favored over inheritance for flexibility, it avoids brittle hierarchies and lets behavior be assembled and swapped at runtime.'),
  ('2027-02-07', 'Base64', ARRAY['It represents binary data using only ordinary printable characters.', 'It is not encryption; it hides nothing and adds no security.', 'It exists so binary can travel safely through text-only channels.', 'Embedding an image directly inside a web page or email uses it.', 'It grows the data by about a third as the price of that safety.', 'It is an encoding that represents binary data as printable ASCII text.']::text[], 'A binary-to-text encoding that represents arbitrary binary data using 64 printable ASCII characters, so it can pass safely through text-only channels like email or JSON. It is not encryption and adds no security; it inflates size by roughly one third and is used for data URIs and attachments.'),
  ('2027-02-08', 'Static Typing', ARRAY['It insists on knowing the type of everything before the program ever runs.', 'Many mistakes are caught by the compiler rather than by the user.', 'It often lets tools offer better autocompletion and refactoring.', 'It can require more upfront annotation, though inference can ease that.', 'Java, C++, and Rust all work this way.', 'It is type checking performed at compile time, before execution.']::text[], 'A discipline in which the type of every variable and expression is known and checked at compile time, before the program runs. It catches type errors early and aids tooling and optimization, sometimes at the cost of verbosity, and is used by languages like Java, C++, and Rust.'),
  ('2027-02-09', 'Checksum', ARRAY['It is a small value used to spot whether data got corrupted.', 'It is computed from the data and sent or stored alongside it.', 'Recomputing it and comparing reveals accidental changes.', 'It catches transmission errors but is not meant to stop deliberate tampering.', 'A mismatch means the data is no longer what it was.', 'It is a small value derived from data to detect accidental errors.']::text[], 'A small value computed from a block of data and stored or sent with it, so recomputing and comparing can detect accidental corruption. Checksums such as CRCs guard against transmission and storage errors, but unlike cryptographic hashes they do not defend against deliberate tampering.'),
  ('2027-02-10', 'First-Class Function', ARRAY['In such a language, a function is treated as ordinary data.', 'You can store one in a variable just like a number or a string.', 'You can pass one into another function or return one as a result.', 'This property is what makes closures and higher-order functions possible.', 'JavaScript and Python treat their functions this way.', 'It describes a language where functions can be passed, returned, and assigned like values.']::text[], 'A property of a language in which functions are treated as first-class values—assignable to variables, passable as arguments, returnable from other functions, and storable in data structures. This enables higher-order functions, closures, and functional programming styles.'),
  ('2027-02-11', 'Insertion Sort', ARRAY['It shines on data that is already almost in order, finishing such input in nearly linear time.', 'It builds the result one item at a time, the way many people sort a hand of playing cards.', 'Each new item is slid backward past larger ones until it lands in its correct spot.', 'Standard libraries often switch to it for the small subarrays inside a bigger sort.', 'It is stable and works in place, but on reversed input it degrades to quadratic.', 'It grows a sorted region by taking the next element and inserting it into its proper place.']::text[], 'A comparison sort that builds a sorted sequence one element at a time, inserting each new element into its correct position among those already sorted. It is stable and in-place, running in O(n) on nearly-sorted data and O(n²) in the worst case.'),
  ('2027-02-12', 'Floyd’s Cycle Detection', ARRAY['It can discover a loop while using essentially no extra memory.', 'It sends two explorers through the same sequence at different speeds.', 'If a loop exists, the faster one eventually laps and meets the slower.', 'If there is no loop, the faster one simply reaches the end.', 'It is nicknamed after a tortoise and a hare for its two paces.', 'It detects a cycle in a linked sequence using two pointers moving at different speeds.']::text[], 'A cycle-detection technique, nicknamed the tortoise and hare, that moves two pointers through a sequence at different speeds; if a cycle exists they eventually meet, otherwise the fast one reaches the end. It uses O(1) extra space and can also locate the cycle’s start.'),
  ('2027-02-13', 'Recurrence Relation', ARRAY['It defines something in terms of smaller instances of itself.', 'Recursive algorithms are naturally described by one.', 'Solving it reveals the algorithm’s overall growth rate.', 'The Fibonacci sequence is a simple numeric example.', 'A famous theorem provides a shortcut for solving many of the divide-and-conquer ones.', 'It is an equation expressing each term of a sequence using earlier terms.']::text[], 'An equation that defines each term of a sequence as a function of preceding terms, together with base cases. Recurrence relations describe the running time of recursive algorithms; solving them (by substitution, recursion trees, or the Master Theorem) yields a closed-form growth rate.'),
  ('2027-02-14', 'Interrupt', ARRAY['It is how hardware grabs the processor’s attention without being asked.', 'It abruptly pauses whatever the processor was doing to handle something urgent.', 'A keystroke, an arriving network packet, or a timer can raise one.', 'A special routine handles it, then execution resumes where it left off.', 'It spares the processor from constantly polling devices to check for events.', 'It is a signal that diverts the CPU to handle an event, then returns to its prior task.']::text[], 'A signal, from hardware or software, that temporarily halts the CPU’s current work so it can run a handler for an urgent event—such as I/O completion, a timer, or an error—after which execution resumes. Interrupts let the CPU respond to events without wasteful polling.'),
  ('2027-02-15', 'WebSocket', ARRAY['Unlike the usual request-and-reply web model, it keeps a line open both ways.', 'Once established, either side can send data at any time.', 'It avoids the overhead of opening a new connection per message.', 'Chat apps and live dashboards rely on it for instant updates.', 'It begins life as an ordinary web request that then upgrades.', 'It is the protocol providing a persistent, two-way connection between browser and server.']::text[], 'A protocol providing a persistent, full-duplex channel over a single TCP connection between client and server, established by upgrading an HTTP request. Unlike request-response HTTP, either side can send messages anytime, enabling real-time features like chat, notifications, and live feeds.'),
  ('2027-02-16', 'Git', ARRAY['It is the tool most developers use to track their code’s history.', 'Every clone contains the entire project history, not just the latest copy.', 'Its lightweight branches make parallel work cheap and routine.', 'It was created to manage the development of the Linux kernel.', 'Services like GitHub host projects that use it.', 'It is the distributed version-control system that tracks source-code changes.']::text[], 'A distributed version-control system that tracks changes to source code, giving every clone the full project history and enabling fast, cheap branching and merging. Created by Linus Torvalds for Linux kernel development, it is the dominant tool for managing code and is hosted on platforms like GitHub.'),
  ('2027-02-17', 'NP-Completeness', ARRAY['A fast solution to any single one of them would instantly crack all of them.', 'No one has found an efficient algorithm for any of them, nor proven none exists.', 'Checking a proposed answer is easy, but finding one seems brutally hard.', 'Any problem in a certain broad class can be transformed into one of them.', 'The traveling salesman and boolean satisfiability problems are famous members.', 'It describes the hardest problems whose candidate solutions can at least be verified quickly.']::text[], 'A class of decision problems that are both in NP (solutions verifiable in polynomial time) and NP-hard (every NP problem reduces to them). A polynomial-time algorithm for any one would solve them all; examples include SAT, graph coloring, and the traveling salesman decision problem.'),
  ('2027-02-18', 'Space Complexity', ARRAY['It concerns a resource other than time that an algorithm can just as easily exhaust.', 'It counts how much working memory an algorithm needs as its input grows.', 'Some fast algorithms buy their speed by demanding a lot of it.', 'An in-place algorithm keeps it down to a small constant.', 'Like its time counterpart, it is expressed in growth-rate notation.', 'It measures how an algorithm’s memory usage grows with the size of its input.']::text[], 'A measure of how much memory an algorithm requires as a function of input size, including auxiliary working storage, expressed with asymptotic notation. It captures trade-offs where algorithms use extra memory for speed, and in-place algorithms minimize it.'),
  ('2027-02-19', 'Unit Test', ARRAY['It checks one small piece of code in isolation from the rest.', 'It runs fast and pinpoints exactly what broke when it fails.', 'It typically stubs out anything external the code depends on.', 'A suite of them guards against regressions as code changes.', 'It is the narrowest and most numerous layer of automated testing.', 'It is an automated test verifying a single small unit of code in isolation.']::text[], 'An automated test that verifies a single small unit of code—such as a function or method—in isolation, often replacing external dependencies with stubs or mocks. Fast and focused, unit tests pinpoint failures precisely and guard against regressions as code evolves.'),
  ('2027-02-20', 'Functional Programming', ARRAY['It treats computation as the evaluation of functions and avoids changing state.', 'It prefers producing new values over modifying existing ones.', 'Functions are its primary building blocks, passed around like any value.', 'Keeping functions free of side effects makes programs easier to reason about.', 'Haskell, Lisp, and increasingly mainstream languages embrace it.', 'It is the paradigm built around pure functions and immutable data.']::text[], 'A paradigm that models computation as the evaluation of functions, emphasizing pure functions, immutability, first-class and higher-order functions, and avoidance of shared mutable state. It aids reasoning, testing, and parallelism, influencing languages from Haskell and Lisp to modern JavaScript.'),
  ('2027-02-21', 'Just-In-Time Compilation', ARRAY['It blurs the line between interpreting a program and compiling it.', 'It translates code to native form while the program is already running.', 'It concentrates its effort on the parts that run most often, the hot paths.', 'It can even use runtime information to optimize in ways an ahead-of-time compiler cannot.', 'Modern JavaScript engines and the Java virtual machine rely on it for speed.', 'It is compilation that happens on the fly, during execution rather than before.']::text[], 'A technique that compiles code to native machine code during execution rather than beforehand, typically focusing on frequently executed "hot" paths and exploiting runtime information to optimize. Used by the JVM and modern JavaScript engines, it blends interpretation’s flexibility with compilation’s speed.'),
  ('2027-02-22', 'Priority Queue', ARRAY['Arrival order means nothing to it; only importance decides who goes next.', 'Instead of first come first served, it always hands you the most urgent item.', 'It is most often built on top of a heap to stay efficient.', 'Shortest-path algorithms depend on one to repeatedly pick the closest unvisited node.', 'Every item carries a key ranking it, and the extreme key always comes out first.', 'It is a queue where each element has a priority and the highest-priority one is removed first.']::text[], 'An abstract data type where each element has a priority and removal always returns the highest- (or lowest-) priority element rather than the oldest. Usually backed by a binary heap, it gives O(log n) insertion and extraction and drives algorithms like Dijkstra and Huffman coding.'),
  ('2027-02-23', 'Hash Function', ARRAY['It crushes an input of any size down to a fixed-size fingerprint.', 'The same input always yields the same output, but the reverse is meant to be hard.', 'A good one scatters even similar inputs to wildly different results.', 'It is the engine that decides where a key lands in a hash table.', 'Two inputs mapping to the same output is called a collision.', 'It is a function mapping arbitrary data to a fixed-size value.']::text[], 'A function that maps input of arbitrary size to a fixed-size value (a hash or digest), deterministically and ideally spreading inputs uniformly. Hash functions power hash tables, checksums, and—in cryptographic form—integrity checks, with distinct inputs occasionally colliding to the same output.'),
  ('2027-02-24', 'Critical Section', ARRAY['It is the stretch of code that only one thread may run at a time.', 'Letting two threads into it simultaneously risks corrupting shared data.', 'A lock is placed around it to enforce the one-at-a-time rule.', 'Keeping it short reduces how long other threads must wait.', 'It is precisely the region that mutual-exclusion primitives are meant to guard.', 'It is a section of code accessing shared resources that must not run concurrently.']::text[], 'A portion of code that accesses shared resources and must not be executed by more than one thread at a time to avoid race conditions. It is protected by mutual-exclusion mechanisms like mutexes or semaphores, and keeping it short improves concurrency.'),
  ('2027-02-25', 'Von Neumann Architecture', ARRAY['Its defining choice is to keep instructions and data in the very same memory.', 'This unity is elegant but creates a traffic jam between processor and memory.', 'That single shared pathway is often blamed for a fundamental performance bottleneck.', 'Nearly every general-purpose computer today follows its basic plan.', 'It pairs a processing unit, a control unit, memory, and input/output.', 'It is the computer design that stores program and data together in one memory.']::text[], 'A foundational computer design in which program instructions and data share the same memory and bus connecting them to the CPU. Comprising a processing unit, control unit, memory, and I/O, it describes almost all general-purpose computers, though the shared bus causes the "von Neumann bottleneck".'),
  ('2027-02-26', 'Counting Sort', ARRAY['It sidesteps comparisons entirely, which lets it beat the usual sorting speed limit.', 'It only works when the values are integers drawn from a limited range.', 'It tallies how many times each possible value appears.', 'From those tallies it works out exactly where each value belongs.', 'It runs in linear time when the range of values is not much larger than the count of items.', 'It sorts by counting occurrences of each key and using the counts to place elements directly.']::text[], 'A non-comparison sort for integers in a bounded range that counts occurrences of each key, converts the counts to positions, and places elements directly. It runs in O(n + k) for range k and is stable, but is impractical when the value range is very large.'),
  ('2027-02-27', 'Time Complexity', ARRAY['It answers how an algorithm’s effort scales, not how many seconds it takes on your laptop.', 'It counts basic operations as a function of the input size.', 'It is usually reported for the best, average, and worst cases.', 'It is most often expressed in the capital-O growth-rate notation.', 'Two algorithms in the same growth class scale alike even if one is faster in practice.', 'It measures how the number of operations an algorithm performs grows with input size.']::text[], 'A measure of how the number of operations an algorithm performs grows as a function of input size, typically expressed with asymptotic notation and reported for best, average, and worst cases. It predicts scalability independently of specific hardware or constant factors.'),
  ('2027-02-28', 'Doubly Linked List', ARRAY['Compared with its simpler cousin, it spends extra memory to buy the ability to walk backward.', 'Each node knows not only what comes next but also what came before.', 'That backward link lets you remove a node in constant time without scanning from the front.', 'It underpins many implementations of double-ended queues and least-recently-used caches.', 'You can traverse it forward or in reverse with equal ease.', 'It is a chain of nodes where each one points both to the next node and the previous node.']::text[], 'A linked list in which each node stores references to both its successor and predecessor, enabling traversal in both directions and O(1) removal of a known node. The extra pointer per node costs memory but simplifies deletions and structures like deques and LRU caches.'),
  ('2027-03-01', 'Memory Leak', ARRAY['It is a slow drain rather than a sudden crash.', 'It happens when a program keeps memory it will never use again.', 'Over hours or days it can starve a long-running program of resources.', 'It is most common in languages where you free memory by hand.', 'Even with automatic cleanup, forgotten references can still cause it.', 'It is the gradual loss of usable memory a program fails to release.']::text[], 'A defect where a program allocates memory but never releases it once it is no longer needed, so usable memory steadily shrinks. Common in manually managed languages—and possible even under garbage collection via lingering references—leaks can eventually exhaust memory in long-running programs.'),
  ('2027-03-02', 'Memoization', ARRAY['It spends memory to buy back time.', 'Call it twice with identical arguments and the second call does no real work.', 'It stashes results in a lookup keyed by the inputs that produced them.', 'It is the top-down face of a broader optimization technique.', 'Wrapping a naive recursive Fibonacci in it makes it dramatically faster.', 'It is caching a function’s return values so repeated calls with the same inputs skip the work.']::text[], 'An optimization that caches the results of expensive function calls keyed by their arguments, returning the stored value when the same inputs recur. It is the top-down form of dynamic programming and eliminates redundant recomputation in overlapping-subproblem algorithms.'),
  ('2027-03-03', 'Memory Address', ARRAY['It is essentially a house number for a specific spot in memory.', 'A certain kind of variable holds one as its value.', 'Its width caps how much memory a system can directly reach.', 'On a 64-bit machine it is 64 bits wide, though not every bit is used.', 'It is usually printed in hexadecimal for readability.', 'It is a numerical identifier locating a specific byte in memory.']::text[], 'A numerical identifier specifying the location of a byte or word in memory. Pointers store addresses, and the address width (e.g., 32 or 64 bits) limits how much memory can be directly referenced. Addresses are commonly displayed in hexadecimal.'),
  ('2027-03-04', 'Bitwise Operator', ARRAY['It manipulates a value at the level of its individual ones and zeros.', 'It applies simple logic like and, or, and exclusive-or to each position independently.', 'It is far faster than arithmetic and used where every cycle counts.', 'Combining it with a mask lets you read or set specific flags packed into one number.', 'Its exclusive-or has the neat property of undoing itself when applied twice.', 'It is an operator that acts on the individual bits of its operands.']::text[], 'An operator that manipulates the individual bits of integer operands, including AND, OR, XOR, NOT, and shifts. Bitwise operations are fast, low-level tools for packing flags, masking, toggling, and efficient arithmetic tricks.'),
  ('2027-03-05', 'Dependency Injection', ARRAY['Instead of building what it needs, an object is handed those things from outside.', 'This inverts who is responsible for wiring components together.', 'It makes swapping a real dependency for a fake one in tests easy.', 'Frameworks often automate the wiring for you.', 'It reduces how tightly components are bound to specific implementations.', 'It is supplying an object’s dependencies from outside rather than having it create them.']::text[], 'A technique in which an object receives the other objects it depends on from an external source rather than creating them itself, inverting control of construction. It reduces coupling, eases testing by allowing substitutes, and is often automated by frameworks or containers.'),
  ('2027-03-06', 'Binary Number', ARRAY['It gets by with only two symbols, which is exactly why hardware loves it.', 'Each position represents a power of two rather than a power of ten.', 'Moving a digit one place to the left doubles its value.', 'Every color, character, and instruction inside a computer is ultimately written this way.', 'The value ten is written in it as 1010.', 'It is a number expressed in base two, using only the digits 0 and 1.']::text[], 'A representation of numbers in base 2 using only the digits 0 and 1, where each position denotes a power of two. It is the native number system of digital hardware, since two states map directly onto electrical on/off signals.'),
  ('2027-03-07', 'Symmetric Encryption', ARRAY['It uses the very same secret to lock and to unlock data.', 'It is fast, making it suitable for large amounts of data.', 'Its central challenge is getting that shared secret to both parties safely.', 'It contrasts with schemes that use a matched pair of different keys.', 'A widely used standard for it is abbreviated AES.', 'It is encryption where one shared key both encrypts and decrypts.']::text[], 'Encryption in which the same secret key both encrypts and decrypts data. It is fast and suited to bulk data but requires securely sharing the key beforehand—the key-distribution problem that public-key cryptography helps solve. AES is a common example.'),
  ('2027-03-08', 'System Call', ARRAY['It is how an ordinary program asks the privileged core to do something for it.', 'Reading a file or opening a network connection ultimately goes through one.', 'It deliberately crosses the boundary between unprivileged and privileged code.', 'That crossing has a real cost, so programs try not to make too many.', 'It is the controlled doorway into the operating system’s services.', 'It is a request from a program to the kernel to perform a privileged operation.']::text[], 'A controlled request from a user program to the kernel to perform a privileged operation such as file, memory, or network access. It transitions the CPU from user mode to kernel mode and forms the interface between applications and the kernel’s services.'),
  ('2027-03-09', 'LRU Cache', ARRAY['When it runs out of room, it throws out whatever has gone untouched the longest.', 'It bets that recently used items are the ones you will want again soon.', 'It usually pairs a hash map with a doubly linked list to stay fast.', 'Every access moves an item to the most-recently-used end.', 'Both looking something up and updating its recency happen in constant time.', 'It is the fixed-capacity cache that evicts the least recently used entry when full.']::text[], 'A fixed-capacity cache that evicts the least recently used item when it needs space, based on temporal locality. It is typically built from a hash map for O(1) lookup plus a doubly linked list to track recency, giving constant-time access and eviction.'),
  ('2027-03-10', 'Array', ARRAY['Everything in it sits in one continuous block, which is exactly why one operation is instant and another is slow.', 'Because every slot is the same size and laid out end to end, the machine can jump straight to any position with simple arithmetic.', 'Reaching the tenth element takes exactly as long as reaching the first.', 'Its main weakness is growing: making it bigger usually means allocating a new block and copying everything over.', 'You reach any element directly by its numeric position, usually counting from zero.', 'It is the most basic collection: an ordered, fixed-size sequence of elements stored side by side in memory.']::text[], 'A contiguous block of memory holding a fixed number of equally sized elements, each reachable in constant time by its integer index. Arrays give O(1) random access but costly insertion, deletion, and resizing, since elements must be shifted or the whole block copied.'),
  ('2027-03-11', 'Knuth-Morris-Pratt Algorithm', ARRAY['It never re-examines a character of the text it has already passed.', 'It speeds up pattern matching by learning from the pattern’s own repeated structure.', 'Before searching, it precomputes how far to jump when a partial match fails.', 'That precomputed table encodes the pattern’s longest repeated prefixes.', 'It finds a pattern inside a text in time proportional to their combined lengths.', 'It is the linear-time string search that avoids rechecking already-matched characters.']::text[], 'A string-matching algorithm that locates a pattern within a text in O(n + m) time by precomputing a table of the pattern’s longest proper prefix-suffixes, letting it skip ahead after a mismatch without re-scanning text characters.'),
  ('2027-03-12', 'API', ARRAY['It is the agreed-upon way one piece of software talks to another.', 'It hides a system’s internals behind a defined set of operations.', 'It lets developers use a service without knowing how it works inside.', 'A web one is often accessed over HTTP and returns structured data.', 'It is essentially a contract between a provider and its consumers.', 'It is the defined interface through which programs interact with a service or library.']::text[], 'An application programming interface, a defined set of operations, inputs, and outputs through which one program uses another without knowing its internals. APIs range from library function sets to web endpoints (often HTTP-based returning JSON), acting as contracts between provider and consumer.'),
  ('2027-03-13', 'Machine Code', ARRAY['It is the only form of a program a processor can actually run.', 'To a human it looks like nothing but numbers.', 'Every higher-level language is ultimately turned into it.', 'It is specific to a particular processor family and unintelligible to others.', 'Each of its instructions directly commands the hardware.', 'It is the raw binary instructions a CPU executes directly.']::text[], 'The binary-encoded instructions a CPU executes directly, specific to a processor architecture. It is the lowest-level representation of a program; all higher-level languages are ultimately compiled or assembled into it, and it is unintelligible to humans without disassembly.'),
  ('2027-03-14', 'Linked List', ARRAY['Reaching its tenth element costs about ten times as much as reaching its first.', 'Its pieces can live scattered anywhere in memory rather than packed into one block.', 'Each piece carries its value plus directions to where the next one lives.', 'Inserting or removing in the middle is cheap once you are there, but getting there is slow.', 'Moving through it means hopping from one node to the next until you arrive.', 'It is a chain of nodes in which every node points to the one after it.']::text[], 'A linear structure whose elements (nodes) are stored non-contiguously, each holding a value and a reference to the next node. It allows O(1) insertion and deletion at a known position but O(n) access, and comes in singly, doubly, and circular forms.'),
  ('2027-03-15', 'Interpreter', ARRAY['It runs a program without ever producing a standalone translated file.', 'It reads and executes source a piece at a time, as it goes.', 'This makes starting up quick but running slower than a pre-translated program.', 'It is what lets you type a line of code and see the result immediately.', 'Python and JavaScript are classically run this way.', 'It is the program that executes source code directly, without a separate compile step.']::text[], 'A program that reads and executes source code directly, statement by statement, without first producing a separate machine-code file. Interpreters enable interactive use and portability at the cost of slower execution, and languages like Python are traditionally run this way.'),
  ('2027-03-16', 'Router', ARRAY['It is the traffic director sitting between different networks.', 'It decides where each unit of data should go next on its journey.', 'It keeps a table mapping destinations to the best next hop.', 'Home versions of it also connect all your devices to the internet.', 'It operates by reading the destination address on each packet.', 'It is the device that forwards data packets between networks toward their destination.']::text[], 'A networking device that forwards data packets between networks, choosing the next hop toward each packet’s destination using a routing table. Routers connect local networks to the wider internet and, in homes, often combine routing with switching, wireless access, and firewalling.'),
  ('2027-03-17', 'Promise', ARRAY['It is a stand-in for a value that is not available just yet.', 'It represents an operation that will finish sometime in the future.', 'It ends up either fulfilled with a value or rejected with an error.', 'You attach handlers to react when it eventually settles.', 'It was introduced largely to flatten deeply nested callbacks.', 'It is an object representing the eventual result of an asynchronous operation.']::text[], 'An object representing the eventual result of an asynchronous operation, initially pending and later settling as fulfilled (with a value) or rejected (with an error). Promises let asynchronous code be composed with handlers and chaining, avoiding deeply nested callbacks.'),
  ('2027-03-18', 'CORS', ARRAY['It governs when a web page may talk to a server on a different origin.', 'Browsers block such cross-origin requests by default for safety.', 'The target server must opt in with specific response headers.', 'For some requests the browser first sends a preflight check.', 'Misconfiguring it is a common source of frustrating web errors.', 'It is the browser mechanism controlling cross-origin web requests via server headers.']::text[], 'Cross-Origin Resource Sharing, a browser security mechanism controlling whether a web page may request resources from a different origin (domain, protocol, or port). Such requests are restricted by default; the target server must grant access via specific headers, sometimes after a preflight check.'),
  ('2027-03-19', 'Load Balancer', ARRAY['It spreads incoming work across many servers so none is overwhelmed.', 'It presents a single entry point hiding a whole fleet behind it.', 'It can route around a server that has failed, improving reliability.', 'Strategies include round-robin and sending each request to the least busy server.', 'It is essential for scaling a service to many users.', 'It is the component that distributes incoming requests across multiple servers.']::text[], 'A component that distributes incoming requests across multiple servers to improve capacity, responsiveness, and reliability. Using strategies like round-robin or least-connections plus health checks to avoid failed servers, it presents one endpoint while scaling a service horizontally.'),
  ('2027-03-20', 'CDN', ARRAY['It fights slowness by keeping copies of content physically closer to users.', 'It spreads a site’s files across many servers around the world.', 'A visitor is served from whichever location is nearest.', 'It offloads traffic from the origin and absorbs sudden spikes.', 'Large media and software downloads rely on it heavily.', 'It is a distributed network of servers that delivers content from locations near users.']::text[], 'A content delivery network, a geographically distributed set of servers that cache and serve web content from locations near users, cutting latency and offloading the origin. CDNs speed delivery of static assets and media and help absorb traffic spikes and attacks.'),
  ('2027-03-21', 'Dynamic Typing', ARRAY['It waits until a program is actually running to worry about types.', 'A variable can hold a number now and a string a moment later.', 'It makes code quick to write but lets some errors slip through to runtime.', 'Type mistakes reveal themselves only when the offending line executes.', 'Python and JavaScript are prominent examples.', 'It is type checking performed at runtime rather than before execution.']::text[], 'A discipline in which types are associated with values at runtime and checked as the program executes, so variables can hold values of any type over time. It offers flexibility and concise code but defers type errors to runtime, as in Python, Ruby, and JavaScript.'),
  ('2027-03-22', 'Sliding Window', ARRAY['It avoids recomputing from scratch by adjusting a running answer as it moves.', 'It keeps a contiguous span of a sequence under consideration at any moment.', 'As it advances, it adds a new element on one side and drops one on the other.', 'Finding the longest stretch of a string with no repeats is a classic use.', 'It turns many quadratic subarray problems into a single linear pass.', 'It is the technique of maintaining a moving range over a sequence to answer subarray questions.']::text[], 'A technique that maintains a contiguous range (window) over an array or string, expanding and contracting it while updating a running result instead of recomputing. It reduces many subarray and substring problems from O(n²) to O(n).'),
  ('2027-03-23', 'OSI Model', ARRAY['It is a teaching framework that splits networking into tidy layers.', 'Each layer relies on the one beneath and serves the one above.', 'It has seven levels, from physical wires up to applications.', 'Real-world networking does not map onto it perfectly.', 'People often reference its layer numbers as shorthand.', 'It is the seven-layer conceptual model describing how network communication is organized.']::text[], 'The Open Systems Interconnection model, a conceptual framework dividing network communication into seven layers—physical, data link, network, transport, session, presentation, and application—each building on the one below. Though protocols like TCP/IP don’t map exactly, it is a standard reference.'),
  ('2027-03-24', 'Polymorphism', ARRAY['It lets a single instruction do different things depending on what it acts on.', 'One name can invoke behavior tailored to each specific type.', 'Calling "draw" on a shape works whether it is a circle or a square.', 'It frees code from needing to know an object’s exact type in advance.', 'It comes in forms including overriding and generic parameterization.', 'It is the ability for one interface to be backed by many different implementations.']::text[], 'The ability for a single interface, name, or operation to work with values of different types, each supplying its own behavior—so calling draw() runs the right code for a circle or a square. Forms include subtype polymorphism (overriding), parametric polymorphism (generics), and overloading.'),
  ('2027-03-25', 'Trie', ARRAY['What matters here is where a node sits, not what value it stores.', 'Two entries that begin the same way share the same path near the root.', 'How long a lookup takes depends on the length of the key, not how many keys are stored.', 'Autocomplete and prefix search are its signature applications.', 'Its odd name comes from the middle of the word retrieval.', 'It is a tree keyed by character, where each path from the root spells out a string.']::text[], 'A tree for storing strings in which each node represents a character and each root-to-node path spells a prefix. Tries enable fast prefix queries, autocomplete, and dictionary lookups, with search time proportional to key length rather than the number of stored keys.'),
  ('2027-03-26', 'Stack', ARRAY['The thing you put in most recently is the only thing you can reach right now.', 'The mechanism that lets functions call other functions is built on one of these.', 'Undo features and backtracking rely naturally on its ordering.', 'Its two core moves, push and pop, both happen at the same end.', 'Its discipline is last in, first out.', 'It works like a pile of trays where you always add to and take from the top.']::text[], 'An abstract data type with last-in-first-out (LIFO) ordering, supporting push (add to the top) and pop (remove from the top). It underlies function-call management, expression evaluation, and backtracking.'),
  ('2027-03-27', 'Arithmetic Logic Unit', ARRAY['It is the part of the processor that actually does the math.', 'It also performs the comparisons and logical operations behind every decision.', 'It takes operands from fast internal stores and produces a result plus status flags.', 'Those flags record things like whether a result was zero or overflowed.', 'It is one of the two main subunits inside a central processor.', 'It is the circuit within the CPU that performs arithmetic and logical operations.']::text[], 'A digital circuit within the CPU that performs arithmetic (add, subtract) and logical (AND, OR, comparison) operations on operands from registers, setting status flags such as zero, carry, and overflow. It is a core component of the processor.'),
  ('2027-03-28', 'Version Control', ARRAY['It remembers every change ever made to a project, and who made it.', 'It lets you return to any earlier state at will.', 'It enables many people to work on the same code without overwriting each other.', 'Parallel lines of work can diverge and later be merged back together.', 'Git is by far its most popular incarnation.', 'It is a system that records and manages changes to files over time.']::text[], 'A system that records changes to files over time, letting developers review history, revert to earlier states, and collaborate without overwriting each other’s work via branching and merging. Distributed systems like Git are the modern standard for managing source code.'),
  ('2027-03-29', 'NoSQL', ARRAY['It is a broad family united mainly by what they are not.', 'They abandon rigid tables in favor of more flexible data models.', 'Many trade strict consistency for the ability to scale across many machines.', 'Document, key-value, column, and graph stores all fall under it.', 'It rose to prominence with the demands of massive web applications.', 'It is the umbrella term for databases that depart from the relational table model.']::text[], 'An umbrella term for databases that depart from the relational table model, using flexible schemas and models such as document, key-value, wide-column, or graph. Often built to scale horizontally and to favor availability over strict consistency, they suit large-scale and rapidly evolving data.'),
  ('2027-03-30', 'AVL Tree', ARRAY['It is willing to do extra shuffling after every edit to guarantee it never gets lopsided.', 'After each insert or delete it checks whether any part has grown too tall relative to its sibling.', 'When it detects imbalance it performs local rotations to restore even height.', 'Its strict balancing keeps every operation logarithmic even in the worst case.', 'It was the first self-balancing search tree ever invented, named after two mathematicians.', 'It is a height-balanced search tree that rotates to keep sibling subtrees within one level of each other.']::text[], 'A self-balancing binary search tree that keeps, for every node, a height difference of at most one between its subtrees, restoring this with rotations after insertions and deletions. It guarantees O(log n) operations, at the cost of more rotations than more loosely balanced trees.'),
  ('2027-03-31', 'Immutability', ARRAY['Once created, such a value can never be changed—only replaced.', 'Wanting a modified version means making a whole new copy.', 'It eliminates a class of bugs where shared data changes underfoot.', 'It makes sharing data across threads inherently safe.', 'Strings in many languages already have this property.', 'It is the property of data that cannot be altered after it is created.']::text[], 'The property of an object or value that cannot be changed after creation; any "modification" produces a new value instead. Immutability simplifies reasoning, prevents a class of aliasing bugs, and makes data safe to share across threads, at the cost of extra copying.'),
  ('2027-04-01', 'Huffman Coding', ARRAY['It assigns shorter codes to the things that appear most often.', 'Rare symbols get longer codes in exchange.', 'No code is ever a prefix of another, so decoding is unambiguous.', 'It builds its code by repeatedly merging the two least frequent items.', 'It provably produces the optimal such variable-length code.', 'It is the greedy algorithm for optimal prefix-free compression codes.']::text[], 'A greedy algorithm that produces an optimal prefix-free variable-length code, assigning shorter bit sequences to more frequent symbols by repeatedly merging the two least frequent nodes into a binary tree. It is a foundational lossless-compression technique used within formats like ZIP and JPEG.'),
  ('2027-04-02', 'Matrix', ARRAY['It arranges data in a rectangle, so two numbers rather than one are needed to locate any element.', 'Rows and columns give every element an address like a grid reference.', 'Graphics transformations and systems of equations are expressed and solved with it.', 'One common way to store a graph uses one of these, marking which nodes connect.', 'It is a two-dimensional arrangement of values laid out in rows and columns.', 'It is the rectangular grid of numbers that linear algebra multiplies and transforms.']::text[], 'A two-dimensional array of values arranged in rows and columns and addressed by a pair of indices. Matrices represent linear transformations, systems of equations, image data, and graph adjacency, and are central to linear algebra and computer graphics.'),
  ('2027-04-03', 'Class', ARRAY['It is a blueprint, not a thing you can use until you make one from it.', 'It specifies what data its products hold and what they can do.', 'From it you stamp out any number of individual instances.', 'It can build on another one, inheriting its features.', 'Its instances each carry their own copy of the data it describes.', 'It is the template from which objects are created.']::text[], 'A blueprint that defines the structure (fields) and behavior (methods) shared by a category of objects. Objects are instances of a class, each with its own data, and classes can inherit from others to form hierarchies.'),
  ('2027-04-04', 'Reference', ARRAY['It lets two names refer to the very same underlying object.', 'Change the object through one and the change is visible through the other.', 'It behaves like a pointer but usually cannot be left empty or aimed elsewhere.', 'Passing a large object by it avoids copying the whole thing.', 'Many high-level languages use it silently for all their objects.', 'It is an alias that lets you access an object without copying it.']::text[], 'A value that refers to an object without copying it, letting multiple names access the same data. Similar to a pointer but usually safer—often non-null and non-reassignable—references enable sharing and the pass-by-reference semantics common in high-level languages.'),
  ('2027-04-05', 'Exception', ARRAY['It is the language’s way of signaling that something went wrong.', 'When raised, it interrupts the normal flow of the program.', 'It travels up the call stack until something agrees to handle it.', 'Unhandled, it usually crashes the program with a diagnostic message.', 'It cleanly separates error handling from the main logic.', 'It is an object representing an error that disrupts normal control flow.']::text[], 'A mechanism for signaling and handling errors or unusual conditions: when raised (thrown), it interrupts normal control flow and propagates up the call stack until caught by a handler, or terminates the program if uncaught. Exceptions separate error handling from mainline logic.'),
  ('2027-04-06', 'Callback', ARRAY['It is a function you hand to other code to be run later.', 'It is invoked when some operation finishes or an event occurs.', 'It is a classic way to handle work that completes asynchronously.', 'Nesting many of them deeply leads to famously tangled code.', 'Newer abstractions were invented largely to tame it.', 'It is a function passed to other code to be called back at a later point.']::text[], 'A function passed as an argument to other code, to be invoked later—when an operation completes or an event fires. Callbacks are a fundamental way to handle asynchronous work and events, though deeply nested ones create hard-to-read "callback hell," which promises and async/await address.'),
  ('2027-04-07', 'Variable', ARRAY['It is a name you attach to a value so you can refer to it later.', 'Behind the name sits a location that can hold data.', 'In many languages the value it holds can change over time.', 'It usually has a type that constrains what kind of value it may store.', 'Where it can be used is governed by its scope.', 'It is a named storage location holding a value that a program can read and change.']::text[], 'A named storage location that holds a value a program can read and, in many languages, modify. Each variable has a name, a value, usually a type, and a scope governing where it is accessible; variables are the basic means of tracking state in code.'),
  ('2027-04-08', 'Sharding', ARRAY['It splits one giant database into pieces spread across many machines.', 'Each piece holds only a subset of the total rows.', 'A key decides which piece any given record lives in.', 'It lets a database scale beyond what a single server could handle.', 'Queries spanning multiple pieces become more complicated as a result.', 'It is horizontally partitioning data across multiple servers to scale.']::text[], 'A horizontal-partitioning technique that splits a large dataset across multiple servers (shards), each holding a subset of rows chosen by a shard key. Sharding lets a database scale beyond one machine’s capacity, at the cost of more complex cross-shard queries and rebalancing.'),
  ('2027-04-09', 'Unicode', ARRAY['It set out to give every character in every language a single number.', 'It also covers symbols and, famously, emoji.', 'It assigns each character an abstract number independent of how it is stored.', 'Several encodings exist to turn those numbers into actual bytes.', 'It superseded a patchwork of incompatible regional character sets.', 'It is the universal standard assigning a unique number to every character.']::text[], 'A universal character-encoding standard that assigns a unique number (code point) to virtually every character across the world’s writing systems, plus symbols and emoji. It defines the abstract character-to-number mapping, while encodings like UTF-8 and UTF-16 specify how those numbers become bytes.'),
  ('2027-04-10', 'Circular Buffer', ARRAY['It reuses the same fixed space forever, letting new data quietly overwrite the oldest.', 'When writing reaches the end, it simply wraps back around to the beginning.', 'Its capacity never changes, which makes it a favorite in memory-tight systems.', 'Streaming audio, logs, and producer-consumer pipelines lean on it.', 'Two markers chase each other around the loop to track where reading and writing happen.', 'It is a fixed-size buffer treated as a ring, so the newest data overwrites the oldest.']::text[], 'A fixed-size buffer treated as a loop, using head and tail pointers so that once full, new writes overwrite the oldest data. Also called a ring buffer, it suits streaming, buffering, and producer-consumer scenarios with bounded memory.'),
  ('2027-04-11', 'Bit Shifting', ARRAY['It slides all the ones and zeros of a value sideways by a set number of places.', 'Nudging them one way is a lightning-fast stand-in for multiplying by two.', 'Nudging them the other way divides by two instead.', 'Digits that fall off the end are simply discarded.', 'It is a favorite tool for squeezing performance out of tight numeric code.', 'It is the operation that moves a number’s bits left or right by a given amount.']::text[], 'An operation that moves all bits of a value left or right by a specified number of positions. A left shift by k multiplies an unsigned integer by 2^k and a right shift divides by 2^k, making shifts fast substitutes for multiplication and division by powers of two.'),
  ('2027-04-12', 'Quadtree', ARRAY['It saves effort by refusing to subdivide regions that are empty or uniform.', 'Whenever a region holds too much detail, it splits that region into four smaller ones.', 'Two-dimensional space is what it is built to organize.', 'Image compression, collision detection, and maps use it to skip over empty areas quickly.', 'Each of its internal nodes has exactly four children, one per quadrant.', 'It is the tree that recursively divides a two-dimensional area into four quadrants.']::text[], 'A tree in which each internal node has four children, recursively subdividing a two-dimensional space into quadrants only where detail requires it. Quadtrees accelerate spatial queries, collision detection, image compression, and geographic indexing by pruning empty or uniform regions.'),
  ('2027-04-13', 'Deque', ARRAY['It refuses to pick a side: both ends are equally open for business.', 'You can add or remove at the front or the back with equal speed.', 'It generalizes two simpler structures, behaving like either one depending on how you use it.', 'Sliding-window algorithms often lean on it to add and drop items at both ends.', 'Its name is a contraction of the phrase "double-ended".', 'It is a queue that lets you insert and remove at both the front and the back.']::text[], 'A double-ended queue supporting insertion and removal at both ends in O(1). It generalizes stacks and queues and is commonly used for sliding-window problems and work-stealing schedulers.'),
  ('2027-04-14', 'Big-O Notation', ARRAY['It deliberately ignores the constant factors that decide real-world speed.', 'By its measure, a sluggish algorithm and a fast one can look identical.', 'It cares only about behavior as the input grows toward infinity.', 'Coefficients and lower-order terms drop away; only the dominant growth remains.', 'It sorts algorithms into families like constant, logarithmic, linear, and quadratic.', 'It is the notation, written with a capital O and parentheses, describing growth rate.']::text[], 'A notation describing the limiting growth of an algorithm’s time or space as input size increases, expressed as an asymptotic upper bound with constant factors and lower-order terms dropped (e.g., O(n), O(log n), O(n²)). It lets algorithms be compared independently of hardware.'),
  ('2027-04-15', 'Side Effect', ARRAY['It is anything a function does beyond simply computing and returning a value.', 'Printing to the screen or writing a file is a classic example.', 'Modifying a global variable or its own arguments counts too.', 'Functions that avoid it are far easier to reason about and test.', 'Managing it carefully is a central theme of functional programming.', 'It is an observable change to state outside a function’s local computation.']::text[], 'Any observable effect a function has beyond returning a value—such as modifying global state, mutating arguments, performing I/O, or throwing. Side effects make code harder to test and reason about, so functional programming seeks to minimize and isolate them.'),
  ('2027-04-16', 'Abstraction', ARRAY['It lets you use something without knowing how it works inside.', 'It exposes the essential controls while hiding messy detail.', 'Driving a car without understanding its engine is the classic analogy.', 'Layers of it are how large systems stay comprehensible.', 'It focuses on what an object does rather than how it does it.', 'It is the practice of exposing only essential features while hiding complexity.']::text[], 'The practice of exposing only the essential features of something while hiding its underlying complexity, letting users work at a higher conceptual level. In software it appears as interfaces, functions, and layers separating what a component does from how it does it.'),
  ('2027-04-17', 'Virtual Memory', ARRAY['It lets programs behave as if they have far more memory than physically exists.', 'It also gives each program the illusion of a private, contiguous address space.', 'Rarely used portions can be quietly parked on disk until needed.', 'Hardware translates the addresses a program sees into real physical ones.', 'Overusing it triggers thrashing, where the system spends all its time swapping.', 'It is the abstraction that maps each program’s address space onto physical memory and disk.']::text[], 'A memory-management technique that gives each process the illusion of a large, private, contiguous address space by mapping virtual addresses to physical memory and disk. It enables isolation, more apparent memory than exists, and demand paging, at the risk of thrashing under load.'),
  ('2027-04-18', 'Referential Transparency', ARRAY['It means an expression can be swapped for its value without changing anything.', 'It holds only when evaluating the expression has no hidden effects.', 'Pure functions are exactly what make it possible.', 'It lets a compiler safely cache or reorder computations.', 'It is a property that fails the moment code depends on mutable state.', 'It is the property that an expression can be replaced by its result with no change in behavior.']::text[], 'A property of an expression whereby it can be replaced by its resulting value without altering the program’s behavior. It requires freedom from side effects, holds for pure functions, and enables optimizations like caching and reordering as well as equational reasoning.'),
  ('2027-04-19', 'Type Inference', ARRAY['It lets you skip writing out types the compiler can figure out on its own.', 'The language deduces each type from how a value is used.', 'It gives you the safety of declared types without all the typing.', 'Writing "auto" or "var" often hands the job to it.', 'Functional languages pioneered its most powerful forms.', 'It is a compiler’s ability to deduce the types of expressions automatically.']::text[], 'A feature by which the compiler automatically deduces the types of variables and expressions from context, so explicit annotations are often unnecessary. It combines static typing’s safety with concise code, and its advanced forms (like Hindley-Milner) come from functional languages.'),
  ('2027-04-20', 'Two Pointers', ARRAY['It replaces a slow nested loop with a single sweep using two moving markers.', 'Those markers often begin at opposite ends and move toward each other.', 'Sorted input is what usually makes it work.', 'Finding a pair that sums to a target value is its textbook example.', 'It cuts many quadratic scans down to a single linear pass.', 'It is the technique of scanning a sequence with two coordinated indices at once.']::text[], 'A technique that solves array or string problems by advancing two indices in a coordinated way—often from opposite ends or at differing speeds—usually over sorted data. It commonly reduces O(n²) brute force to O(n), as in pair-sum and partitioning problems.'),
  ('2027-04-21', 'A* Search', ARRAY['It improves on a plain shortest-path search by using a hint about how far the goal still is.', 'It balances the distance already traveled against an estimate of the distance remaining.', 'That estimate must never overshoot, or the path it returns may not be optimal.', 'Game pathfinding and route planners rely on it constantly.', 'With a perfect estimate it heads straight for the goal, exploring almost nothing extra.', 'It is the best-first search that guides itself toward a goal using an admissible heuristic.']::text[], 'A best-first search that finds a lowest-cost path to a goal by ranking nodes by the cost so far plus a heuristic estimate of the cost remaining. With an admissible heuristic it is guaranteed optimal, generalizing Dijkstra’s algorithm with goal-directed guidance.'),
  ('2027-04-22', 'B-Tree', ARRAY['It was designed for a world where reaching storage is slow, so it minimizes how often it must do so.', 'Unlike most trees, a single one of its nodes can hold many keys and have many children.', 'Keeping nodes wide and the whole structure shallow means fewer storage reads per lookup.', 'Database indexes and filesystems are its natural home.', 'It stays balanced by splitting and merging its fat nodes as data changes.', 'It is the shallow, wide, self-balancing tree used to index data kept on disk.']::text[], 'A self-balancing tree that keeps data sorted while allowing each node to hold many keys and children, minimizing height and therefore disk accesses. Widely used in databases and filesystems, B-trees and variants like B+ trees give O(log n) operations tuned for block storage.'),
  ('2027-04-23', 'Declarative Programming', ARRAY['It focuses on what you want, leaving the how to the system.', 'You describe the desired result rather than the steps to reach it.', 'A database query language is a familiar example.', 'It often reads more clearly but hides the underlying execution.', 'Functional and logic programming both fall under it.', 'It is the paradigm of specifying the desired outcome rather than the control flow.']::text[], 'A paradigm that expresses the logic of a computation—what result is desired—without describing the explicit control flow to achieve it, leaving execution details to the system. SQL, HTML, and functional and logic languages exemplify it, often improving clarity at the cost of low-level control.'),
  ('2027-04-24', 'Port', ARRAY['It lets a single machine run many network services without confusion.', 'It is a number that identifies which program should get an arriving message.', 'Combined with an address, it pinpoints an exact endpoint.', 'Certain low numbers are reserved for well-known services.', 'Web traffic conventionally uses 80 and its secure form 443.', 'It is a numbered endpoint distinguishing services on the same network host.']::text[], 'A numbered communication endpoint that, combined with an IP address, identifies a specific service or process on a host, letting one machine handle many connections at once. Well-known ports (like 80 for HTTP and 443 for HTTPS) are reserved for standard services.'),
  ('2027-04-25', 'GPU', ARRAY['It was built for one job—drawing pixels—but now powers something entirely different.', 'Its strength is doing thousands of similar calculations at the same time.', 'It struggles with branchy, sequential work that its general-purpose cousin handles easily.', 'Training modern neural networks would be impractical without it.', 'Cryptocurrency mining once created a notorious shortage of them.', 'It is the massively parallel processor originally designed to render graphics.']::text[], 'A graphics processing unit, a processor with many simple cores optimized for performing the same operation on large amounts of data in parallel. Originally for rendering images, its throughput makes it central to machine learning, scientific computing, and other data-parallel workloads.'),
  ('2027-04-26', 'Concurrency', ARRAY['It is about a program structured to juggle many tasks, not necessarily at the same instant.', 'A single processor can achieve it by rapidly switching among tasks.', 'It is often confused with truly simultaneous execution, but the two are distinct.', 'Its central challenge is coordinating access to shared state safely.', 'It deals with tasks that overlap in time even if only one runs at any moment.', 'It is the composition of independently executing tasks that make progress together.']::text[], 'The ability of a system to make progress on multiple tasks whose lifetimes overlap, whether or not they run at the same instant—for example by interleaving them on one CPU. It concerns program structure and coordination, and is distinct from parallelism, which is literal simultaneous execution.'),
  ('2027-04-27', 'Design Pattern', ARRAY['It is a reusable solution shape, not a piece of code you copy directly.', 'It captures a proven answer to a problem that keeps recurring.', 'A famous "Gang of Four" book catalogued many of them.', 'They fall into creational, structural, and behavioral families.', 'Naming them gives developers a shared vocabulary for designs.', 'It is a general, reusable template for solving a common design problem.']::text[], 'A general, reusable solution to a commonly occurring software-design problem—a template for structuring classes and objects, not concrete code. Popularized by the "Gang of Four," patterns are grouped as creational, structural, and behavioral and give teams a shared design vocabulary.'),
  ('2027-04-28', 'Bubble Sort', ARRAY['It is the sort almost everyone learns first and almost no one uses in earnest.', 'It works by comparing neighbors and swapping them whenever they are out of order.', 'After each full pass, the largest remaining value has drifted to its final place at the end.', 'Larger values appear to rise toward the top one position at a time, which inspired its name.', 'On already-sorted data it can finish in a single pass, but otherwise it is quadratic.', 'It repeatedly steps through the list swapping adjacent out-of-order pairs until none remain.']::text[], 'A simple comparison sort that repeatedly steps through the list, comparing adjacent elements and swapping them if out of order, so larger values gradually move to the end. It runs in O(n²) on average and is mainly of educational value.'),
  ('2027-04-29', 'Garbage Collection', ARRAY['It frees programmers from a tedious and error-prone chore.', 'It automatically reclaims memory that a program can no longer reach.', 'It periodically hunts down objects nothing points to anymore.', 'Its work can briefly pause a program at unpredictable moments.', 'Java, Python, and Go all rely on some form of it.', 'It is the automatic reclamation of memory no longer in use by a program.']::text[], 'Automatic memory management that reclaims memory occupied by objects a program can no longer reach, sparing developers manual freeing. Using strategies like tracing (mark-and-sweep) or reference counting, it prevents many leaks and dangling pointers but can introduce pauses and overhead.'),
  ('2027-04-30', 'Assembly Language', ARRAY['It is the most human-friendly way to write code that still maps almost directly onto the hardware.', 'Each of its statements corresponds to a single processor instruction.', 'It uses short mnemonic names in place of raw numeric codes.', 'A dedicated tool converts it into the binary the CPU runs.', 'It is tied to one specific processor architecture.', 'It is the low-level language of mnemonics that stands one step above machine code.']::text[], 'A low-level language using human-readable mnemonics that correspond almost one-to-one with a processor’s machine instructions. Tied to a specific architecture and translated by an assembler, it offers direct hardware control for performance-critical or systems code.'),
  ('2027-05-01', 'Instruction Set', ARRAY['It is the vocabulary of commands a particular processor natively understands.', 'Code compiled for one is generally gibberish to a different one.', 'Designs split broadly into lean, reduced styles and richer, complex ones.', 'It defines the registers, operations, and encodings the hardware exposes.', 'Families like x86 and ARM are prominent examples.', 'It is the set of low-level commands a processor architecture can execute.']::text[], 'The set of instructions a processor architecture can execute, defining its operations, registers, data types, and encodings—the contract between hardware and software. Designs range from reduced (RISC, like ARM) to complex (CISC, like x86), and binaries are specific to one instruction set.'),
  ('2027-05-02', 'Reservoir Sampling', ARRAY['It can pick a fair random sample even when it never learns how much data is coming.', 'It reads a stream once and keeps only a fixed number of items at any moment.', 'Each new item may randomly bump out one already chosen, with carefully set odds.', 'When the stream ends, every item that ever passed had an equal chance of being kept.', 'It is ideal when the data is too large to store or its size is unknown in advance.', 'It selects a fixed-size sample uniformly at random from a stream of unknown length in one pass.']::text[], 'A family of randomized algorithms that choose a uniform random sample of k items from a stream of unknown or very large size in a single pass using O(k) space. Each new element replaces a held one with a carefully tuned probability so all elements are equally likely to be selected.'),
  ('2027-05-03', 'Register', ARRAY['It is the fastest storage a processor has, and also the scarcest.', 'It sits right inside the processor, not out in main memory.', 'The processor works almost exclusively on data held here.', 'There are only a few dozen of them, each holding a single word.', 'Values are constantly shuttled between it and slower memory.', 'It is a small, extremely fast storage location built directly into the CPU.']::text[], 'A small, very fast storage location built into the CPU that holds the data and addresses the processor is actively working on. Registers are the top of the memory hierarchy—fastest and least numerous—and instructions typically operate directly on their contents.'),
  ('2027-05-04', 'Cryptographic Hash', ARRAY['It is a fingerprinting function built to resist deliberate tampering.', 'Changing a single bit of input scrambles the entire output unpredictably.', 'Finding two inputs with the same output must be computationally infeasible.', 'It must also be practically impossible to reverse.', 'Passwords are stored as these rather than in the clear.', 'It is a hash function designed to be one-way and collision-resistant for security.']::text[], 'A hash function designed for security, with properties including preimage resistance (hard to invert), collision resistance (hard to find two inputs with the same digest), and the avalanche effect (tiny input changes drastically alter the output). Examples like SHA-256 secure passwords, signatures, and integrity checks.'),
  ('2027-05-05', 'Cache Miss', ARRAY['It is the disappointing moment a fast lookup fails to find what it hoped for.', 'It forces the system to fetch the data from a slower level instead.', 'Poor data layout that ignores locality makes it happen far more often.', 'It comes in flavors named compulsory, capacity, and conflict.', 'Minimizing it is a central goal of performance-sensitive code.', 'It occurs when requested data is absent from the cache and must come from slower storage.']::text[], 'An event where data requested from a cache is not present, requiring it to be fetched from a slower level of the memory hierarchy and incurring a latency penalty. Misses are classified as compulsory, capacity, or conflict, and reducing them via locality-friendly code is key to performance.'),
  ('2027-05-06', 'Tabulation', ARRAY['Unlike its top-down sibling, it never uses recursion at all.', 'It fills a table starting from the smallest cases and working upward.', 'Every entry it needs has already been computed before it is read.', 'It is the bottom-up way to carry out a well-known optimization technique.', 'It trades the elegance of recursion for tight iterative loops and no call-stack risk.', 'It solves a problem bottom-up by filling a table of subproblem answers in order.']::text[], 'The bottom-up form of dynamic programming that iteratively fills a table of subproblem solutions from the base cases up, so every entry is available before it is needed. It avoids recursion and its stack overhead, sometimes at the cost of computing entries a top-down method would skip.'),
  ('2027-05-07', 'Mutex', ARRAY['Whoever locks it is the only one who should unlock it.', 'Forget to release it and the whole program can seize up.', 'It forces a shared section of code to run one thread at a time.', 'A thread that cannot acquire it simply waits until it is free.', 'Its name is a contraction of the two words describing what it enforces.', 'It is a lock granting one thread at a time exclusive access to a shared resource.']::text[], 'A synchronization primitive (short for "mutual exclusion") ensuring only one thread accesses a shared resource or critical section at a time. Threads acquire the lock, do their work, and release it while others block; misuse causes deadlocks or data corruption.'),
  ('2027-05-08', 'Stack Overflow', ARRAY['It is what an infinite recursion almost always ends in.', 'It happens when a program’s automatic call-tracking region runs out of room.', 'Each unreturned function call eats a little more of a fixed space until none is left.', 'A missing base case in a recursive function is the usual culprit.', 'It typically crashes the program immediately when it strikes.', 'It is the error that occurs when the call stack exceeds its size limit.']::text[], 'A runtime error that occurs when a program uses more space on the call stack than is available, typically from unbounded or excessively deep recursion. It usually terminates the program abruptly, and is distinct from the programming question-and-answer website of the same name.'),
  ('2027-05-09', 'Semaphore', ARRAY['Unlike a simple lock, it can let a limited number of users in at once.', 'At its heart is just a counter guarded against simultaneous changes.', 'Taking one decrements the counter; releasing one increments it.', 'When the counter hits zero, further takers must wait.', 'A version limited to values of zero and one behaves like a plain lock.', 'It is a counter-based primitive that controls access to a limited pool of resources.']::text[], 'A synchronization primitive built around a counter that controls access to a limited number of identical resources: threads decrement it to acquire and increment it to release, blocking when it reaches zero. A binary semaphore acts like a lock, and semaphores also coordinate signaling between threads.'),
  ('2027-05-10', 'Generics', ARRAY['They let you write one piece of code that works for many different types.', 'A single list or sorting routine can serve integers, strings, and more.', 'They preserve type safety without forcing you to duplicate code per type.', 'The specific type is supplied as a parameter when the code is used.', 'C++ templates and Java’s angle-bracket syntax are examples.', 'They are the feature allowing code to be written against a type supplied later.']::text[], 'A language feature that lets code be written in terms of type parameters supplied later, so one implementation works across many types while preserving type safety. Also called parametric polymorphism, it avoids duplication, as with C++ templates or Java’s List<T>.'),
  ('2027-05-11', 'Lambda Calculus', ARRAY['It shows that functions alone are enough to express any computation.', 'It has no loops, no numbers, and no data types built in—only rule-based substitution.', 'It is exactly as powerful as the tape-based model of computation.', 'Functional programming languages trace their core ideas directly back to it.', 'In it, everything is a function that takes a function and returns a function.', 'It is the formal system of computation built entirely from anonymous functions and application.']::text[], 'A formal system introduced by Alonzo Church that expresses computation using only anonymous functions, variable binding, and function application with substitution. Equivalent in power to Turing machines, it is the theoretical foundation of functional programming.'),
  ('2027-05-12', 'Deadlock', ARRAY['Four specific conditions must all hold at once; break any one and it cannot occur.', 'Everyone involved is waiting, and no one can ever move forward.', 'Each party holds exactly what another party is waiting for.', 'A circular chain of waiting sits at its heart.', 'Two threads each grabbing a lock the other already holds triggers it.', 'It is a standstill in which processes block forever, each waiting on the others.']::text[], 'A situation where two or more processes or threads are each blocked forever, waiting on resources the others hold. It requires four simultaneous conditions—mutual exclusion, hold-and-wait, no preemption, and circular wait—and is broken by negating one of them.'),
  ('2027-05-13', 'Method Overriding', ARRAY['A subclass uses it to replace behavior it would otherwise inherit.', 'The replacement keeps the same name and signature as the original.', 'Which version runs is decided by the object’s actual type at runtime.', 'It is the everyday mechanism behind runtime polymorphism.', 'A subclass’s toString replacing its parent’s is a common case.', 'It is redefining an inherited method in a subclass to change its behavior.']::text[], 'The redefinition of an inherited method in a subclass, keeping the same name and signature but supplying new behavior. The version invoked is chosen at runtime by the object’s actual type (dynamic dispatch), making overriding the basis of subtype polymorphism.'),
  ('2027-05-14', 'NP-Hard', ARRAY['Membership means "at least as hard as the hardest problems whose answers are easy to check".', 'A problem can belong even if verifying a proposed answer is not itself easy.', 'Every problem in a certain famous class reduces to any problem here.', 'Some members are not even decision problems and may lie outside that famous class.', 'Finding an efficient exact solution to one would be a historic breakthrough.', 'It labels problems at least as hard as every problem whose solutions are quickly verifiable.']::text[], 'A classification for problems at least as hard as every problem in NP, meaning any NP problem reduces to them in polynomial time. Such problems need not be in NP themselves or even be decision problems, and no polynomial-time algorithm is known for any of them.'),
  ('2027-05-15', 'Floating Point', ARRAY['It trades exactness for the ability to represent an enormous range of magnitudes.', 'Adding two innocent-looking decimals in it can yield a tiny, surprising error.', 'It stores numbers in parts, much like scientific notation does.', 'A sign, an exponent, and a fraction together encode each value.', 'An international standard governs exactly how it behaves across machines.', 'It is the format that represents real numbers using a movable radix point.']::text[], 'A method of representing real numbers using a sign, a fractional significand, and an exponent, analogous to scientific notation and standardized by IEEE 754. It spans a vast range of magnitudes at the cost of limited precision, which causes rounding errors in many decimal fractions.'),
  ('2027-05-16', 'Kernel', ARRAY['It is the innermost, most privileged part of the software that runs a computer.', 'It is the one component allowed to touch the hardware directly.', 'Ordinary programs must politely ask it to do anything sensitive.', 'It handles scheduling, memory, and device access at the lowest level.', 'It runs in a protected mode separate from regular applications.', 'It is the core of the operating system, with full control over the hardware.']::text[], 'The central, most privileged component of an operating system, running in a protected mode with direct control over hardware. It manages CPU scheduling, memory, device drivers, and system calls, mediating all access between applications and the machine.'),
  ('2027-05-17', 'Selection Sort', ARRAY['No matter what the input looks like, it always does the same amount of comparing.', 'It divides the list into a sorted part and an unsorted part, growing the first one element at a time.', 'On each pass it scans the unsorted part to find the smallest remaining value.', 'It then places that value at the end of the sorted part, making very few swaps overall.', 'Its comparisons are always quadratic, but it never moves an element more than once.', 'It repeatedly selects the minimum of the unsorted portion and appends it to the sorted portion.']::text[], 'A comparison sort that repeatedly finds the minimum of the unsorted portion and moves it to the end of the sorted portion. It always performs O(n²) comparisons regardless of input but at most n swaps, which matters when writes are costly.'),
  ('2027-05-18', 'Write-Ahead Log', ARRAY['It is the safety journal a database writes before touching the real data.', 'Every change is recorded here first, then applied.', 'After a crash, replaying it restores the database to a consistent state.', 'It is the mechanism behind durability in many storage engines.', 'Its append-only nature makes writing to it fast and sequential.', 'It is a log of changes written before they are applied, enabling crash recovery.']::text[], 'A durability technique in which every change is first appended to a sequential log on stable storage before being applied to the main data. After a crash, replaying the log restores a consistent state, underpinning the atomicity and durability of many databases and filesystems.'),
  ('2027-05-19', 'Dynamic Programming', ARRAY['It only pays off when the same small subproblem keeps showing up again and again.', 'Its confusing name has nothing to do with code that changes at runtime.', 'The trick is to solve each piece once and remember the answer.', 'It comes in a top-down memoized flavor and a bottom-up tabulated one.', 'Knapsack and longest-common-subsequence are among its classic problems.', 'It solves a problem by combining stored answers to overlapping subproblems.']::text[], 'An optimization method that solves problems by breaking them into overlapping subproblems, solving each once, and storing results (via memoization or tabulation) to avoid redundant work. It applies when a problem has optimal substructure and overlapping subproblems.'),
  ('2027-05-20', 'Firewall', ARRAY['It is the guard that decides which network traffic is allowed through.', 'It filters connections based on a set of configured rules.', 'It can block traffic by address, port, or protocol.', 'It forms a barrier between a trusted network and an untrusted one.', 'It exists in both hardware and software forms.', 'It is a security system that monitors and controls network traffic by rules.']::text[], 'A network security system that monitors and controls incoming and outgoing traffic based on configured rules, forming a barrier between trusted and untrusted networks. Firewalls filter by address, port, and protocol—and, in advanced forms, by application—and exist as hardware or software.'),
  ('2027-05-21', 'Red-Black Tree', ARRAY['It tolerates a bit more lopsidedness than the strictest balanced trees, trading perfect shape for fewer fix-ups.', 'Every node wears one of two colors, and rules about those colors keep it roughly balanced.', 'No path from top to bottom can be more than twice as long as any other.', 'It backs many standard-library ordered maps and sets.', 'After edits it repairs itself through recoloring and a few rotations.', 'It is a self-balancing search tree that uses two node colors and coloring rules to bound its height.']::text[], 'A self-balancing binary search tree in which each node is colored red or black and a set of color invariants ensures the longest root-to-leaf path is at most twice the shortest. It offers O(log n) operations with fewer rotations than an AVL tree and backs many library ordered maps and sets.'),
  ('2027-05-22', 'Binary Search', ARRAY['Its correctness rests on a precondition people frequently forget to check.', 'A slightly wrong midpoint calculation can overflow or loop forever on huge inputs.', 'Each comparison lets it throw away half of what remains.', 'It narrows a range by tracking a low and a high bound and probing the middle.', 'It runs in logarithmic time, but only on data that is already ordered.', 'It finds a value in a sorted list by repeatedly splitting the search range in half.']::text[], 'A search algorithm that finds a target in a sorted array by repeatedly comparing it to the middle element and discarding the half that cannot contain it. It runs in O(log n) but requires the data to be sorted.'),
  ('2027-05-23', 'TCP', ARRAY['It is the workhorse that makes an unreliable network feel dependable.', 'It guarantees your data arrives complete and in the right order.', 'It sets up a connection with a handshake before any data flows.', 'Lost pieces are detected and quietly resent.', 'It trades a little speed for reliability, unlike its lightweight sibling.', 'It is the connection-oriented protocol providing reliable, ordered delivery.']::text[], 'The Transmission Control Protocol, a core internet protocol providing reliable, ordered, error-checked delivery of a byte stream between applications. It opens a connection via a three-way handshake, retransmits lost data, and manages flow and congestion, trading some speed for reliability.'),
  ('2027-05-24', 'SQL Join', ARRAY['It is how a query pulls related rows from more than one table together.', 'It matches rows based on a condition, usually shared key values.', 'One variety keeps only rows that match on both sides.', 'Others deliberately keep unmatched rows, filling the gaps with nulls.', 'Done carelessly on large tables, it can be very expensive.', 'It is the SQL operation that combines rows from two tables on a related column.']::text[], 'A SQL operation that combines rows from two or more tables based on a related column, usually matching keys. Inner joins keep only matching rows, while outer joins also retain unmatched rows padded with nulls; joins recombine normalized data for queries.'),
  ('2027-05-25', 'Currying', ARRAY['It rewrites a function of several arguments as a chain of one-argument functions.', 'Each call in the chain takes one argument and hands back another function.', 'Supplying only some arguments produces a specialized function awaiting the rest.', 'It is named after the same logician as a well-known programming language.', 'It makes partial application natural and function composition cleaner.', 'It is the transformation of a multi-argument function into nested single-argument functions.']::text[], 'The technique of transforming a function of multiple arguments into a sequence of functions each taking one argument, so applying some arguments yields a specialized function awaiting the rest. Named after Haskell Curry, it enables partial application and cleaner composition.'),
  ('2027-05-26', 'Null Pointer', ARRAY['It points to nothing, which is exactly what makes it dangerous.', 'Trying to follow it typically crashes the program on the spot.', 'Its inventor famously called introducing it his billion-dollar mistake.', 'Forgetting to check for it before use is one of the most common bugs there is.', 'It is the special address value meaning "this refers to no object".', 'It is a pointer that deliberately references no valid memory location.']::text[], 'A pointer that references no valid object, represented by a special value such as null, nil, or nullptr. Dereferencing it causes a crash or exception; its inventor Tony Hoare called it his "billion-dollar mistake," and guarding against it is routine defensive practice.'),
  ('2027-05-27', 'Bloom Filter', ARRAY['It may claim to have seen something it never did, but it will never deny something it truly saw.', 'You can add items to it, but you can never remove one.', 'It answers "have I seen this?" using nothing but a row of bits.', 'Several hash functions each flip a few of those bits per item.', 'It trades exactness for a tiny, fixed amount of memory.', 'It is a probabilistic set that reports an item as possibly present or definitely absent.']::text[], 'A space-efficient probabilistic data structure that tests set membership using a bit array and several hash functions. It can produce false positives but never false negatives, trading exactness for very low memory, and is used to skip expensive lookups for items that are definitely absent.'),
  ('2027-05-28', 'Pointer', ARRAY['Its value is not the data you care about, but where to find that data.', 'Leave one dangling or empty and you get a classic crash.', 'Following it reaches through to the value it refers to.', 'Doing arithmetic on it moves in units of the type it targets.', 'C exposes it directly, while Java hides it behind safer references.', 'It is a variable that stores a memory address.']::text[], 'A variable whose value is the memory address of another value; dereferencing it accesses the data it points to. Pointers enable dynamic structures and efficient sharing, but null or dangling ones are a common source of crashes and security bugs.'),
  ('2027-05-29', 'Turing Machine', ARRAY['It is a deliberately primitive imaginary device, yet nothing real computes anything it cannot.', 'It consists of an endless tape, a head that reads and writes cells, and a table of rules.', 'Despite its simplicity it defines the very limits of what is computable.', 'What a modern computer can compute is exactly what it can compute.', 'It was introduced in the 1930s to make the idea of an algorithm precise.', 'It is the abstract machine, with an infinite tape and state rules, that formalizes computation.']::text[], 'An abstract device with an infinite tape, a read-write head, and a finite set of state-transition rules, introduced by Alan Turing to formalize computation. It captures exactly what any physical computer can compute and defines computability and decidability.'),
  ('2027-05-30', 'Randomized Algorithm', ARRAY['Run it twice on the same input and it may take different paths or even give different answers.', 'It deliberately uses random choices as part of its logic.', 'Some variants are always correct but random in how long they take.', 'Others run in a fixed time but are only probably correct.', 'Randomly choosing a pivot to dodge a sorting algorithm’s worst case is a classic use.', 'It is an algorithm that makes random choices to guide its behavior.']::text[], 'An algorithm that incorporates randomness into its logic. Las Vegas variants are always correct with random running time; Monte Carlo variants run in bounded time but are only probably correct. Randomization can simplify algorithms and avoid worst-case inputs, as in randomized quicksort.'),
  ('2027-05-31', 'Serialization', ARRAY['It flattens a living in-memory object into a form that can be stored or sent.', 'The reverse process rebuilds the object from that flat form later.', 'Formats for it include JSON, XML, and compact binary schemes.', 'It is how program state crosses between machines or survives to disk.', 'Deserializing untrusted input is a well-known security risk.', 'It is converting an in-memory object into a storable or transmittable format.']::text[], 'The process of converting an in-memory data structure or object into a format (such as JSON, XML, or a binary encoding) that can be stored or transmitted, with deserialization reconstructing it later. It enables persistence and communication across systems, though deserializing untrusted data is hazardous.'),
  ('2027-06-01', 'Clock Speed', ARRAY['It loosely indicates how many basic steps a processor can take each second.', 'It is measured in cycles per second, nowadays in the billions.', 'Raising it too far makes a chip run dangerously hot.', 'It is only a rough guide to real performance, which also depends on architecture.', 'Chipmakers hit a wall on it and turned to adding more cores instead.', 'It is the rate, measured in hertz, at which a CPU executes its basic cycle.']::text[], 'The frequency, measured in hertz (typically gigahertz), at which a CPU’s clock drives its fetch-decode-execute cycle. Higher speeds mean more cycles per second but more heat and power; because scaling it hit physical limits, designers shifted toward multiple cores.'),
  ('2027-06-02', 'Backtracking', ARRAY['It explores possibilities but abandons any path the moment it proves hopeless.', 'It builds up a candidate solution one choice at a time.', 'When a partial choice cannot possibly work, it undoes it and tries another.', 'Solving a maze, placing queens on a chessboard, or filling a Sudoku all use it.', 'It is essentially a depth-first exploration of the space of solutions, with pruning.', 'It is the strategy of trying choices, retreating on dead ends, and trying the next option.']::text[], 'A problem-solving strategy that incrementally builds candidate solutions and abandons a candidate as soon as it cannot be completed. Effectively a pruned depth-first search of the solution space, it solves constraint problems like N-queens, Sudoku, and maze-solving.'),
  ('2027-06-03', 'Kadane’s Algorithm', ARRAY['It solves a classic array problem in a single pass with no nested loops.', 'At each element it makes one simple decision: extend, or start fresh here.', 'It keeps a running best-ending-here total alongside the best seen anywhere.', 'A running total that goes negative is discarded, because it can only hurt what follows.', 'It finds the contiguous stretch of numbers with the largest possible sum.', 'It is the linear-time dynamic-programming method for the maximum-subarray problem.']::text[], 'A dynamic-programming algorithm that finds the maximum-sum contiguous subarray in one O(n) pass by tracking the best sum ending at the current position and the best overall, resetting the running sum whenever it turns negative.'),
  ('2027-06-04', 'Loop Invariant', ARRAY['It is a fact you pin down to convince yourself a loop is actually correct.', 'It must hold before the loop starts and remain true after every iteration.', 'Combined with the loop’s exit condition, it proves the final result is right.', 'It is the loop equivalent of the base-and-inductive reasoning used in proofs.', 'For a sorting loop, it might state that a prefix of the array is already sorted.', 'It is a condition that stays true throughout a loop and helps prove its correctness.']::text[], 'A condition that holds before a loop begins and after every iteration, used to reason formally about a loop’s correctness. Showing it is established initially, maintained each iteration, and combined with the exit condition proves the loop computes the intended result.'),
  ('2027-06-05', 'Factory Pattern', ARRAY['It hands responsibility for creating objects to a dedicated helper.', 'Calling code asks for an object without naming the concrete type it gets.', 'This lets the exact type produced be decided or swapped in one place.', 'It decouples what a program uses from how those things are constructed.', 'It is one of the creational patterns from the classic catalogue.', 'It is a pattern that delegates object creation instead of calling a constructor directly.']::text[], 'A creational design pattern that delegates object creation to a dedicated method or class, so client code requests an object by interface without naming its concrete class. This decouples usage from construction and centralizes decisions about which implementation to instantiate.'),
  ('2027-06-06', 'Hash Table', ARRAY['Its worst case is genuinely awful, yet in everyday use you almost never meet it.', 'A function turns each key into a position in an underlying array.', 'Two different keys can demand the same slot, so it needs a plan for those clashes.', 'Growing it means rebuilding the whole thing so the keys spread out again.', 'It gives average constant-time lookup, insertion, and deletion by key.', 'It is the key-value store that Python calls a dict and Java a HashMap.']::text[], 'A structure that maps keys to values by applying a hash function to compute an index into an array of buckets. It offers average O(1) insert, lookup, and delete using collision-resolution strategies such as chaining or open addressing, and degrades to O(n) in the rare worst case.'),
  ('2027-06-07', 'Event Loop', ARRAY['It is how a single-threaded program juggles many tasks without blocking.', 'It continuously pulls the next pending task from a queue and runs it.', 'Slow operations are handed off, and their results are queued for later.', 'It is the beating heart of JavaScript’s runtime.', 'A long-running task on it freezes everything else.', 'It is the loop that processes queued events and callbacks one at a time.']::text[], 'A construct that repeatedly takes events or tasks from a queue and dispatches their handlers one at a time, letting a single thread handle many concurrent operations without blocking. Long-running I/O is offloaded and its callbacks queued; it is central to Node.js and browser JavaScript.'),
  ('2027-06-08', 'Socket', ARRAY['It is the software endpoint a program uses to speak over a network.', 'It bundles an address and a port into one handle a program can read and write.', 'Opening one is how an application joins a network conversation.', 'Its interface makes network I/O look much like file I/O.', 'Both ends of a connection have one.', 'It is the programming endpoint through which a process sends and receives network data.']::text[], 'An endpoint for network communication, identified by an IP address and port, that a program uses to send and receive data. The socket API abstracts network I/O to resemble file operations, and a connection is defined by the pair of sockets at its two ends.'),
  ('2027-06-09', 'Denormalization', ARRAY['It deliberately breaks a tidy design in the name of speed.', 'It stores redundant copies of data to avoid expensive joins.', 'Reads get faster, but keeping the copies in sync becomes a burden.', 'It is common in read-heavy and analytics workloads.', 'It is essentially the reverse of the redundancy-removing process.', 'It is intentionally adding redundant data to a schema to improve read performance.']::text[], 'The deliberate introduction of redundancy into a schema—duplicating data or precomputing joins—to speed reads by avoiding expensive joins. The reverse of normalization, it improves read-heavy performance at the cost of extra storage and harder update consistency.'),
  ('2027-06-10', 'Message Queue', ARRAY['It lets two systems communicate without both being available at the same time.', 'A sender drops a message into it and moves on immediately.', 'A receiver picks the message up whenever it is ready.', 'It smooths out bursts by buffering work until it can be processed.', 'It decouples producers from consumers, improving resilience.', 'It is a buffer that holds messages between sender and receiver for asynchronous communication.']::text[], 'A component that enables asynchronous communication by holding messages sent by producers until consumers retrieve and process them. By decoupling senders from receivers in time, message queues buffer bursts, improve resilience, and enable scalable, loosely coupled architectures.'),
  ('2027-06-11', 'Quickselect', ARRAY['It answers a question a full sort could answer, but does far less work to do it.', 'It borrows the partitioning idea from a well-known sorting algorithm.', 'After partitioning, it recurses into only the side that must contain its target.', 'It finds the k-th smallest element without fully ordering the data.', 'On average it runs in linear time, though a bad pivot can ruin that.', 'It is the selection algorithm that partitions like quicksort but recurses on one side only.']::text[], 'A selection algorithm that finds the k-th smallest element of an unordered list by partitioning around a pivot (as in quicksort) and recursing only into the partition containing the target. It runs in O(n) on average and O(n²) in the worst case, avoiding a full sort.'),
  ('2027-06-12', 'Primary Key', ARRAY['It is the column whose value uniquely fingerprints each row.', 'No two rows may share the same one, and it can never be empty.', 'It is how other tables refer to a specific record.', 'A database automatically indexes it for fast lookup.', 'Sometimes it is a natural attribute, sometimes an auto-generated number.', 'It is the column (or columns) uniquely identifying each row in a table.']::text[], 'A column or set of columns whose value uniquely identifies each row in a table and which cannot be null or duplicated. It is the anchor other tables reference via foreign keys, and databases index it automatically for fast lookups.'),
  ('2027-06-13', 'Strong Typing', ARRAY['It refuses to quietly reinvent one kind of value as another behind your back.', 'Adding a number to a string, for instance, is rejected rather than guessed at.', 'It contrasts with looser systems that perform surprising automatic conversions.', 'It reduces a class of subtle bugs caused by unintended coercions.', 'It is about how strictly types are enforced, not about when they are checked.', 'It is a discipline that forbids operating on incompatible types without explicit conversion.']::text[], 'A typing discipline that strictly enforces type rules and disallows implicit, error-prone conversions between incompatible types, requiring explicit casts instead. Orthogonal to static versus dynamic typing, it reduces bugs from unintended coercions.'),
  ('2027-06-14', 'Atomic Operation', ARRAY['To the rest of the system it appears to happen all at once, with no in-between state.', 'It cannot be interrupted partway through by another thread.', 'This indivisibility is what makes it safe to use on shared data without a lock.', 'Compare-and-swap is a famous example used to build lock-free structures.', 'Hardware often provides a few of these as primitives.', 'It is an operation that completes indivisibly, appearing instantaneous to other threads.']::text[], 'An operation that appears to occur instantaneously and indivisibly to other threads—none can observe it half-completed. Provided by hardware (for example, compare-and-swap), atomics are the foundation of lock-free programming and safe access to shared data.'),
  ('2027-06-15', 'Singleton', ARRAY['It guarantees that only one instance of something can ever exist.', 'It provides a single, global point of access to that lone instance.', 'Configuration objects and connection pools sometimes use it.', 'Critics warn it acts like a global variable in disguise.', 'It often hurts testability by hiding a hard dependency.', 'It is the design pattern ensuring a class has just one instance, globally accessible.']::text[], 'A creational design pattern that restricts a class to a single instance and provides a global access point to it. Useful for shared resources like configuration or connection pools, it is often criticized for introducing global state that complicates testing and hides dependencies.'),
  ('2027-06-16', 'JSON', ARRAY['It is a lightweight text format that both humans and machines can read.', 'Its structure grew out of a scripting language’s object syntax.', 'It represents data as nested key-value pairs and ordered lists.', 'It has become the default way web APIs exchange data.', 'It supports only a handful of basic value types.', 'It is the text-based format for representing structured data as objects and arrays.']::text[], 'JavaScript Object Notation, a lightweight, human-readable text format representing structured data as key-value objects and ordered arrays with a few basic value types. Language-independent despite its origins, it is the de facto standard for data interchange in web APIs.'),
  ('2027-06-17', 'ASCII', ARRAY['It is an early scheme for turning characters into numbers.', 'It uses only seven bits, covering 128 possible characters.', 'It handles the English letters, digits, and basic punctuation, and little else.', 'Its inability to represent other languages spurred a much larger successor.', 'The letter A is 65 in it.', 'It is the standard mapping of basic English characters to 7-bit numbers.']::text[], 'The American Standard Code for Information Interchange, a 7-bit character encoding mapping 128 values to English letters, digits, punctuation, and control codes (for example, "A" is 65). Its limited range led to Unicode, and it remains a compatible subset of UTF-8.'),
  ('2027-06-18', 'Byte', ARRAY['It is the chunk a computer typically hands out as its smallest addressable piece of memory.', 'It is built from eight of the tiniest units of information.', 'It can represent 256 distinct values, enough for one character in older text encodings.', 'Storage is measured in multiples of it, like kilo, mega, and giga.', 'A single one usually holds one ASCII character.', 'It is a group of eight bits treated as a single unit.']::text[], 'A unit of digital information consisting of eight bits, able to represent 256 distinct values. It is typically the smallest individually addressable unit of memory and the standard measure of storage, historically encoding a single ASCII character.'),
  ('2027-06-19', 'Digital Signature', ARRAY['It proves both who created a message and that it was not altered.', 'It is produced using the sender’s private key.', 'Anyone can verify it using the matching public key.', 'It provides authenticity and makes denial of authorship impossible.', 'Software updates and certificates rely on it for trust.', 'It is a cryptographic stamp verifying a message’s origin and integrity.']::text[], 'A cryptographic mechanism in which a sender signs data with their private key, producing a value anyone can verify with the corresponding public key. It proves authenticity and integrity and provides non-repudiation, underpinning secure software distribution, certificates, and signed documents.'),
  ('2027-06-20', 'Eventual Consistency', ARRAY['It accepts brief disagreement in exchange for staying always available.', 'Different copies of the data may momentarily hold different values.', 'Given no new updates, all copies eventually converge to the same state.', 'It is a common choice in large distributed systems that favor availability.', 'It contrasts with the immediate agreement of strict consistency.', 'It is a model where replicas converge to the same value over time, not instantly.']::text[], 'A consistency model for distributed systems in which replicas may temporarily hold different values but, absent new updates, all converge to the same state over time. It favors availability and partition tolerance, accepting temporary staleness for responsiveness and scale.'),
  ('2027-06-21', 'Greedy Algorithm', ARRAY['It never looks back or reconsiders once it makes a choice.', 'At each step it simply grabs whatever looks best right now.', 'For some problems this shortsighted strategy still yields the true optimum.', 'Making change with coins and building certain minimum-cost trees rely on it.', 'Proving it actually works often requires showing a special structural property.', 'It builds a solution step by step, always taking the locally best option available.']::text[], 'A strategy that builds a solution incrementally, always choosing the option that looks best at the moment without reconsidering. It is simple and fast and gives optimal results for problems with the right structure, but can be suboptimal otherwise.'),
  ('2027-06-22', 'Rate Limiting', ARRAY['It caps how often a client may hit a service in a given window.', 'It protects a system from being overwhelmed, whether by abuse or bugs.', 'Exceeding the cap typically returns a "too many requests" response.', 'Common schemes include token buckets and fixed windows.', 'Public APIs use it to enforce fair usage across many callers.', 'It is the practice of restricting how many requests a client can make over time.']::text[], 'A technique that restricts how many requests a client may make to a service within a time window, protecting it from overload, abuse, and runaway cost. Implemented with schemes like token buckets or sliding windows, it typically returns a 429 "Too Many Requests" response when exceeded.'),
  ('2027-06-23', 'Coroutine', ARRAY['It is a function that can pause itself partway and resume later where it left off.', 'Unlike an ordinary function, it does not have to run to completion in one go.', 'It cooperatively hands control back rather than being forcibly interrupted.', 'It is a lightweight way to express concurrency without full threads.', 'Generators are a common, restricted form of it.', 'It is a routine that can suspend and resume, preserving its state between pauses.']::text[], 'A generalization of a subroutine that can suspend its execution and later resume from the same point, preserving local state across pauses. Coroutines yield control cooperatively, giving lightweight concurrency without OS threads, and underlie generators, async runtimes, and cooperative multitasking.'),
  ('2027-06-24', 'Model-View-Controller', ARRAY['It splits an application into three cooperating responsibilities.', 'One part holds the data and rules, cleanly separate from how things look.', 'Another renders what the user sees, and a third handles their input.', 'This separation lets the interface change without touching core logic.', 'It has shaped countless web and desktop application frameworks.', 'It is the architectural pattern dividing an app into model, view, and controller.']::text[], 'An architectural pattern that separates an application into the model (data and business rules), the view (presentation), and the controller (input handling that mediates between them). This separation of concerns improves modularity and has shaped many UI and web frameworks.'),
  ('2027-06-25', 'Encapsulation', ARRAY['It hides an object’s inner workings behind a controlled surface.', 'Outside code interacts only through an approved set of operations.', 'This lets the internals change without breaking anyone relying on the object.', 'It typically marks internal data as private and off-limits.', 'It bundles data together with the methods that are allowed to touch it.', 'It is the bundling of data with its methods while hiding internal details.']::text[], 'The bundling of data with the methods that operate on it, while restricting direct outside access to internal state behind a public interface. Encapsulation enforces invariants, reduces coupling, and lets implementations change without affecting client code.'),
  ('2027-06-26', 'Idempotence', ARRAY['It describes an operation you can repeat without changing the result further.', 'Doing it once or doing it five times leaves the same final state.', 'It makes safely retrying a failed request possible.', 'Setting a value to five has it; adding five to a value does not.', 'Certain web request methods are expected to have this property.', 'It is the property that repeating an operation yields the same result as doing it once.']::text[], 'A property of an operation whereby applying it multiple times yields the same result as applying it once, leaving state unchanged after the first application. Idempotence makes retries safe—crucial for unreliable networks and APIs—and characterizes HTTP methods like GET, PUT, and DELETE.'),
  ('2027-06-27', 'Compiler', ARRAY['It does all of its work before a program ever runs.', 'It reads a whole program in one language and produces an equivalent one in another.', 'It catches many mistakes up front that would otherwise surface only later.', 'Its output is usually a form the machine can run directly and fast.', 'It contrasts with a tool that instead executes source line by line.', 'It is the program that translates source code into machine code ahead of time.']::text[], 'A program that translates source code from one language (typically high-level) into another, usually machine code or bytecode, before execution. Compilation catches many errors ahead of time and produces fast-running output, in contrast with interpretation.'),
  ('2027-06-28', 'Firmware', ARRAY['It is software, yet it lives so close to the hardware that people forget it is software.', 'It is stored on a chip inside a device rather than loaded from a disk.', 'It is the first code that runs when many devices power on.', 'Updating it is riskier than updating an ordinary app; a failure can brick the device.', 'A router, a keyboard, and a hard drive each contain some.', 'It is low-level software embedded in a device to control its hardware.']::text[], 'Low-level software stored in non-volatile memory on a hardware device that controls the device’s basic functions and often runs first at power-on. Ranging from a PC’s BIOS/UEFI to the code inside peripherals, it sits between pure hardware and higher-level software and is updated cautiously.'),
  ('2027-06-29', 'Continuous Integration', ARRAY['It has developers merge their work into a shared codebase frequently.', 'Each merge automatically triggers a build and a test run.', 'This catches integration problems within minutes rather than weeks.', 'A broken build is meant to be fixed immediately, before other work continues.', 'It is often paired with automated deployment as a pipeline.', 'It is the practice of frequently merging code and automatically building and testing it.']::text[], 'A practice in which developers frequently merge changes into a shared repository, each merge automatically triggering a build and automated tests. By surfacing integration problems quickly, it keeps the codebase working and is often extended into continuous delivery pipelines.'),
  ('2027-06-30', 'Recursion', ARRAY['Done wrong, it is indistinguishable from a loop that eventually crashes.', 'Every step quietly consumes a little more of a resource you do not manage directly.', 'It leans on a terminating condition to know when to stop.', 'A function reduces a problem by invoking itself on something smaller.', 'Traversing a tree or computing a factorial are its textbook examples.', 'It is what happens when a function calls itself to solve smaller versions of a problem.']::text[], 'A technique where a function solves a problem by calling itself on smaller subproblems, converging toward a base case that stops the process. Each call adds a frame to the call stack, and tree traversals, divide-and-conquer, and backtracking are naturally expressed with it.')
